-- Part 3 (200 recipes)
insert into public.recipes (id, doc, status) values ('creamy_spinach_pork_curry', '{"id":"creamy_spinach_pork_curry","name":"Creamy Spinach and Ginger Pork Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"spinach","q":300},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"butter","q":30},{"f":"greek_yogurt","q":150},{"f":"lemon","q":1}],"steps":["Melt the butter in a deep skillet over medium heat and cook the finely chopped onion for 6 to 8 minutes until soft and golden at the edges.","Add the minced garlic and ginger with a generous spoonful of curry spices and toast for 1 minute until the kitchen smells unmistakably like dinner.","Add the cubed pork loin and sear for 4 to 5 minutes, turning to coat every piece in the spiced butter.","Pile in the spinach in handfuls, letting each batch wilt down glossy and dark before adding the next, then splash in a few tablespoons of water and simmer covered for 10 minutes until the pork is just cooked through.","Off the heat, stir in the greek yogurt a spoonful at a time until the sauce turns pale and creamy, then brighten with lemon juice and salt to taste."],"tip":"Temper the yogurt off the heat or it will split faster than a bad band."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_carnitas_lettuce_cups', '{"id":"pork_carnitas_lettuce_cups","name":"Crispy Pork Carnitas Lettuce Cups with Avocado and Lime","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"romaine","q":1},{"f":"lime","q":2},{"f":"avocado","q":1},{"f":"onion","q":1},{"f":"cilantro","q":0.3},{"f":"sour_cream","q":60},{"f":"olive_oil","q":15}],"steps":["Cut the pork loin into small cubes, season aggressively with salt, cumin, and the juice of one lime, and let it sit for 10 minutes.","Simmer the pork with half the onion and a splash of water in a covered skillet over medium-low heat for 20 minutes until fork-tender.","Uncover, raise the heat, add the olive oil, and fry the pork for 6 to 8 minutes, pressing pieces against the pan until the edges crackle and turn deep golden brown.","Separate the romaine into sturdy cup-shaped leaves, wash, and pat completely dry so they stay crisp.","Pile the crispy pork into the leaves and top with diced avocado, the remaining onion finely minced, torn cilantro, a smear of sour cream, and wedges of the second lime."],"tip":"The fry-after-braise step is not optional — soft carnitas without crispy edges is just sad boiled pork."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_broccoli_cheddar_frittata', '{"id":"bacon_broccoli_cheddar_frittata","name":"Bacon, Broccoli, and Sharp Cheddar Frittata","emoji":"🍳","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"eggs","q":8},{"f":"bacon","q":120},{"f":"broccoli","q":250},{"f":"cheddar","q":60},{"f":"onion","q":1},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 190C and cook the chopped bacon in an ovenproof skillet over medium heat for 6 to 8 minutes until crisp, then lift it out, leaving the fat behind.","Add the olive oil, diced onion, and small broccoli florets to the skillet and cook for 5 minutes until the broccoli is bright green and just tender at the tip of a knife.","Whisk the eggs with a big pinch of salt until uniformly yellow and slightly frothy, then stir in most of the cheddar and the crisped bacon.","Pour the eggs over the vegetables, shake the pan to settle everything, and cook undisturbed for 2 minutes until the edges begin to set.","Scatter the remaining cheddar on top and bake for 10 to 12 minutes until the center is puffed and barely jiggles; rest 5 minutes before cutting into wedges."],"tip":"Pull it when the middle still wobbles slightly — a frittata keeps cooking out of the oven and overbaked eggs bounce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_bacon_romaine_salad', '{"id":"warm_bacon_romaine_salad","name":"Warm Bacon Dressing Romaine Salad with Jammy Eggs","emoji":"🥗","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"bacon","q":150},{"f":"romaine","q":2},{"f":"eggs","q":4},{"f":"avocado","q":1},{"f":"parmesan","q":30},{"f":"olive_oil","q":20},{"f":"lemon","q":1}],"steps":["Lower the eggs into boiling water for exactly 7 minutes, then shock them in ice water so the yolks stay glossy and jammy; peel and halve.","Cook the chopped bacon in a skillet over medium heat for 8 minutes until deeply crisp, then pull the pan off the heat, keeping every drop of fat.","Whisk the lemon juice and olive oil straight into the warm bacon fat with cracked pepper to make a smoky, tangy dressing.","Chop the romaine into wide ribbons, wash, and spin thoroughly dry so the warm dressing clings instead of sliding off.","Toss the leaves with the warm dressing and bacon, then top with sliced avocado, the halved eggs, and thick shavings of parmesan."],"tip":"Dress the romaine seconds before serving — warm bacon fat waits for no one and neither does crisp lettuce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_bacon_chowder', '{"id":"cauliflower_bacon_chowder","name":"Smoky Cauliflower and Bacon Chowder","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"bacon","q":200},{"f":"cauliflower","q":1.3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":750},{"f":"milk","q":250},{"f":"cheddar","q":80},{"f":"butter","q":20}],"steps":["Cook the chopped bacon in a heavy pot over medium heat for 8 minutes until crisp, then set it aside on paper towels, leaving two tablespoons of fat in the pot.","Add the butter, diced onion, and garlic and cook for 4 minutes until soft and fragrant, scraping up the bacon-browned bits.","Add the cauliflower florets and broth, bring to a lively simmer, and cook for 15 minutes until a fork slides through the stems with no resistance.","Blend half the pot until completely smooth and stir it back in with the milk, giving the chowder body while leaving satisfying chunks.","Stir in the cheddar off the boil until melted and velvety, season with salt and pepper, and serve each bowl crowned with the reserved crispy bacon."],"tip":"Blending only half the pot is the whole trick — all-smooth is baby food, all-chunky is just soup with commitment issues."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_ribbon_carbonara_bacon', '{"id":"zucchini_ribbon_carbonara_bacon","name":"Zucchini Ribbon Carbonara with Crispy Bacon","emoji":"🥓","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"bacon","q":150},{"f":"zucchini","q":3},{"f":"eggs","q":3},{"f":"parmesan","q":60},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Shave the zucchini into long ribbons with a vegetable peeler, salt them lightly, and let them sit in a colander for 10 minutes to weep out excess water; pat dry.","Whisk the eggs with the grated parmesan and an indecent amount of black pepper until the mixture looks like thick paint.","Cook the chopped bacon in the olive oil over medium heat for 7 to 8 minutes until crisp, then add the sliced garlic for 30 seconds.","Toss the zucchini ribbons in the hot pan for just 90 seconds until barely tender but still holding a slight bite.","Kill the heat, wait 30 seconds, then pour in the egg mixture and toss constantly for a minute until it thickens into a glossy sauce that coats every ribbon; serve immediately with more parmesan."],"tip":"Residual heat makes the sauce; direct heat makes scrambled eggs with vegetables — know the difference."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_bacon_cabbage_stir_fry', '{"id":"sesame_bacon_cabbage_stir_fry","name":"Sesame-Ginger Bacon and Cabbage Stir-Fry","emoji":"🥬","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free"],"allergens":["gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"bacon","q":200},{"f":"cabbage","q":0.7},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Cut the bacon into thick lardons and render them in a wok over medium heat for 6 to 7 minutes until crisp and golden; scoop them out, leaving the fat.","Crank the heat to high, add the minced garlic and ginger to the bacon fat, and stir for 20 seconds until they sizzle and perfume the kitchen.","Add the roughly chopped cabbage in two big handfuls and stir-fry for 5 to 6 minutes until the edges char in spots but the ribs stay crunchy.","Splash in the soy sauce and let it hiss and reduce around the cabbage for 30 seconds.","Return the bacon, drizzle with the sesame oil, toss once, and serve piping hot with extra cracked pepper."],"tip":"Charred-but-crunchy is the goal — cabbage cooked past its snap goes from stir-fry to soggy regret in about a minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_salmon_asparagus', '{"id":"sheet_pan_salmon_asparagus","name":"Sheet-Pan Lemon-Garlic Salmon with Asparagus","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"asparagus","q":400},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425F and line a sheet pan while you snap the woody ends off the asparagus.","Toss the asparagus with half the olive oil, minced garlic, salt, and pepper, then spread it in a single layer so it roasts instead of steams.","Rub the salmon fillets with the remaining oil, paprika, salt, and pepper, and nestle them skin-side down among the spears.","Roast for 12 to 14 minutes, until the asparagus tips crisp at the edges and the salmon flakes when nudged with a fork but still looks glossy in the center.","Squeeze the lemon over everything while the pan is still hot so the juice sizzles and loosens the browned bits, then serve straight from the pan."],"tip":"Thicker fillets need the full 14 minutes; skinny tail pieces are done at 10, so tuck the thin ends under themselves to even the odds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_zoodle_piccata_skillet', '{"id":"salmon_zoodle_piccata_skillet","name":"Salmon Piccata Skillet with Zucchini Noodles","emoji":"🍋","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"zucchini","q":2},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":25},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Spiralize or julienne the zucchini into noodles, salt them lightly, and let them drain in a colander while you cook the fish.","Season the salmon and sear it in olive oil over medium-high heat, 4 minutes on the skin side until it crackles and releases easily, then 2 minutes on the flesh side; move it to a plate.","Drop the butter and sliced garlic into the same skillet and swirl until the butter foams and smells nutty, about 1 minute.","Add the lemon juice and the zoodles and toss for just 2 minutes, until they bend without snapping but have not gone watery.","Return the salmon to the pan, shower everything with parmesan and chopped parsley, and serve while the sauce still clings."],"tip":"Two minutes is a promise, not a suggestion — zoodles go from al dente to soup faster than you can find the tongs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_ginger_salmon_stirfry', '{"id":"sesame_ginger_salmon_stirfry","name":"Sesame-Ginger Salmon and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"broccoli","q":350},{"f":"bell_pepper","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"scallions","q":1}],"steps":["Cut the salmon into 4-centimeter chunks and pat them bone dry so they sear instead of stew.","Get a wok or wide skillet ripping hot with the olive oil, then sear the salmon pieces undisturbed for 2 minutes per side until bronzed; lift them out gently.","Stir-fry the broccoli florets and sliced bell pepper with a splash of water for 3 to 4 minutes, until the broccoli turns vivid green and the edges char slightly.","Push the vegetables aside, sizzle the grated ginger and garlic for 30 seconds until fragrant, then pour in the soy sauce and sesame oil.","Slide the salmon back in, toss once or twice to glaze without breaking the chunks, and finish with sliced scallions."],"tip":"Treat the salmon like it owes you money and leave it alone in the pan — poking is what turns chunks into flakes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_curry_salmon_spinach', '{"id":"coconut_curry_salmon_spinach","name":"Coconut Curry Salmon with Wilted Spinach","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"coconut_milk","q":250},{"f":"spinach","q":150},{"f":"onion","q":0.5},{"f":"olive_oil","q":10},{"f":"curry_powder","q":6},{"f":"turmeric","q":2},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":3}],"steps":["Soften the diced onion in olive oil over medium heat for 4 minutes, until translucent and sweet-smelling.","Add the grated ginger, minced garlic, curry powder, and turmeric and toast for 1 minute, stirring so the spices bloom without scorching.","Pour in the coconut milk, bring it to a gentle simmer, and season with salt; the sauce should be the color of marigolds.","Slip in the salmon cut into large chunks and poach at a bare simmer for 6 to 8 minutes, until the pieces turn opaque and just flake.","Fold in the spinach by the handful until it collapses, then brighten the pot with lime juice and torn cilantro before serving."],"tip":"A bare simmer means lazy bubbles, not a rolling boil — boiled salmon is how curries end up with fish confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_cauliflower_chowder', '{"id":"salmon_cauliflower_chowder","name":"Creamy Salmon and Cauliflower Chowder","emoji":"🥣","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":40,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"cauliflower","q":0.5},{"f":"onion","q":1},{"f":"celery","q":80},{"f":"broth","q":750},{"f":"milk","q":300},{"f":"butter","q":25},{"f":"garlic","q":0.3},{"f":"oregano","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Melt the butter in a soup pot and sweat the diced onion and celery over medium heat for 5 minutes, until soft but not browned.","Add the garlic and oregano, cook for 30 seconds, then tip in the cauliflower florets and the broth and simmer for 12 minutes, until a knife slides through the stems.","Ladle a third of the pot into a blender, puree until silky, and stir it back in to thicken the chowder without a speck of flour.","Pour in the milk, drop in the salmon cut into bite-size chunks, and poach gently for 6 minutes, until the fish turns pale pink and opaque.","Season generously with salt and black pepper, taste, and serve steaming, with the chunks intact and the broth just coating a spoon."],"tip":"Once the milk goes in, keep the heat below a boil unless you enjoy chowder that looks like it has already been eaten."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_taco_lettuce_cups', '{"id":"salmon_taco_lettuce_cups","name":"Chili-Lime Salmon Taco Lettuce Cups","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":25,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"salsa","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"chili_powder","q":4},{"f":"cumin","q":2},{"f":"salt","q":3}],"steps":["Rub the salmon all over with olive oil, chili powder, cumin, and salt until it wears a brick-red crust of spices.","Sear it in a hot skillet for 4 minutes on the first side and 3 on the second, until the spice crust darkens and the center flakes into big rosy petals.","While the fish rests, separate the romaine into sturdy cup-shaped leaves and mash the avocado with lime juice and a pinch of salt.","Break the salmon into chunky flakes with a fork, tasting one for quality-control purposes.","Swipe avocado into each leaf, pile on the warm salmon, spoon over salsa, and finish with cilantro and a final squeeze of lime."],"tip":"Use the inner romaine leaves for cups and save the floppy outer ones for tomorrow''s salad — structural integrity matters when dinner is handheld."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_salmon_romaine_salad', '{"id":"greek_salmon_romaine_salad","name":"Seared Salmon Greek Salad with Feta and Olives","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"oregano","q":2},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Whisk the lemon juice with the olive oil, oregano, salt, and pepper until the dressing turns cloudy and thick.","Chop the romaine into ribbons, halve the cherry tomatoes, and cut the cucumber into chunky half-moons, then toss them in a wide bowl with most of the dressing.","Season the salmon and sear it in a hot, lightly oiled skillet for 4 minutes skin-side down, until the skin is shatteringly crisp, then flip for 2 minutes more.","Let the fish rest for 2 minutes so the juices settle, then break it into large warm flakes over the cold, crunchy salad.","Scatter the feta and olives on top, drizzle with the last of the dressing, and grind over black pepper at the table."],"tip":"Warm fish on cold crunchy salad is the whole trick here, so dress the greens before you even think about flipping the salmon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_glazed_salmon_cauli_rice_bowl', '{"id":"soy_glazed_salmon_cauli_rice_bowl","name":"Soy-Glazed Salmon Cauliflower Rice Bowls","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"cauliflower","q":0.5},{"f":"edamame_frozen","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"scallions","q":1}],"steps":["Pulse the cauliflower florets in a food processor until they look like rice, stopping before they turn to snow.","Sear the salmon fillets in olive oil over medium-high heat, 4 minutes skin-side down and 2 on the flesh, then pour in the soy sauce with the grated ginger and half the garlic and spoon the bubbling glaze over the fish for 1 minute until lacquered.","Move the salmon to a plate and wipe the pan, then stir-fry the cauliflower rice with the remaining garlic and the edamame over high heat for 4 to 5 minutes, until dry, fluffy, and toasted in spots.","Season the rice with the sesame oil and a spoonful of the leftover glaze from the fish plate.","Divide the cauliflower rice between bowls, perch a glazed fillet on each, and shower with sliced scallions."],"tip":"Wet cauliflower rice is sad cauliflower rice — keep the heat high and resist crowding the pan so it toasts instead of steams."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_spinach_parmesan_frittata', '{"id":"salmon_spinach_parmesan_frittata","name":"Salmon, Spinach, and Parmesan Frittata","emoji":"🍳","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"salmon","q":250},{"f":"spinach","q":100},{"f":"parmesan","q":30},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 375F and whisk the eggs with the parmesan, salt, and pepper until uniformly pale yellow.","In an ovenproof skillet, soften the diced onion in olive oil for 4 minutes, then wilt in the spinach until it hisses down to almost nothing.","Add the salmon cut into small cubes and cook for 2 minutes, just until the outsides blush opaque.","Pour the eggs over everything, drag a spatula through twice to distribute the filling, and cook undisturbed for 3 minutes until the edges set.","Transfer the skillet to the oven for 8 to 10 minutes, until the center is puffed and barely jiggles, then rest 5 minutes and slide it out with torn basil on top."],"tip":"Pull it while the middle still wobbles like it is nervous — carryover heat finishes the job and rubbery frittata has no defenders."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('walnut_crusted_salmon_green_beans', '{"id":"walnut_crusted_salmon_green_beans","name":"Walnut-Crusted Salmon with Blistered Green Beans","emoji":"🌿","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","nuts","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"walnuts","q":40},{"f":"parmesan","q":20},{"f":"green_beans","q":350},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 400F and chop the walnuts fine, then mix them with the grated parmesan, minced garlic, chopped parsley, lemon zest, and a spoonful of olive oil into a damp, sandy paste.","Season the salmon, set it on a lined sheet pan, and press the walnut mixture onto the flesh in an even cap.","Toss the green beans with the remaining oil, salt, and pepper and scatter them around the fish.","Roast for 12 to 15 minutes, until the crust turns deep golden and smells like toasted nuts and the beans blister and wrinkle at the tips.","Squeeze the lemon over the beans and serve, crust-side proudly up."],"tip":"Press the crust on like you mean it — a timid pat is how half your walnuts end up seasoning the sheet pan instead of the salmon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_style_salmon_skewers', '{"id":"tandoori_style_salmon_skewers","name":"Tandoori-Style Salmon Skewers with Cucumber Salad","emoji":"🔥","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"greek_yogurt","q":120},{"f":"garam_masala","q":5},{"f":"turmeric","q":2},{"f":"paprika","q":3},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"cucumber","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Stir two-thirds of the yogurt with the garam masala, turmeric, paprika, grated ginger, garlic, half the lemon juice, and salt into a marinade the color of a sunset.","Cut the salmon into large cubes, coat them in the marinade, and let them sit for 15 minutes while the broiler heats on high.","Thread the cubes onto skewers, brush with olive oil, and broil on a foil-lined pan for 8 to 10 minutes, turning once, until the edges char and the yogurt coating develops smoky dark spots.","Meanwhile, dice the cucumber and toss it with the remaining yogurt, lemon juice, chopped cilantro, and a pinch of salt for a cooling raita-style salad.","Serve the blistered skewers hot over the cold cucumber salad, with any pan juices drizzled on top."],"tip":"Char is the flavor here, so park the pan close to the broiler and let a few corners go properly black before you lose your nerve."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('balsamic_glazed_salmon_roasted_veg', '{"id":"balsamic_glazed_salmon_roasted_veg","name":"Balsamic-Glazed Salmon with Roasted Eggplant and Tomatoes","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"balsamic_vinegar","q":40},{"f":"eggplant","q":0.5},{"f":"cherry_tomatoes","q":150},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425F, cube the eggplant, and roast it with the cherry tomatoes, olive oil, salt, and pepper for 20 minutes, until the eggplant is creamy inside and the tomatoes burst.","While the vegetables roast, simmer the balsamic vinegar with the minced garlic in a small skillet for 3 to 4 minutes, until it reduces to a syrup that coats the back of a spoon.","Season the salmon and sear it in a hot skillet, 4 minutes on the skin side until crisp and 2 on the flesh side.","Brush the fillets generously with the balsamic glaze and let them sit in the warm pan for 1 minute so the syrup sets into a shiny lacquer.","Pile the roasted vegetables onto plates, top with the glazed salmon, and finish with torn basil and any stray glaze."],"tip":"Watch the reducing balsamic like a hawk in its final minute — the line between glaze and pan candy is about thirty seconds wide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_stuffed_bell_peppers', '{"id":"salmon_stuffed_bell_peppers","name":"Mexican Salmon-Stuffed Bell Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":2,"ing":[{"f":"bell_pepper","q":2},{"f":"salmon","q":300},{"f":"cauliflower","q":0.3},{"f":"salsa","q":120},{"f":"cheddar","q":60},{"f":"olive_oil","q":10},{"f":"cumin","q":3},{"f":"chili_powder","q":3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":3}],"steps":["Heat the oven to 400F, halve the bell peppers through the stem, scoop out the seeds, and roast the empty halves cut-side up for 10 minutes to give them a head start.","Pulse the cauliflower into rice and saute it in olive oil over high heat for 4 minutes with the cumin, chili powder, and salt, until fragrant and lightly toasted.","Stir in the salmon cut into small cubes and the salsa, and cook for 2 minutes, just until the fish starts to turn opaque at the edges.","Mound the filling into the softened pepper halves, cap each with cheddar, and bake for 15 minutes, until the cheese bubbles and browns at the edges and the peppers slump agreeably.","Rest for 5 minutes, then finish with lime juice and chopped cilantro before serving two halves per person."],"tip":"Undercook the salmon filling on the stove — it finishes in the oven, and nobody has ever complained that their stuffed pepper was too juicy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_zoodles', '{"id":"shrimp_scampi_zoodles","name":"Shrimp Scampi Zoodles","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"zucchini","q":2},{"f":"butter","q":40},{"f":"olive_oil","q":15},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":30},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Shave the zucchini into long ribbons with a vegetable peeler, salt them lightly, and let them drain in a colander while you cook so they stay springy instead of soggy.","Pat the shrimp bone-dry, season with salt and pepper, and sear them in the olive oil over medium-high heat for about 90 seconds per side, until they curl into loose commas and pick up golden edges; move them to a plate.","Drop the heat to medium, melt the butter in the same skillet, and stir in the sliced garlic for 60 seconds, just until it smells sweet and toasty but hasn''t browned.","Squeeze in the lemon juice, scrape up the browned bits, and return the shrimp along with any juices, tossing to glaze them in the pan sauce.","Add the zucchini ribbons and toss for one to two minutes only, until barely warmed and glossy, then shower with grated parmesan, chopped parsley, and a final crack of black pepper before serving straight from the skillet."],"tip":"Zoodles keep cooking in the residual heat, so pull the pan off the burner the moment they bend without snapping — limp zoodles have no second act."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_sheet_pan_shrimp_peppers', '{"id":"smoky_sheet_pan_shrimp_peppers","name":"Smoky Sheet-Pan Shrimp and Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"zucchini","q":1},{"f":"olive_oil","q":30},{"f":"chili_powder","q":4},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"avocado","q":1},{"f":"salt","q":3}],"steps":["Heat the oven to 230°C (450°F) with a large rimmed sheet pan inside so the vegetables hit hot metal and sizzle on contact.","Slice the peppers and onion into finger-width strips, halve the zucchini into thick half-moons, and toss everything with two-thirds of the oil, half the chili powder, the cumin, paprika, and a good pinch of salt.","Spread the vegetables on the hot pan in a single layer and roast for 12 to 14 minutes, until the pepper edges char and the onions turn silky.","Meanwhile toss the shrimp with the remaining oil and spices, then scatter them over the vegetables and roast 5 to 6 minutes more, just until the shrimp turn opaque pink and snap back when pressed.","Squeeze the lime over the whole pan while it''s still steaming, then top with sliced avocado and torn cilantro and serve right off the sheet."],"tip":"Crowded shrimp steam instead of roast, so if your pan looks like rush hour, evict the vegetables to the edges first."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_soup', '{"id":"coconut_lime_shrimp_soup","name":"Coconut-Lime Shrimp Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":600},{"f":"coconut_milk","q":400},{"f":"broth","q":1000},{"f":"mushrooms","q":250},{"f":"zucchini","q":1},{"f":"ginger","q":20},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Warm the oil in a soup pot over medium heat and sweat the sliced ginger, minced garlic, and scallion whites for two minutes, until the kitchen smells sharp and citrusy.","Add the sliced mushrooms and cook 4 to 5 minutes, stirring, until they release their liquid and it evaporates, leaving them browned at the edges.","Pour in the broth and coconut milk, season with salt, and bring to a bare simmer — small bubbles at the edge, never a rolling boil, or the coconut milk will split.","Slide in the zucchini half-moons and simmer 4 minutes until just tender, then add the shrimp and cook 2 to 3 minutes more, until they blush pink and curl.","Kill the heat, squeeze in the juice of both limes, and taste — it should be rich, salty, and bright in equal measure — then ladle into bowls and bury each under cilantro and scallion greens."],"tip":"Lime juice goes in off the heat or it turns bitter and sulky, much like anyone else who gets boiled."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_egg_roll_in_a_bowl', '{"id":"shrimp_egg_roll_in_a_bowl","name":"Shrimp Egg Roll in a Bowl","emoji":"🥡","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["shellfish","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":100},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"scallions","q":1},{"f":"black_pepper","q":2}],"steps":["Get a wok or your widest skillet screaming hot over high heat, add the olive oil, and stir-fry the shrimp for about two minutes, until pink and just barely cooked; scoop them out and set aside.","Add the minced garlic and ginger to the pan and stir for 30 seconds, until fragrant but not browned.","Pile in the shredded cabbage and grated carrots and stir-fry 4 to 5 minutes, tossing constantly, until the cabbage collapses to half its volume but still keeps a little crunch at its core.","Splash in the soy sauce, letting it hiss and reduce against the hot metal for a minute so it coats rather than puddles.","Return the shrimp, toss everything with the sesame oil and plenty of black pepper, and serve in bowls topped with sliced scallions."],"tip":"It''s everything you love about an egg roll minus the wrapper, the deep fryer, and the shame."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_shrimp_feta_cherry_tomatoes', '{"id":"baked_shrimp_feta_cherry_tomatoes","name":"Baked Shrimp with Feta and Cherry Tomatoes","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["shellfish","dairy"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"cherry_tomatoes","q":300},{"f":"feta","q":100},{"f":"olives","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"oregano","q":2},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200°C (400°F) and set a medium baking dish or ovenproof skillet on the stovetop over medium heat with the olive oil.","Soften the sliced onion for 4 minutes until translucent, then add the garlic and oregano and cook one minute more, until fragrant.","Tumble in the cherry tomatoes and cook 5 to 6 minutes, pressing a few with the back of a spoon, until they burst and their juices bubble into a loose, brick-red sauce.","Nestle the shrimp into the sauce in one layer, scatter the olives and crumbled feta over the top, and bake 8 to 10 minutes, until the shrimp are opaque and the feta has softened into creamy pockets with browned peaks.","Finish with lemon juice, chopped parsley, and black pepper, and eat it hot from the dish while the feta is still molten."],"tip":"The feta won''t fully melt and that''s the point — you want soft, briny landmines, not cheese sauce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_spinach_coconut_curry', '{"id":"shrimp_spinach_coconut_curry","name":"Shrimp and Spinach Coconut Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":250},{"f":"crushed_tomatoes","q":200},{"f":"spinach","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"curry_powder","q":6},{"f":"garam_masala","q":3},{"f":"turmeric","q":2},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Warm the oil in a deep skillet over medium heat and cook the finely chopped onion for 6 to 8 minutes, stirring now and then, until soft and golden at the edges.","Stir in the garlic, ginger, curry powder, and turmeric and toast for one minute, until the spices darken a shade and the mixture smells like the good corner of a spice shop.","Pour in the crushed tomatoes and simmer 5 minutes, until the sauce thickens and the oil beads at the edges — the classic sign the base is ready.","Add the coconut milk and salt, bring back to a gentle simmer, then slide in the shrimp and cook 3 to 4 minutes, until pink and just firm.","Fold in the spinach a handful at a time so it wilts into the sauce, dust with garam masala, and let it rest two minutes off the heat before serving."],"tip":"Garam masala is a finishing spice, not a marathon runner — add it at the end so its perfume survives the trip to the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_shrimp_avocado_spinach_salad', '{"id":"warm_shrimp_avocado_spinach_salad","name":"Warm Garlic Shrimp and Avocado Spinach Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"spinach","q":200},{"f":"asparagus","q":250},{"f":"cherry_tomatoes","q":150},{"f":"avocado","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"balsamic_vinegar","q":20},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pile the spinach into a wide serving bowl and let it wait — the hot pan contents will do the dressing and wilting for you.","Sear the asparagus pieces in half the olive oil over medium-high heat for 4 to 5 minutes, until blistered in spots but still snappy, then tip them over the spinach.","Add the remaining oil to the pan with the shrimp and sliced garlic and cook 2 to 3 minutes, tossing, until the shrimp are pink and the garlic is pale gold.","Deglaze with the balsamic vinegar and a squeeze of lemon, swirling for 30 seconds until it turns syrupy, then pour the shrimp and every drop of warm pan dressing over the greens.","Toss until the spinach slumps slightly, season with salt and pepper, and crown with the halved cherry tomatoes and sliced avocado."],"tip":"Warm dressing wilts spinach in seconds, so toss at the table unless you enjoy eating your salad against the clock."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_chicken_bacon_kale_salad', '{"id":"warm_chicken_bacon_kale_salad","name":"Warm Chicken and Bacon Kale Salad","emoji":"🥓","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","nuts"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"bacon","q":60},{"f":"kale","q":1},{"f":"walnuts","q":30},{"f":"parmesan","q":20},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Cook the chopped bacon in a large skillet over medium heat for 6 to 8 minutes, until crisp, then lift it out and leave every drop of rendered fat behind.","Season the chicken with salt and pepper, sear it in the bacon fat with the olive oil for 5 to 6 minutes per side, until deeply browned and 74°C (165°F) inside, then rest it on a board.","Strip the kale from its stems, tear it into bite-size pieces, and add it to the still-warm pan with the garlic, tossing for one to two minutes until it turns glossy, deep green, and barely tender.","Splash in the balsamic and scrape up the browned bits so the vinegar and drippings become the dressing right in the pan.","Slice the chicken against the grain, pile it over the kale, and finish with the bacon, toasted walnuts, shaved parmesan, and a crack of pepper."],"tip":"Bacon fat is the only kale massage therapist that never asks for a tip."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_spinach_bacon_egg_salad', '{"id":"warm_spinach_bacon_egg_salad","name":"Warm Wilted Spinach Salad with Bacon and Jammy Eggs","emoji":"🍳","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","gluten-free","dairy-free"],"allergens":["eggs"],"time":25,"servings":2,"ing":[{"f":"spinach","q":300},{"f":"bacon","q":100},{"f":"eggs","q":4},{"f":"mushrooms","q":150},{"f":"onion","q":0.5},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":2}],"steps":["Lower the eggs into boiling water for exactly 7 minutes, then shock them in ice water — you want set whites and yolks like soft amber jam.","Meanwhile, cook the chopped bacon in a wide skillet over medium heat until crisp, about 8 minutes, and set it on a plate, keeping the fat in the pan.","Add the olive oil, sliced mushrooms, and thinly sliced onion to the drippings and cook 5 to 6 minutes, until the mushrooms brown and the onion sweetens.","Pour in the balsamic, let it bubble for 20 seconds, then immediately tip the hot pan contents over the spinach in a large bowl and toss until the leaves collapse to a silky half-wilt.","Season with salt and pepper, divide between plates, and top with the bacon and the peeled, halved eggs, yolks facing up like they''re proud of themselves."],"tip":"Seven minutes means seven minutes — an egg timer is cheaper than the disappointment of a chalky yolk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_pork_apple_cabbage_salad', '{"id":"warm_pork_apple_cabbage_salad","name":"Warm Pork and Apple Cabbage Salad","emoji":"🍏","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"cabbage","q":0.4},{"f":"apple","q":1},{"f":"walnuts","q":40},{"f":"balsamic_vinegar","q":30},{"f":"olive_oil","q":30},{"f":"garlic","q":0.2},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin into medallions about 2 centimeters thick, season generously with salt and pepper, and sear in half the oil over medium-high heat for 3 to 4 minutes per side, until burnished and just faintly pink at the center; rest them under foil.","Add the remaining oil to the pan with the shredded cabbage and cook 6 to 8 minutes, stirring occasionally but not obsessively, so the edges char while the ribbons soften.","Stir in the garlic and matchstick-cut apple and cook two minutes more, until the apple warms through but keeps its crunch.","Deglaze with the balsamic, scraping up the pork drippings, and toss until the cabbage glistens in a tangy, mahogany glaze.","Pile the warm slaw onto plates, fan the pork medallions and their resting juices over the top, and scatter with toasted walnuts."],"tip":"Pork loin goes from juicy to gym-towel in about ninety seconds, so pull it early and let the resting juices finish the job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_salmon_asparagus_feta_salad', '{"id":"warm_salmon_asparagus_feta_salad","name":"Warm Salmon and Asparagus Salad with Feta","emoji":"🐟","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"asparagus","q":250},{"f":"spinach","q":150},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pat the salmon dry, season with salt, pepper, and oregano, and lay it skin-side down in a cold skillet with half the oil; turn the heat to medium and cook 6 to 7 minutes, until the skin releases easily and crackles like parchment.","Flip and cook 2 minutes more, until the flesh flakes at the thick end but still looks glossy inside, then rest it on a plate.","Sear the asparagus in the same pan with the remaining oil over medium-high for 4 to 5 minutes, rolling occasionally, until blistered and bright green.","Toss the warm asparagus with the spinach in a serving bowl so the residual heat softens the leaves, then dress with lemon juice and the toasty oil left in the pan.","Break the salmon into large flakes over the salad and finish with crumbled feta, olives, and a last crack of black pepper."],"tip":"Starting salmon in a cold pan is the lazy path to crisp skin — the fat renders before the flesh even notices it''s cooking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_turkey_taco_salad', '{"id":"warm_turkey_taco_salad","name":"Warm Turkey Taco Salad","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"romaine","q":1},{"f":"cheddar","q":60},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"salsa","q":120},{"f":"tomato","q":1},{"f":"scallions","q":1},{"f":"chili_powder","q":5},{"f":"cumin","q":3},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Brown the turkey in the oil over medium-high heat, breaking it into rubble and leaving it undisturbed in two-minute stretches so it develops crusty, caramelized patches instead of steaming gray.","Season with chili powder, cumin, and salt, stir in half the salsa, and simmer 3 to 4 minutes, until the mixture is saucy but not soupy.","While the meat simmers, chop the romaine into ribbons, dice the tomato, and slice the avocado and scallions.","Mound the cool, crunchy romaine into wide bowls and spoon the hot taco meat straight over the top so the cheddar you scatter next melts on contact.","Finish with tomato, avocado, scallions, the remaining salsa, and a dollop of sour cream, then toss at the table so every forkful gets hot, cold, creamy, and crisp at once."],"tip":"The hot-meat-on-cold-lettuce trick only works if you serve immediately — this salad does not believe in leftovers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_beef_larb_style_salad', '{"id":"warm_beef_larb_style_salad","name":"Warm Beef Larb-Style Lettuce Salad","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":450},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"lime","q":2},{"f":"soy_sauce","q":30},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"scallions","q":2},{"f":"cilantro","q":0.5},{"f":"chili_powder","q":2},{"f":"olive_oil","q":10}],"steps":["Heat the oil in a wok or heavy skillet over high heat and fry the ground beef, smashing it flat and letting it sizzle untouched for two minutes at a time, until deeply browned and crisp in spots, about 8 minutes total.","Push the beef aside, drop the minced garlic and ginger into the cleared space, and stir for 30 seconds until fragrant, then mix everything together.","Pull the pan off the heat and season the hot beef with the soy sauce, the juice of both limes, and the chili powder — it should taste aggressively salty, sour, and warm, because the lettuce will mellow it.","Fold in most of the sliced scallions and chopped cilantro while the meat still steams so the herbs bloom in the residual heat.","Spoon the warm beef over thick ribbons of romaine and cool half-moons of cucumber, top with the remaining herbs, and serve while the contrast between hot and crisp is at its loudest."],"tip":"Season the meat off the heat and taste before serving — lime juice mellows fast on a hot pan and shy larb is sad larb."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_skillet', '{"id":"turkey_taco_skillet","name":"Smoky Turkey Taco Skillet","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"tomato","q":2},{"f":"cheddar","q":80},{"f":"sour_cream","q":60},{"f":"avocado","q":1},{"f":"lime","q":1}],"steps":["Heat the olive oil in a large skillet over medium-high heat until it shimmers, then add the diced onion and bell pepper and cook for 4 minutes until the edges pick up a little char.","Push the vegetables aside, add the ground turkey, and let it sear undisturbed for 2 minutes before breaking it up; season generously with chili powder, cumin, smoked paprika, and salt.","Stir in the chopped tomatoes and simmer for 5 to 6 minutes, until the juices reduce into a thick, brick-red sauce that coats the back of a spoon.","Kill the heat, scatter the cheddar over the top, and cover for 2 minutes so the cheese melts into glossy pools.","Serve straight from the pan with dollops of sour cream, sliced avocado, and a hard squeeze of lime over everything."],"tip":"Let the turkey sit and sear before stirring — pale, steamed taco meat is a crime with an easy fix."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_turkey_lettuce_cups', '{"id":"ginger_turkey_lettuce_cups","name":"Ginger-Garlic Turkey Lettuce Cups","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["soy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"mushrooms","q":150},{"f":"carrots","q":1},{"f":"romaine","q":1}],"steps":["Heat the sesame oil in a wide skillet over medium-high heat and fry the minced garlic and ginger for 30 seconds, just until fragrant and sizzling but not browned.","Add the ground turkey and finely chopped mushrooms and cook for 6 to 7 minutes, breaking the meat into small crumbles, until the mushroom liquid evaporates and everything starts to brown and crackle.","Pour in the soy sauce and toss in the grated carrot, stirring for 1 minute so the sauce glazes the meat with a savory sheen.","Separate the romaine into sturdy individual leaves, rinse and pat them completely dry so they stay crisp.","Spoon the hot filling into the cool leaves at the table and eat them like tacos while the contrast of temperatures is at its best."],"tip":"Chop the mushrooms as fine as the turkey crumbles and nobody will detect your stealth vegetable operation."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_turkey_cauliflower_bowl', '{"id":"greek_turkey_cauliflower_bowl","name":"Greek Turkey and Cauliflower Rice Bowl","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"olive_oil","q":30},{"f":"cauliflower","q":0.7},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"feta","q":80},{"f":"lemon","q":1},{"f":"garlic","q":0.2}],"steps":["Pulse the cauliflower into rice-sized bits, then saute it in half the olive oil over medium-high heat for 5 minutes until it loses its raw crunch and picks up golden flecks; season with salt and scrape it into serving bowls.","Return the skillet to the heat with the remaining oil and brown the ground turkey with the minced garlic, dried oregano, salt, and pepper for 7 to 8 minutes, until deeply browned with crisp edges.","While the turkey cooks, dice the cucumber and tomatoes and toss them with a pinch of salt and half the lemon''s juice.","Pile the turkey over the cauliflower rice and spoon the juicy cucumber-tomato salad alongside so the cold and hot elements stay distinct.","Crumble the feta over everything and finish with the rest of the lemon juice and a final glug of olive oil."],"tip":"Squeeze the riced cauliflower dry in a towel first, unless soggy rice is your love language."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_turkey_stuffed_peppers', '{"id":"italian_turkey_stuffed_peppers","name":"Italian Turkey-Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"bell_pepper","q":3},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"mozzarella","q":100},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and halve the bell peppers through the stem, scooping out the seeds so you have six sturdy boats.","Brown the ground turkey in the olive oil over medium-high heat with the diced onion and garlic for 6 minutes, seasoning with dried oregano, fennel seed if you have it, salt, and plenty of black pepper.","Stir in the chopped tomatoes and spinach and cook 3 minutes more, until the spinach collapses and the mixture looks saucy but not wet.","Pack the filling into the pepper halves, top each with torn mozzarella, and bake for 22 to 25 minutes until the peppers slump slightly and the cheese is blistered and bronzed.","Rest for 5 minutes before serving so the filling sets and stops behaving like lava."],"tip":"Choose peppers that sit flat on their backs — a capsized stuffed pepper takes its cheese down with it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_parmesan_zucchini_boats', '{"id":"turkey_parmesan_zucchini_boats","name":"Turkey Parmesan Zucchini Boats","emoji":"🛶","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"zucchini","q":3},{"f":"olive_oil","q":15},{"f":"garlic","q":0.2},{"f":"tomato","q":2},{"f":"parmesan","q":40},{"f":"mozzarella","q":80}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the seedy cores with a spoon, leaving a half-centimeter wall; chop the scooped flesh and save it.","Sear the ground turkey in olive oil over medium-high heat for 5 minutes until browned, then add the garlic, reserved zucchini flesh, and chopped tomatoes with a big pinch of salt, oregano, and chili flakes.","Simmer for 5 minutes until the mixture thickens into a rustic ragu, then stir in half the parmesan off the heat.","Fill the zucchini shells generously, blanket them with mozzarella and the remaining parmesan, and bake 20 minutes until the boats are tender and the cheese is spotted brown.","Finish under the broiler for 2 minutes if you want proper bubbling drama, and serve hot."],"tip":"Salt the hollowed zucchini and let them weep for ten minutes — dry boats hold sauce, wet boats sink."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('feta_turkey_meatballs_yogurt', '{"id":"feta_turkey_meatballs_yogurt","name":"Feta Turkey Meatballs with Lemon Yogurt","emoji":"🧆","cuisine":"Mediterranean","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"eggs","q":1},{"f":"feta","q":60},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"spinach","q":150},{"f":"greek_yogurt","q":100},{"f":"lemon","q":1}],"steps":["Mix the ground turkey with the egg, crumbled feta, grated garlic, dried oregano, salt, and pepper, working it just until it holds together — overmixing makes meatballs bounce.","Roll into twelve balls with damp hands and chill them for 10 minutes so they firm up.","Brown the meatballs in olive oil over medium heat, turning every 3 minutes, for 12 to 14 minutes total, until deeply golden all over and springy to a gentle poke.","Push the meatballs to one side, pile the spinach into the pan, and let it wilt in the drippings for 2 minutes with a squeeze of lemon.","Whisk the yogurt with the remaining lemon juice and a pinch of salt, swoosh it across the plates, and top with the meatballs and greens."],"tip":"Fry one tester meatball first — seasoning regret is much cheaper at the one-ball stage."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_smash_patties_romaine', '{"id":"turkey_smash_patties_romaine","name":"Turkey Smash Patties in Romaine Wraps","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"olive_oil","q":10},{"f":"cheddar","q":60},{"f":"romaine","q":0.5},{"f":"tomato","q":1},{"f":"avocado","q":1},{"f":"onion","q":0.5}],"steps":["Divide the turkey into four loose balls and season them boldly with salt, pepper, and garlic powder — turkey forgives nothing bland.","Get a heavy skillet ripping hot with a slick of oil, drop in two balls, and smash them flat with a spatula; sear 3 minutes until a lacy brown crust forms before flipping.","Top each flipped patty with cheddar and thin onion rings, cook 2 minutes more until the cheese droops over the edges, then repeat with the second batch.","Strip the romaine into wide, cupped leaves and double them up so each wrap can handle the juices.","Load each leaf with a patty, sliced tomato, and mashed avocado, and eat over the plate — these drip with intent."],"tip":"Smash once, hard, at the start; pressing later just squeezes out the juices you worked for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('no_bean_turkey_chili', '{"id":"no_bean_turkey_chili","name":"No-Bean Turkey Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":50,"servings":4,"ing":[{"f":"ground_turkey","q":700},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":2},{"f":"garlic","q":0.4},{"f":"tomato","q":4},{"f":"broth","q":500},{"f":"zucchini","q":1},{"f":"cheddar","q":80},{"f":"sour_cream","q":100}],"steps":["Brown the ground turkey in olive oil in a heavy pot over medium-high heat for 6 to 8 minutes, letting it develop dark crusty bits on the bottom of the pot — that fond is the chili''s backbone.","Add the diced onion, bell peppers, and garlic and cook 5 minutes until softened, then bloom two tablespoons of chili powder with cumin and smoked paprika directly in the fat for 1 minute until the kitchen smells like a barbecue joint.","Stir in the chopped tomatoes and broth, scraping up the browned bits, and simmer uncovered for 25 minutes until thick enough to mound on a spoon.","Add the diced zucchini for the last 10 minutes so it stays tender-firm instead of dissolving.","Taste, correct the salt bravely, and ladle into bowls under a landslide of cheddar and sour cream."],"tip":"Chili improves overnight, so make it a day early and accept the applause tomorrow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_turkey_vegetable_soup', '{"id":"italian_turkey_vegetable_soup","name":"Italian Turkey and Greens Soup","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"ground_turkey","q":600},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":2},{"f":"celery","q":2},{"f":"broth","q":1000},{"f":"tomato","q":2},{"f":"spinach","q":150},{"f":"parmesan","q":40}],"steps":["Brown the ground turkey in olive oil in a soup pot over medium-high heat for 6 minutes, seasoning with salt, fennel seed, and chili flakes so it tastes like sausage without the casing.","Add the diced onion, carrots, celery, and garlic and sweat for 5 minutes until the onion turns translucent and the bottom of the pot glazes over.","Pour in the broth and chopped tomatoes, bring to a lively simmer, and cook for 15 minutes until the carrots yield easily to a knife tip.","Stir in the spinach off the heat and let it wilt into silky green ribbons in about a minute.","Ladle into deep bowls and shower each with grated parmesan, letting it half-melt into the surface."],"tip":"Toss the parmesan rind into the pot while it simmers — it is free umami you were about to throw away."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheddar_turkey_cauliflower_bake', '{"id":"cheddar_turkey_cauliflower_bake","name":"Cheddar Turkey Cauliflower Bake","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"cauliflower","q":0.8},{"f":"cheddar","q":100},{"f":"sour_cream","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and boil the cauliflower florets in salted water for 5 minutes, until just fork-tender; drain them aggressively and let them steam dry.","Meanwhile, brown the ground turkey with the diced onion and garlic in olive oil over medium-high heat for 7 minutes, seasoning with smoked paprika, salt, and black pepper until the meat is crusty at the edges.","Fold the turkey, cauliflower, sour cream, and half the cheddar together in a baking dish, making sure every floret gets a creamy coating.","Top with the remaining cheddar and bake for 18 to 20 minutes until the top is golden and the edges bubble like a hot spring.","Rest for 5 minutes so the bake firms from molten to merely luxurious, then serve in generous scoops."],"tip":"Undercook the cauliflower on the stove — it finishes in the oven, and nobody has ever praised mushy florets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_taco_salad_lime_crema', '{"id":"turkey_taco_salad_lime_crema","name":"Turkey Taco Salad with Lime Crema","emoji":"🥗","cuisine":"Mexican","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"olive_oil","q":15},{"f":"romaine","q":1},{"f":"avocado","q":1},{"f":"tomato","q":2},{"f":"cheddar","q":60},{"f":"greek_yogurt","q":80},{"f":"lime","q":1},{"f":"onion","q":0.5}],"steps":["Brown the ground turkey in olive oil over medium-high heat for 7 to 8 minutes with cumin, chili powder, garlic powder, and salt, cooking until the crumbles are dark-edged and sizzling.","While the meat cooks, whisk the greek yogurt with the zest and juice of the lime and a pinch of salt into a pourable crema; loosen with a teaspoon of water if it resists.","Chop the romaine into bite-sized ribbons, ice-water crisp if it has gone limp, and spread it across two wide bowls.","Scatter over the diced tomatoes, thin-sliced onion, and cubed avocado, then crown with the hot turkey so the cheese-ready heat rises through the salad.","Shower with cheddar, zigzag the lime crema over the top, and toss at the table just before eating."],"tip":"Hot meat on cold lettuce is the whole trick — assemble at the last second or accept wilted consequences."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_keema_saag', '{"id":"turkey_keema_saag","name":"Turkey Keema Saag","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"butter","q":20},{"f":"olive_oil","q":10},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"tomato","q":3},{"f":"spinach","q":200},{"f":"greek_yogurt","q":100}],"steps":["Melt the butter with the oil in a deep skillet over medium heat and fry the finely diced onion for 6 to 8 minutes until it turns a lazy amber at the edges.","Add the minced garlic and ginger with a tablespoon of garam masala, a teaspoon of turmeric, and a pinch of cayenne, frying for 1 minute until the spices darken and perfume the kitchen.","Raise the heat, add the ground turkey, and cook for 6 minutes, mashing it into fine crumbles as it browns in the spiced fat.","Stir in the chopped tomatoes and simmer for 8 minutes until they break down into a thick, rusty gravy, then fold in the spinach handful by handful until it wilts to a deep green.","Take the pan off the heat, swirl in the yogurt so it stays creamy rather than curdled, and season with salt to taste."],"tip":"Temper the yogurt with a spoonful of hot gravy before it meets the pan, and it will never break on you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('unstuffed_egg_roll_stir_fry', '{"id":"unstuffed_egg_roll_stir_fry","name":"Unstuffed Egg Roll Turkey Stir-Fry","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["soy","gluten","sesame","eggs"],"time":20,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"sesame_oil","q":20},{"f":"cabbage","q":0.5},{"f":"carrots","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"eggs","q":2}],"steps":["Heat half the sesame oil in your widest skillet over high heat and brown the ground turkey hard for 5 minutes, breaking it up only after it has developed color.","Add the garlic and ginger and stir for 30 seconds, then pile in the shredded cabbage and carrot — it will look like too much, and it is not.","Toss constantly for 4 to 5 minutes until the cabbage collapses to half its volume and picks up charred edges while keeping a slight crunch.","Splash in the soy sauce and let it hiss and glaze everything for a final minute.","In a separate small pan, fry the eggs in the remaining sesame oil until the whites are crisp-edged and the yolks still tremble, then slide one over each portion and break the yolk into the pile like a sauce."],"tip":"All the flavor of an egg roll, none of the deep-fryer cleanup — the runny yolk is doing the wrapper''s job."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_feta_skillet_frittata', '{"id":"spinach_feta_skillet_frittata","name":"Spinach & Feta Skillet Frittata","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"feta","q":80},{"f":"spinach","q":150},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and set an oven-safe 20cm skillet over medium heat with the olive oil.","Soften the sliced half onion for 4 minutes until translucent, then pile in the spinach and stir until it collapses into a glossy dark tangle and any liquid has cooked off.","Whisk the eggs with a pinch of salt and plenty of black pepper until no streaks of white remain, then pour them over the vegetables and scatter the crumbled feta on top.","Cook undisturbed for 3 minutes until the edges set and pull away from the pan, then transfer to the oven for 8 to 10 minutes until the center is puffed and barely jiggles.","Rest 2 minutes, then slide onto a board and cut into wedges; the feta should be soft and golden at the tips."],"tip":"If your frittata browns like a marshmallow at a bonfire, your oven runs hot — drop it 15 degrees next time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('broccoli_cheddar_breakfast_bake', '{"id":"broccoli_cheddar_breakfast_bake","name":"Broccoli Cheddar Breakfast Bake","emoji":"🥦","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":50,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cheddar","q":90},{"f":"broccoli","q":250},{"f":"milk","q":60},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 180C and rub a small baking dish with the olive oil so nothing welds itself to the corners.","Cut the broccoli into small florets and steam or blanch them for 3 minutes until bright green but still snappy, then drain thoroughly — wet broccoli makes a weepy bake.","Whisk the eggs with the milk, a generous pinch of salt, and black pepper until completely smooth and slightly frothy.","Arrange the broccoli in the dish, scatter over two-thirds of the grated cheddar, and pour the custard evenly on top, finishing with the remaining cheese.","Bake 30 to 35 minutes until the top is burnished gold and a knife inserted in the middle comes out clean; rest 5 minutes before scooping."],"tip":"Squeeze the blanched broccoli like it owes you money — trapped water is the enemy of a sliceable bake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_soft_scramble', '{"id":"salmon_soft_scramble","name":"Silky Salmon Soft Scramble","emoji":"🐟","cuisine":"American","meal":["breakfast"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy","fish"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"salmon","q":150},{"f":"butter","q":20},{"f":"sour_cream","q":40}],"steps":["Cut the salmon into 2cm chunks, season with salt, and sear in half the butter in a nonstick pan over medium heat for about 3 minutes until just opaque; lift it out onto a plate.","Wipe the pan, drop the heat to low, and melt the remaining butter until it foams gently.","Whisk the eggs with a pinch of salt, pour them in, and stir slowly and constantly with a spatula, scraping the bottom so soft curds form like loose ribbons — this takes a patient 4 to 5 minutes.","When the eggs are glossy and still slightly wet, fold in the salmon and the sour cream and pull the pan off the heat; residual warmth finishes the job.","Season with cracked black pepper and serve immediately, before the curds tighten up."],"tip":"Take the eggs off the heat when they look one minute underdone — carryover cooking is the sous-chef you never have to pay."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_egg_silk_stirfry', '{"id":"shrimp_egg_silk_stirfry","name":"Shrimp & Egg Silk Stir-Fry","emoji":"🦐","cuisine":"Asian","meal":["breakfast"],"diets":["dairy-free","low-carb","high-protein"],"allergens":["eggs","shellfish","soy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"shrimp","q":200},{"f":"onion","q":0.5},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Pat the shrimp completely dry, season lightly with salt, and get a wok or wide skillet screaming hot with the olive oil.","Sear the shrimp with the thinly sliced onion for about 2 minutes, tossing, until the shrimp curl into pink commas and the onion chars at the edges; scrape everything onto a plate.","Whisk the eggs with the soy sauce until uniform, lower the heat to medium, and pour the eggs into the same pan.","Let them set for 15 seconds, then push gently from the edges toward the center in big folds so the eggs stay in soft, wobbly sheets rather than dry crumbles.","When the eggs are 90 percent set, return the shrimp and onion, drizzle with sesame oil, give two final folds, and serve while everything still glistens."],"tip":"The wok should be hot enough that the shrimp hiss on contact — a quiet pan means steamed shrimp and regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_ricotta_egg_bake', '{"id":"zucchini_ricotta_egg_bake","name":"Zucchini Ricotta Egg Bake","emoji":"🥒","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":55,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"ricotta","q":150},{"f":"zucchini","q":1.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 180C, coarsely grate the zucchini, toss it with a big pinch of salt, and let it sit in a colander for 10 minutes before wringing it out in a clean towel.","Warm the olive oil in a pan over medium heat and cook the minced garlic with the zucchini for 3 to 4 minutes until fragrant and just tender.","Whisk the eggs with half the ricotta, salt, and black pepper until mostly smooth — a few ricotta flecks are charming, not a flaw.","Fold in the zucchini, pour into an oiled baking dish, and dot the surface with spoonfuls of the remaining ricotta.","Bake 30 minutes until the ricotta dollops turn golden-freckled and the center springs back when pressed; rest 5 minutes so the slices hold their shape."],"tip":"Salting and squeezing the zucchini feels fussy until you taste the difference between custard and swamp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('caprese_folded_omelet', '{"id":"caprese_folded_omelet","name":"Caprese Folded Omelet","emoji":"🍅","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mozzarella","q":100},{"f":"tomato","q":2},{"f":"olive_oil","q":15}],"steps":["Dice the tomatoes, salt them lightly, and let them drain in a sieve while you tear the mozzarella into small pieces.","Whisk 3 eggs per omelet with a pinch of salt until fully blended, and heat half the olive oil in a nonstick pan over medium heat until it shimmers.","Pour in the eggs and swirl the pan; as the edges set, drag them toward the center and tilt so raw egg flows underneath, about 90 seconds total.","While the surface is still glossy, scatter half the mozzarella and drained tomato over one side, fold the omelet over, and slide it onto a plate — the cheese will melt into soft pull-apart pockets from the residual heat.","Repeat for the second omelet, finishing each with black pepper and a thread of olive oil."],"tip":"An omelet waits for no one — plate it while the center still looks a touch underdone or eat rubber."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_parmesan_frittata', '{"id":"mushroom_parmesan_frittata","name":"Mushroom Parmesan Frittata","emoji":"🍄","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mushrooms","q":250},{"f":"parmesan","q":60},{"f":"butter","q":15},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 200C and melt the butter in an oven-safe skillet over medium-high heat until the foam subsides.","Add the sliced mushrooms in a single layer and resist stirring for 3 minutes so they brown deeply; then toss with the minced garlic and a pinch of salt and cook 2 minutes more until their liquid evaporates and the pan smells nutty.","Whisk the eggs with most of the grated parmesan and a grind of pepper, then pour over the mushrooms and shake the pan to settle everything evenly.","Cook on the stovetop 2 to 3 minutes until the edges set, dust with the remaining parmesan, and bake 7 to 9 minutes until the top is puffed and speckled gold.","Let it rest briefly, then cut into wedges — the center should be tender, not bouncy."],"tip":"Crowded mushrooms steam and sulk; give them room and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tofu_egg_breakfast_scramble', '{"id":"tofu_egg_breakfast_scramble","name":"Savory Tofu & Egg Scramble","emoji":"🥢","cuisine":"Asian","meal":["breakfast"],"diets":["vegetarian","dairy-free","low-carb","high-protein"],"allergens":["eggs","soy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"eggs","q":5},{"f":"tofu","q":250},{"f":"onion","q":0.5},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Press the tofu between paper towels for a few minutes, then crumble it into rough bite-size pieces.","Heat the olive oil in a wide skillet over medium-high heat and fry the tofu with the sliced onion for 5 to 6 minutes, stirring occasionally, until the crumbles pick up golden crusty edges.","Splash in the soy sauce and let it sizzle and coat everything with a savory lacquer, about 30 seconds.","Reduce the heat to medium-low, pour in the whisked eggs, and fold slowly so soft curds wrap around the tofu without breaking it to dust.","When the eggs are just set but still shiny, kill the heat, finish with sesame oil and black pepper, and serve straight from the pan."],"tip":"Add the soy sauce to the hot pan, not the raw eggs — caramelized soy tastes like breakfast ambition, watery soy tastes like a spill."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cottage_cheese_egg_muffin_cups', '{"id":"cottage_cheese_egg_muffin_cups","name":"Cottage Cheese Egg Muffin Cups","emoji":"🧁","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cottage_cheese","q":150},{"f":"spinach","q":100},{"f":"bell_pepper","q":0.5},{"f":"cheddar","q":40}],"steps":["Heat the oven to 180C and grease 8 cups of a muffin tin thoroughly — egg muffins cling to bare metal like barnacles.","Finely chop the bell pepper and roughly chop the spinach, then whisk the eggs with the cottage cheese, salt, and pepper until the curds are evenly suspended.","Stir the vegetables into the egg mixture and divide it among the cups, filling each about three-quarters full.","Top each cup with a pinch of grated cheddar and bake 18 to 20 minutes until puffed like little soufflés and set in the center.","Cool 5 minutes in the tin — they will deflate slightly and release cleanly — then run a knife around each and pop them out."],"tip":"They keep 4 days in the fridge, which makes Monday-you very grateful to Sunday-you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_style_poached_eggs', '{"id":"shakshuka_style_poached_eggs","name":"Shakshuka-Style Eggs in Tomato","emoji":"🍲","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tomato","q":4},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"feta","q":60},{"f":"olive_oil","q":20}],"steps":["Warm the olive oil in a deep skillet over medium heat and cook the sliced onion for 5 minutes until soft and sweet, adding the minced garlic for the final minute.","Chop the tomatoes and add them with a good pinch of salt; simmer 10 to 12 minutes, mashing occasionally, until they collapse into a thick, bubbling sauce that holds a trail when you drag a spoon through it.","Make six wells in the sauce with the back of the spoon and crack an egg into each one.","Cover the pan and cook over low heat 6 to 8 minutes, until the whites are set opaque but the yolks still shudder when you nudge the pan.","Crumble the feta over the top, grind on black pepper, and bring the whole skillet to the table while it is still burbling."],"tip":"Undercook the yolks slightly under the lid — they keep cooking while everyone argues over who gets the middle egg."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('masala_onion_tomato_omelet', '{"id":"masala_onion_tomato_omelet","name":"Masala Onion-Tomato Omelet","emoji":"🧅","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["eggs"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"onion","q":1},{"f":"tomato","q":1},{"f":"bell_pepper","q":0.5},{"f":"olive_oil","q":25}],"steps":["Finely chop the onion, tomato, and bell pepper — the pieces should be small enough to suspend in the egg rather than sink through it.","Whisk the eggs hard with the chopped vegetables, salt, and a serious amount of black pepper until the mixture is frothy and flecked throughout.","Heat half the oil in a nonstick pan over medium heat until it shimmers, then pour in half the mixture and swirl to the edges.","Cook 2 to 3 minutes until the underside is lacy and deeply browned and the top has nearly set, then flip confidently and give the second side one more minute.","Fold in half, slide onto a plate, and repeat with the remaining oil and egg; eat hot, when the onions are still juicy inside their golden crust."],"tip":"A street-cart omelet is fried, not coddled — let the underside go properly brown and crisp before you even think about flipping."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_eggs_in_avocado_boats', '{"id":"baked_eggs_in_avocado_boats","name":"Baked Eggs in Avocado Boats","emoji":"🥑","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"avocado","q":2},{"f":"eggs","q":4},{"f":"cheddar","q":40},{"f":"tomato","q":1}],"steps":["Heat the oven to 200C, halve and pit the avocados, and scoop out a spoonful from each cavity so a whole egg can actually fit — snack on the scraps.","Nestle the halves snugly in a small baking dish so they cannot tip, and season the flesh with salt and pepper.","Crack an egg into each cavity, letting any excess white spill over rather than flooding the dish, and top each with a pinch of grated cheddar.","Bake 14 to 17 minutes until the whites are just set and the cheese is bubbling; the yolks should still have a gentle wobble.","Finish with finely diced tomato and more black pepper, and serve with spoons — this is scoop-and-savor food."],"tip":"Crack each egg into a cup first so you can pour in the yolk and just enough white — avocado boats have a strict passenger limit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fajita_frittata', '{"id":"chicken_fajita_frittata","name":"Chicken Fajita Frittata","emoji":"🌶️","cuisine":"Mexican","meal":["breakfast"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"chicken_breast","q":200},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"cheddar","q":50},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and cut the chicken into thin strips; season them well with salt and pepper.","Sear the chicken in the olive oil in an oven-safe skillet over high heat for 3 to 4 minutes until golden at the edges, then add the sliced bell pepper and onion and cook 3 minutes more until the peppers blister and soften.","Whisk the eggs with a pinch of salt, pour them over the sizzling fajita mixture, and shake the pan so the egg seeps into every gap.","Scatter the grated cheddar on top and cook on the stove 2 minutes until the rim sets, then bake 8 to 10 minutes until the surface is puffed, bronzed, and set in the center.","Rest 3 minutes, then slice into fat wedges — each one should show ribbons of pepper and chicken like a cross-section of a very good decision."],"tip":"Get real char on the peppers before the eggs go in; the frittata can bake, but it cannot sear."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('parmesan_crusted_cauliflower_steaks', '{"id":"parmesan_crusted_cauliflower_steaks","name":"Parmesan-Crusted Cauliflower Steaks","emoji":"🥦","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","eggs"],"time":40,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"olive_oil","q":45},{"f":"parmesan","q":60},{"f":"garlic","q":0.3},{"f":"eggs","q":1},{"f":"lemon","q":0.5}],"steps":["Heat the oven to 220C and set a rack in the upper third so the crust browns hard.","Trim the cauliflower''s leaves, stand it stem-down, and slice two thick 2.5-centimeter steaks straight through the core so they hold together.","Brush both sides with olive oil and minced garlic, then roast on a hot sheet pan for 15 minutes until the undersides are deeply bronzed.","Whisk the egg, flip the steaks, paint the tops with egg, and press on a shaggy layer of grated parmesan.","Roast 10 to 12 minutes more until the cheese forms a crackly golden shell, then finish with a hard squeeze of lemon while everything is still sizzling."],"tip":"If your knife wobbles, the two crumbly end pieces are not failures — they are the cook''s roasted snack."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_ricotta_lasagna_bake', '{"id":"zucchini_ricotta_lasagna_bake","name":"Zucchini Ribbon Ricotta Lasagna","emoji":"🥒","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":65,"servings":2,"ing":[{"f":"zucchini","q":3},{"f":"ricotta","q":250},{"f":"mozzarella","q":120},{"f":"parmesan","q":30},{"f":"eggs","q":1},{"f":"tomato","q":3},{"f":"spinach","q":100},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15}],"steps":["Slice the zucchini lengthwise into 5-millimeter planks, salt them generously, and let them weep on a rack for 15 minutes before blotting bone-dry — this is the difference between lasagna and soup.","Simmer the chopped tomatoes with garlic and olive oil in a skillet over medium heat for 10 minutes, crushing them down until the sauce is thick enough to mound on a spoon.","Beat the ricotta with the egg and parmesan until fluffy, then fold in the spinach.","Layer sauce, zucchini planks, and ricotta in a small baking dish, repeating twice and capping the top with mozzarella.","Bake at 190C for 30 minutes until the top blisters with brown spots and the edges bubble like lava, then rest 10 full minutes so the slices hold their shape."],"tip":"Skipping the salting step is the number-one cause of lasagna puddles — respect the blot."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_cauliflower_cabbage_rolls', '{"id":"turkey_cauliflower_cabbage_rolls","name":"Turkey and Cauliflower-Rice Cabbage Rolls","emoji":"🌯","cuisine":"American","meal":["dinner"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"cabbage","q":1},{"f":"ground_turkey","q":400},{"f":"cauliflower","q":0.5},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"tomato","q":3},{"f":"broth","q":250},{"f":"olive_oil","q":15}],"steps":["Core the cabbage and dunk it into a pot of boiling water for 3 to 4 minutes, peeling off eight leaves as they turn glossy and pliable.","Pulse the cauliflower into coarse rice-sized crumbs, then mix it with the raw turkey, half the diced onion, and the garlic until just combined — overworking makes rubbery rolls.","Roll a generous handful of filling into each leaf, tucking the sides like a burrito, and nestle the rolls seam-down in a snug baking dish.","Sizzle the remaining onion in olive oil, add the chopped tomatoes and broth, and simmer 5 minutes into a loose, brick-red sauce.","Pour the sauce over the rolls, cover tightly with foil, and bake at 180C for 45 minutes until a knife slides through the cabbage with zero resistance."],"tip":"Shave down the thick rib on each leaf with a paring knife and your rolls will stop fighting you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_eggplant_shakshuka', '{"id":"smoky_eggplant_shakshuka","name":"Smoky Eggplant Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","eggs"],"time":40,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"tomato","q":4},{"f":"eggs","q":4},{"f":"feta","q":60},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30}],"steps":["Cube the eggplant and sear it in olive oil in a wide skillet over medium-high heat for 8 minutes, resisting the urge to stir until each side is mahogany and creamy inside.","Push the eggplant aside, soften the onion, bell pepper, and garlic for 4 minutes until sweet and slumped.","Add the chopped tomatoes, crushing them with your spoon, and simmer 8 to 10 minutes until the sauce darkens and thickens enough to hold a trench.","Carve four wells with the back of a spoon, crack an egg into each, cover, and cook 5 to 7 minutes until the whites set but the yolks still shiver.","Shower with crumbled feta straight off the heat so it softens into salty pockets."],"tip":"Pull the pan when the eggs look one minute underdone — carryover heat finishes them while you find forks."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_cauliflower_fried_rice', '{"id":"chicken_cauliflower_fried_rice","name":"Chicken Cauliflower Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["low-carb","dairy-free","high-protein"],"allergens":["soy","gluten","eggs","sesame"],"time":30,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chicken_breast","q":300},{"f":"eggs","q":2},{"f":"carrots","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15}],"steps":["Pulse the cauliflower florets into rice-sized bits and spread them on a towel to shed surface moisture while you prep everything else.","Get a wok or large skillet screaming hot, then sear diced chicken in olive oil for 4 to 5 minutes until the edges brown; scoop it out.","Scramble the eggs hard and fast in the same pan for 30 seconds, breaking them into ribbons, and set them with the chicken.","Stir-fry the onion, carrots, and garlic for 2 minutes, then add the cauliflower rice in a single layer and let it sit untouched for 90 seconds to pick up toasty char.","Return the chicken and eggs, splash in the soy sauce around the pan''s rim so it sizzles and caramelizes, and finish off-heat with sesame oil."],"tip":"Wet cauliflower steams and sulks; dry cauliflower fries and sings — towel it like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_charred_cabbage_stir_fry', '{"id":"crispy_tofu_charred_cabbage_stir_fry","name":"Crispy Tofu and Charred Cabbage Stir-Fry","emoji":"🥬","cuisine":"Asian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","low-carb"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"cabbage","q":0.5},{"f":"mushrooms","q":150},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":30}],"steps":["Press the tofu between towels under a heavy pan for 10 minutes, then tear it into ragged bite-sized chunks — torn edges crisp better than clean cubes.","Fry the tofu in olive oil over medium-high heat for 8 minutes, turning only when each side releases easily and turns deep gold; set aside.","Crank the heat, add the mushrooms, and cook 3 minutes until they squeak and brown.","Add thick ribbons of cabbage and let them scorch against the pan for 2 minutes before tossing, chasing blistered black-edged leaves that stay crunchy at the core.","Return the tofu with the garlic, pour the soy sauce down the hot side of the pan so it hisses and glazes everything, and finish with sesame oil off the heat."],"tip":"A crowded pan is a steamy pan — if your skillet is small, char the cabbage in two shifts."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_scampi_zucchini_noodles', '{"id":"shrimp_scampi_zucchini_noodles","name":"Shrimp Scampi with Zucchini Noodles","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"zucchini","q":3},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"garlic","q":0.4},{"f":"lemon","q":1},{"f":"parmesan","q":20}],"steps":["Spiralize the zucchini into long noodles and pat them dry — they will release plenty of water later, so start them as dry as possible.","Melt the butter with olive oil in a wide skillet over medium heat and bloom the sliced garlic for 60 seconds until fragrant but not browned.","Raise the heat, add the shrimp in one layer, and cook 90 seconds per side until they curl into loose commas and blush pink; overcooked shrimp curl into tight Os, so pull them promptly.","Toss the zucchini noodles into the garlicky pan juices for just 2 minutes, until barely tender but still snappy.","Return the shrimp, squeeze in the lemon, and serve immediately with a light dusting of parmesan before the noodles think about weeping."],"tip":"Zoodles keep cooking on the plate, so undershoot the doneness you want by a solid minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_eggplant_tofu_curry', '{"id":"coconut_eggplant_tofu_curry","name":"Coconut Eggplant Curry","emoji":"🍆","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["soy"],"time":45,"servings":4,"ing":[{"f":"eggplant","q":2},{"f":"coconut_milk","q":400},{"f":"tomato","q":3},{"f":"tofu","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"spinach","q":150},{"f":"olive_oil","q":30}],"steps":["Cut the eggplants into chunky 3-centimeter pieces and brown them in oil over medium-high heat in two batches, about 6 minutes per batch, until the cut faces are burnished and the flesh turns silky.","Soften the onion in the same pot for 5 minutes, then add the garlic and cook until the whole kitchen smells like dinner.","Add the chopped tomatoes and simmer 8 minutes, mashing them down until the mixture thickens into a rusty, jammy base.","Pour in the coconut milk, return the eggplant with cubed tofu, and simmer gently for 12 to 15 minutes until the sauce coats a spoon and the eggplant collapses at the touch of a fork.","Wilt in the spinach during the last 2 minutes and season boldly — coconut milk drinks up salt like it is owed."],"tip":"Browned eggplant is the entire curry; pale eggplant is a spongy apology, so take the extra six minutes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('roasted_cauliflower_cheddar_soup', '{"id":"roasted_cauliflower_cheddar_soup","name":"Roasted Cauliflower Cheddar Soup","emoji":"🥣","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":55,"servings":4,"ing":[{"f":"cauliflower","q":2},{"f":"cheddar","q":200},{"f":"milk","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.2},{"f":"olive_oil","q":30}],"steps":["Break the cauliflower into florets, toss with olive oil, and roast at 220C for 25 minutes until the edges frazzle and brown — that caramelization is the soup''s backbone.","Meanwhile, melt the butter in a soup pot and sweat the onion over medium-low heat for 8 minutes until translucent and sweet, adding the garlic for the final minute.","Add the roasted cauliflower, reserving a handful of the crispiest florets for garnish, and pour in the milk plus 500 milliliters of water.","Simmer gently for 10 minutes, then blend until completely velvety, thinning with water if it stands up too stiffly.","Off the heat, stir in the cheddar a handful at a time until it melts glossy and smooth — boiling it now would break the cheese, so keep it below a simmer.","Ladle into bowls and crown with the reserved roasted florets."],"tip":"Grate the cheddar yourself; pre-shredded bags are dusted with anti-caking agents that turn silky soup grainy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_and_cabbage_soup', '{"id":"beef_and_cabbage_soup","name":"Unstuffed Cabbage Beef Soup","emoji":"🍲","cuisine":"American","meal":["dinner","lunch"],"diets":["low-carb","gluten-free","dairy-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"cabbage","q":0.5},{"f":"tomato","q":3},{"f":"broth","q":1000},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"olive_oil","q":15}],"steps":["Brown the beef in olive oil over high heat in a heavy pot, letting it sit undisturbed for 3 minutes to build a crusty fond before breaking it up.","Add the onion and carrots and cook 5 minutes until the onion softens and picks up the beefy drippings, then stir in the garlic for 30 seconds.","Add the chopped tomatoes and scrape the pot bottom hard — every brown speck you free is flavor you already paid for.","Pour in the broth, slide in thick ribbons of cabbage, and simmer uncovered for 25 minutes until the cabbage turns silky and the broth tastes rich and rounded.","Season assertively and ladle into deep bowls while it steams."],"tip":"This soup is one of those rare dishes that is honestly better tomorrow, so make it tonight for the person you will be on Tuesday."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_fajita_zucchini_boats', '{"id":"chicken_fajita_zucchini_boats","name":"Chicken Fajita Zucchini Boats","emoji":"🛶","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"zucchini","q":3},{"f":"chicken_breast","q":300},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"cheddar","q":80},{"f":"sour_cream","q":60},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Halve the zucchini lengthwise and scoop out the seedy centers with a spoon, leaving sturdy 1-centimeter walls; chop the scooped flesh and save it.","Roast the hollowed boats cut-side up at 200C for 10 minutes to drive off moisture while you build the filling.","Sear thin strips of chicken in olive oil over high heat for 4 minutes until browned at the edges, then add the bell pepper, onion, and reserved zucchini flesh and cook 4 minutes more until sizzling and slightly charred.","Hit the filling with half the lime juice, pile it into the boats, and blanket with cheddar.","Bake 12 to 15 minutes until the cheese bubbles and browns in spots, then serve with cool dollops of sour cream and the remaining lime."],"tip":"The scooped zucchini innards are free vegetables hiding in plain sight — chop them into the filling instead of the compost."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_eggplant_whipped_feta_platter', '{"id":"charred_eggplant_whipped_feta_platter","name":"Charred Eggplant with Whipped Feta","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"eggplant","q":2},{"f":"feta","q":120},{"f":"greek_yogurt","q":150},{"f":"tomato","q":1},{"f":"cucumber","q":1},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"olive_oil","q":45}],"steps":["Slice the eggplants into thick 2-centimeter rounds, brush both sides generously with olive oil, and get a grill pan ripping hot over high heat.","Grill the rounds 4 to 5 minutes per side until deep char stripes appear and the centers turn custardy — press one gently; it should give like a ripe peach.","While they cook, blitz the feta, greek yogurt, garlic, and half the lemon juice until it whips into a smooth, tangy cloud.","Swoosh the whipped feta across a platter and shingle the hot eggplant on top so the cheese softens beneath it.","Scatter with diced tomato and cucumber, then finish with the last of the lemon and a final glossy thread of olive oil."],"tip":"Hot eggplant on cold whipped feta is the whole trick — plate it straight off the grill or lose the magic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_cauliflower_rice_skillet', '{"id":"beef_taco_cauliflower_rice_skillet","name":"Beef Taco Cauliflower Rice Skillet","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["low-carb","gluten-free","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"cauliflower","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"tomato","q":2},{"f":"cheddar","q":60},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Pulse the cauliflower into rice-sized crumbs and set it aside on a dry towel.","Brown the beef in olive oil over high heat for 5 minutes, leaving it alone long enough to develop crusty, deeply seasoned edges before breaking it apart.","Add the onion and bell pepper and cook 3 minutes until they soften into the beef fat and smell sweet.","Stir in the chopped tomatoes and simmer 3 minutes until saucy, then fold in the cauliflower rice and cook 4 to 5 minutes, until tender but still faintly toothsome.","Kill the heat, squeeze the lime over everything, and scatter the cheddar across the top, covering for one minute so it melts into molten pockets."],"tip":"Taste before you top — the lime does more heavy lifting here than any amount of extra cheese will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_zoodle_soup', '{"id":"chicken_zoodle_soup","name":"Chicken Zoodle Soup","emoji":"🍜","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"chicken_breast","q":700},{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"carrots","q":2},{"f":"zucchini","q":3},{"f":"broth","q":1500}],"steps":["Warm the olive oil in a Dutch oven over medium heat and sweat the diced onion and sliced carrots for 6 minutes, until the onion turns translucent and smells sweet.","Stir in the minced garlic and cook 30 seconds, just until fragrant, then pour in the broth and bring it to a lively simmer.","Slip in the whole chicken breasts, drop the heat to low, and poach gently for 15 minutes, until the thickest piece registers 74C and the broth is golden.","Lift out the chicken, shred it with two forks into ragged bite-size pieces, and return it to the pot with plenty of salt and cracked pepper.","Shave the zucchini into long ribbons or noodles, stir them into the hot soup, and simmer just 2 minutes so they stay al dente rather than slumping into mush.","Taste, adjust the seasoning, and ladle into deep bowls while the zoodles still have a little snap."],"tip":"Add the zoodles at the last minute — zucchini goes from noodle to noodle soup faster than you can find the ladle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tuscan_chicken_stew', '{"id":"creamy_tuscan_chicken_stew","name":"Creamy Tuscan Chicken Stew","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":600},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":5},{"f":"spinach","q":250},{"f":"milk","q":250},{"f":"parmesan","q":60},{"f":"broth","q":500}],"steps":["Cut the chicken into 3-centimeter chunks, season generously with salt and pepper, and sear in olive oil over medium-high heat for 4 minutes, until the edges are deeply golden but the centers are still pale.","Push the chicken aside, add the diced onion, and cook 5 minutes until soft, then stir in the minced garlic for a fragrant 30 seconds.","Add the chopped tomatoes and cook 6 to 8 minutes, mashing occasionally, until they collapse into a rough, jammy sauce that coats the back of a spoon.","Pour in the broth and milk, bring to a bare simmer, and cook uncovered for 12 minutes so the stew thickens slightly and the chicken turns tender.","Off the heat, stir in the grated parmesan and spinach by the handful, letting each addition wilt into glossy dark ribbons before adding the next.","Rest the stew 5 minutes so the flavors settle, then serve in shallow bowls with an extra grating of parmesan."],"tip":"Keep the milk at a gentle simmer, not a boil — curdled Tuscan stew is a Renaissance tragedy nobody paints."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_no_bean_beef_chili_2', '{"id":"smoky_no_bean_beef_chili_2","name":"Smoky No-Bean Beef Chili","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":55,"servings":4,"ing":[{"f":"ground_beef","q":600},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":2},{"f":"tomato","q":6},{"f":"broth","q":500},{"f":"cheddar","q":100},{"f":"sour_cream","q":100}],"steps":["Brown the ground beef in a heavy pot over medium-high heat for 7 to 8 minutes, breaking it into rough crumbles and letting a dark fond build on the bottom of the pot.","Add the diced onion and bell peppers and cook 5 minutes, scraping up the browned bits, until the vegetables soften and pick up color.","Stir in the minced garlic along with a generous spoonful of chili seasonings, salt, and pepper, toasting for 1 minute until the whole kitchen smells smoky.","Add the chopped tomatoes and broth, bring to a boil, then reduce to a low, blipping simmer and cook uncovered for 30 minutes, until the chili is thick enough to mound on a spoon.","Taste and sharpen the seasoning, then ladle into bowls and crown each with shredded cheddar and a cool spoonful of sour cream."],"tip":"Let the beef sit untouched for the first few minutes — fiddling with it steams the meat, and steam never won a chili cook-off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_albondigas_soup', '{"id":"turkey_albondigas_soup","name":"Turkey Albondigas Soup","emoji":"🥣","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["eggs"],"time":50,"servings":4,"ing":[{"f":"ground_turkey","q":600},{"f":"eggs","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":2},{"f":"zucchini","q":2},{"f":"tomato","q":3},{"f":"broth","q":1500},{"f":"avocado","q":2},{"f":"lime","q":1}],"steps":["Mix the ground turkey with the egg, half the minced garlic, a quarter of the onion grated fine, and a heavy pinch of salt, then roll into walnut-size meatballs with damp hands so they stay smooth.","In a large pot, simmer the broth with the remaining onion, garlic, chopped tomatoes, and sliced carrots for 10 minutes, until the tomatoes soften and tint the broth a pale orange.","Lower the meatballs into the barely simmering broth one at a time and poach gently for 12 minutes without stirring, until they float and feel springy when pressed.","Add the half-moons of zucchini and simmer 5 more minutes, just until they turn glossy and tender at the edges.","Season the broth boldly with salt and pepper, then ladle into bowls and finish each with diced avocado and a hard squeeze of lime."],"tip":"A gentle simmer is meatball insurance — a rolling boil will shake your albondigas apart like a piñata."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_cauliflower_chowder_2', '{"id":"salmon_cauliflower_chowder_2","name":"Salmon and Cauliflower Chowder","emoji":"🐟","cuisine":"American","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["fish","dairy"],"time":40,"servings":4,"ing":[{"f":"salmon","q":500},{"f":"cauliflower","q":0.7},{"f":"milk","q":600},{"f":"butter","q":40},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":500}],"steps":["Melt the butter in a soup pot over medium heat and cook the diced onion for 5 minutes, until soft and just turning gold at the edges, then add the minced garlic for 30 seconds.","Add the cauliflower florets and broth, bring to a simmer, and cook 10 minutes, until a knife slides through a floret with no resistance.","Ladle a third of the cauliflower into a blender with a splash of the liquid, puree until silky, and stir it back in — this gives the chowder body without a speck of flour.","Pour in the milk, bring back to the barest simmer, and slide in the salmon cut into 3-centimeter chunks; poach 5 to 6 minutes, until the fish turns opaque and flakes at a nudge.","Season assertively with salt and pepper, let the chowder rest 3 minutes off the heat, and serve steaming with the salmon chunks still intact."],"tip":"Stir like you mean it before the salmon goes in and barely at all after — flaky fish is the goal, salmon confetti is not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_shrimp_feta_stew', '{"id":"greek_shrimp_feta_stew","name":"Greek Shrimp and Feta Stew","emoji":"🦐","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["shellfish","dairy"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":600},{"f":"olive_oil","q":45},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"tomato","q":6},{"f":"spinach","q":150},{"f":"feta","q":120},{"f":"lemon","q":1}],"steps":["Heat the olive oil in a wide, deep skillet over medium heat and cook the diced onion for 6 minutes, until soft and sweet, then add the sliced garlic and cook 1 minute more.","Add the chopped tomatoes with a good pinch of salt and simmer 12 to 15 minutes, crushing them against the pan, until they break down into a thick, brick-red sauce that sizzles at the edges.","Stir in the spinach a handful at a time and let it wilt completely into the sauce, about 2 minutes.","Nestle the shrimp into the sauce in a single layer, scatter the crumbled feta over the top, cover, and cook 4 to 5 minutes, until the shrimp curl into pink commas and the feta softens into creamy pockets.","Finish with the juice of half the lemon and black pepper, then serve straight from the pan with the remaining lemon in wedges."],"tip":"Pull the pan off the heat the second the shrimp curl — they keep cooking in the sauce, and rubbery shrimp file formal complaints."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_tofu_cabbage_stew', '{"id":"peanut_tofu_cabbage_stew","name":"Spicy Peanut Tofu Cabbage Stew","emoji":"🥜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","low-carb"],"allergens":["soy","gluten","nuts","sesame"],"time":40,"servings":4,"ing":[{"f":"tofu","q":600},{"f":"peanut_butter","q":120},{"f":"cabbage","q":0.3},{"f":"bell_pepper","q":1},{"f":"ginger","q":20},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"lime","q":1}],"steps":["Press the tofu for 10 minutes, cut it into 2-centimeter cubes, and sear in the sesame oil over medium-high heat for 6 to 8 minutes, turning until the faces are burnished and crisp.","Add the minced ginger and garlic to the pot and stir for 30 seconds, until the aroma blooms and hits the back of your throat.","Whisk the peanut butter and soy sauce into 1 liter of hot water until smooth, pour it over the tofu, and bring to a gentle simmer.","Add the shredded cabbage and sliced bell pepper and simmer uncovered for 10 minutes, until the cabbage is silky and the broth has thickened to the texture of thin cream.","Squeeze in the lime juice, taste for salt and heat, and serve in deep bowls while the broth still clings to every cube of tofu."],"tip":"The peanut broth thickens as it sits, so keep a kettle of hot water nearby to loosen leftovers back into stew instead of dip."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('silky_egg_drop_tofu_soup', '{"id":"silky_egg_drop_tofu_soup","name":"Silky Egg Drop Soup with Tofu and Mushrooms","emoji":"🥚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","low-carb"],"allergens":["eggs","soy","gluten","sesame"],"time":30,"servings":4,"ing":[{"f":"eggs","q":8},{"f":"tofu","q":500},{"f":"mushrooms","q":300},{"f":"spinach","q":150},{"f":"ginger","q":15},{"f":"garlic","q":0.3},{"f":"broth","q":1500},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":45}],"steps":["Bring the broth to a simmer with the sliced ginger and smashed garlic and let it steep for 5 minutes, until the steam smells warm and peppery.","Add the sliced mushrooms and simmer 5 minutes, until they darken and sink, then stir in the soy sauce and cubed tofu to heat through.","Beat the eggs thoroughly in a spouted measuring cup so they pour in a thin, controllable stream.","With the soup at a bare simmer, stir slowly in one direction and drizzle in the eggs in a lazy spiral; give them 30 undisturbed seconds so they set into wide, silky ribbons.","Turn off the heat, fold in the spinach until it just wilts, and finish each bowl with a fragrant spoonful of sesame oil and black pepper."],"tip":"The slower you pour and the less you stir, the wider the egg ribbons — patience is the only thickener this soup needs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_cheddar_soup', '{"id":"cauliflower_cheddar_soup","name":"Cauliflower Cheddar Soup","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"cauliflower","q":1.3},{"f":"cheddar","q":200},{"f":"milk","q":500},{"f":"butter","q":40},{"f":"onion","q":1},{"f":"garlic","q":0.3}],"steps":["Melt the butter in a soup pot over medium heat and cook the diced onion with a pinch of salt for 6 minutes, until translucent and sweet, then stir in the minced garlic for 30 seconds.","Add the cauliflower florets and 750 milliliters of water, bring to a boil, then cover and simmer 12 minutes, until the florets crush easily against the side of the pot.","Pour in the milk and puree the soup with an immersion blender until completely smooth and glossy, like a pale velvet.","Over the lowest heat, add the shredded cheddar one handful at a time, whisking each addition until fully melted before adding the next so the soup stays silky instead of grainy.","Season with salt and plenty of black pepper, thin with a splash of water if it tightens up, and serve hot with extra cheddar on top."],"tip":"Grate your own cheddar — the anti-caking dust on pre-shredded cheese turns velvet soup into something suspiciously gritty."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('unstuffed_cabbage_beef_stew', '{"id":"unstuffed_cabbage_beef_stew","name":"Unstuffed Cabbage and Beef Stew","emoji":"🥬","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"cabbage","q":0.6},{"f":"tomato","q":5},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":750},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a Dutch oven over medium-high heat and brown the ground beef for 6 to 7 minutes, breaking it up and letting it crisp in spots before you stir.","Add the diced onion and cook 5 minutes until soft, then stir in the minced garlic and a generous hit of salt and pepper for 30 seconds.","Add the chopped tomatoes and cook 5 minutes, until they slump and release their juices to deglaze the browned bottom of the pot.","Pile in the roughly chopped cabbage, pour in the broth, and bring to a boil; it will look like too much cabbage, but press it down and trust the wilt.","Cover and simmer 20 minutes, stirring once halfway, until the cabbage is tender and translucent and the broth tastes deeply savory.","Taste for seasoning and serve in wide bowls with the juices ladled generously over the top."],"tip":"All the flavor of cabbage rolls with none of the rolling — your fingers can send a thank-you card."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_stroganoff_soup', '{"id":"mushroom_stroganoff_soup","name":"Mushroom Stroganoff Soup","emoji":"🍄","cuisine":"American","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"mushrooms","q":600},{"f":"butter","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"sour_cream","q":250},{"f":"milk","q":300},{"f":"parmesan","q":50}],"steps":["Melt the butter in a wide pot over medium-high heat and cook the thickly sliced mushrooms in two batches, 6 minutes per batch without crowding, until they are deeply browned and squeak-free.","Return all the mushrooms to the pot with the diced onion and cook 5 minutes, until the onion softens in the mushroom butter, then add the minced garlic for 30 seconds.","Pour in the milk and 500 milliliters of water, season with salt and a heavy grind of pepper, and simmer gently for 10 minutes so the broth takes on the mushrooms'' woodsy depth.","Reduce the heat to its lowest setting and whisk in the sour cream and grated parmesan until the soup turns pale, tangy, and just thick enough to coat a spoon.","Warm through without boiling for 2 minutes, taste for salt, and serve with more pepper cracked over each bowl."],"tip":"Brown the mushrooms like you hold a grudge — the crusty batch-two patience is where all the stroganoff flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('indian_yogurt_cauliflower_curry_stew', '{"id":"indian_yogurt_cauliflower_curry_stew","name":"Indian Yogurt and Cauliflower Curry Stew","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy","nuts"],"time":45,"servings":4,"ing":[{"f":"cauliflower","q":1},{"f":"spinach","q":200},{"f":"tomato","q":4},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":20},{"f":"butter","q":60},{"f":"greek_yogurt","q":300},{"f":"almonds","q":80}],"steps":["Melt the butter in a heavy pot over medium heat and fry the sliced onion for 8 to 10 minutes, until deeply golden at the edges, then add the minced garlic, ginger, and your curry spices and toast 1 fragrant minute.","Add the chopped tomatoes and cook 8 minutes, mashing as they soften, until the mixture thickens into a rusty paste and the butter beads at the edges.","Add the cauliflower florets with 500 milliliters of water and a big pinch of salt, cover, and simmer 12 minutes, until the florets are tender but still hold their shape.","Stir in the spinach until it wilts, then pull the pot off the heat and fold in the greek yogurt one spoonful at a time so it melts into a creamy, pale-orange sauce without splitting.","Scatter with toasted sliced almonds and serve hot, with the sauce thick enough to eat with a fork but worth chasing with a spoon."],"tip":"Always add yogurt off the heat — a boiled yogurt curry splits into curds and regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('provencal_ratatouille_stew', '{"id":"provencal_ratatouille_stew","name":"Provencal Ratatouille Stew with Walnuts","emoji":"🍅","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["nuts"],"time":50,"servings":4,"ing":[{"f":"zucchini","q":3},{"f":"bell_pepper","q":2},{"f":"tomato","q":6},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"olive_oil","q":80},{"f":"walnuts","q":80},{"f":"spinach","q":100}],"steps":["Heat half the olive oil in a Dutch oven over medium-high heat and brown the chunked zucchini in a single layer for 5 minutes, until golden on the cut faces, then set it aside so it does not stew into mush too early.","Add the remaining oil, the diced onion, and the bell pepper strips and cook 8 minutes, until soft and sweet with a few caramelized edges, then stir in the sliced garlic for 1 minute.","Add the chopped tomatoes with a serious pinch of salt and simmer 15 minutes, uncovered, until they collapse into a thick, glossy sauce slicked with red-gold oil.","Return the zucchini to the pot with 250 milliliters of water, reduce the heat, and simmer gently for 10 minutes, until every vegetable is tender but still distinct.","Fold in the spinach to wilt, season with salt and pepper, and serve warm with toasted walnuts scattered over each bowl for crunch."],"tip":"Ratatouille tastes even better tomorrow, so make it today and accept the compliments on a delay."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_chicken_lettuce_wraps', '{"id":"ginger_chicken_lettuce_wraps","name":"Ginger Chicken Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch"],"diets":["low-carb","high-protein","dairy-free"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"mushrooms","q":150},{"f":"scallions","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10},{"f":"cashews","q":30},{"f":"romaine","q":1},{"f":"black_pepper","q":1}],"steps":["Dice the chicken breast into pea-sized pieces and mince the mushrooms so they nearly disappear into the filling.","Heat the olive oil in a large skillet over medium-high until shimmering, then add the chicken in a single layer and let it sear undisturbed for 2 minutes before stirring.","Add the mushrooms, grated ginger, and minced garlic and cook 4 to 5 minutes more, until the pan looks dry and the chicken is golden at the edges.","Pour in the soy sauce and sesame oil, scraping up the browned bits, and simmer 1 minute until the liquid clings to the meat like a glaze.","Stir in most of the sliced scallions and the roughly chopped cashews, then taste for pepper.","Separate the romaine into sturdy cup-shaped leaves, pile the hot filling inside, and scatter the remaining scallions over the top."],"tip":"Chill the romaine in ice water for five minutes first — a crisp, cold cup against the hot filling is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_avocado_cucumber_boats', '{"id":"shrimp_avocado_cucumber_boats","name":"Chili-Lime Shrimp Cucumber Boats","emoji":"🥒","cuisine":"Mexican","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free","dairy-free"],"allergens":["shellfish"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"cucumber","q":2},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"garlic","q":0.2},{"f":"olive_oil","q":20},{"f":"chili_powder","q":4},{"f":"cumin","q":2},{"f":"salt","q":3}],"steps":["Halve the cucumbers lengthwise and drag a spoon down the center of each to scoop out the seeds, leaving four sturdy boats; sprinkle the hollows with a little salt and set them cut-side down to drain.","Pat the shrimp bone-dry, then toss with chili powder, cumin, minced garlic, and half the olive oil until evenly rusty red.","Sear the shrimp in a hot skillet over medium-high for about 90 seconds per side, until they curl into loose Cs and turn opaque — pull them the moment they do.","Chop the shrimp roughly and fold with diced avocado, quartered cherry tomatoes, chopped cilantro, the remaining oil, and a generous squeeze of lime.","Blot the cucumber boats dry, mound the shrimp mixture into each, and finish with more lime and cilantro."],"tip":"A shrimp shaped like an O has already told you it''s overcooked — stop at the C."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_salad_avocado_halves', '{"id":"tuna_salad_avocado_halves","name":"Lemon-Herb Tuna Avocado Halves","emoji":"🥑","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"greek_yogurt","q":100},{"f":"celery","q":60},{"f":"scallions","q":0.3},{"f":"lemon","q":0.5},{"f":"avocado","q":2},{"f":"olive_oil","q":10},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2},{"f":"salt","q":2}],"steps":["Drain the tuna thoroughly and flake it into a bowl with a fork until no large chunks remain.","Stir in the Greek yogurt, olive oil, finely diced celery, thinly sliced scallions, and chopped parsley until the salad is creamy but still has crunch.","Season assertively with lemon juice, salt, and plenty of black pepper — cold salads need louder seasoning than you think.","Halve and pit the avocados, then scoop out an extra spoonful from each half to widen the crater and fold that flesh into the tuna.","Pile the tuna salad high into the avocado halves and finish with a last squeeze of lemon and a scatter of parsley."],"tip":"Squeeze lemon over the avocado craters the second you open them, or they will brown faster than you can set the table."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('seared_salmon_asparagus_plate', '{"id":"seared_salmon_asparagus_plate","name":"Crispy-Skin Salmon with Lemon Butter Asparagus","emoji":"🐟","cuisine":"American","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"asparagus","q":350},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"lemon","q":1},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Pat the salmon fillets very dry, season with salt and pepper, and let them sit at room temperature while you snap the woody ends off the asparagus.","Heat the olive oil in a heavy skillet over medium-high until it just starts to smoke, then lay the salmon in skin-side down and press gently for 10 seconds so the skin stays flat.","Cook without moving for 5 to 6 minutes, until the flesh turns opaque two-thirds of the way up the sides, then flip and cook 1 minute more before resting on a plate.","In the same pan, melt the butter with the sliced garlic and toss in the asparagus, rolling the spears for 3 to 4 minutes until bright green and blistered in spots.","Squeeze in the juice of half the lemon, swirl the pan into a quick sauce, and shower with parsley.","Plate the asparagus, set the salmon on top skin-side up so it stays shatteringly crisp, and serve with lemon wedges."],"tip":"If the salmon resists when you try to flip it, it is not ready — properly seared skin releases on its own."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_lettuce_boats', '{"id":"beef_taco_lettuce_boats","name":"Smoky Beef Taco Lettuce Boats","emoji":"🌮","cuisine":"Mexican","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"paprika","q":2},{"f":"romaine","q":1},{"f":"cheddar","q":50},{"f":"salsa","q":100},{"f":"avocado","q":1},{"f":"sour_cream","q":40},{"f":"lime","q":0.5},{"f":"salt","q":3}],"steps":["Brown the ground beef in a dry skillet over medium-high heat, breaking it into small crumbles and letting it sizzle until the edges crisp, about 6 minutes.","Push the beef aside, add the diced onion to the rendered fat, and cook 3 minutes until translucent before stirring in the garlic, chili powder, cumin, paprika, and salt.","Splash in a few tablespoons of water and simmer 2 minutes, stirring, until the spices bloom into a glossy sauce that coats every crumble.","Trim the romaine into a dozen cupped leaves, doubling up thinner ones so each boat holds its cargo.","Spoon the hot beef into the leaves and top with grated cheddar so it slumps slightly, then finish with salsa, diced avocado, sour cream, and a squeeze of lime."],"tip":"Season the beef until it tastes almost too bold on its own — cool lettuce and cream mute everything by half."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_turkey_meatball_plate', '{"id":"greek_turkey_meatball_plate","name":"Greek Turkey Meatballs with Yogurt Sauce","emoji":"🫒","cuisine":"Mediterranean","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"eggs","q":1},{"f":"feta","q":60},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"onion","q":0.3},{"f":"greek_yogurt","q":100},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":25},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Grate the onion directly into the ground turkey, then add the egg, crumbled feta, two minced garlic cloves, oregano, salt, and pepper, mixing with your hands just until combined — overworking makes them tough.","Roll the mixture into 12 golf-ball-sized meatballs with damp hands and chill them for 10 minutes so they hold their shape.","Heat the olive oil in a skillet over medium and brown the meatballs on all sides, about 10 to 12 minutes total, until deeply golden and an inner peek shows no pink.","While they cook, grate half the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the last garlic clove, lemon juice, and a pinch of salt.","Dice the remaining cucumber and plate it with halved cherry tomatoes and olives, then nestle the meatballs alongside and spoon the yogurt sauce generously over everything."],"tip":"Wring that grated cucumber like it owes you money, or your sauce will be soup by noon."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_sesame_slaw', '{"id":"crispy_tofu_sesame_slaw","name":"Crispy Tofu and Sesame-Lime Slaw","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["low-carb","high-protein","vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy","sesame","nuts"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"edamame_frozen","q":100},{"f":"cabbage","q":0.3},{"f":"carrots","q":100},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.3},{"f":"sesame_oil","q":20},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"ginger","q":10},{"f":"garlic","q":0.1},{"f":"cashews","q":40},{"f":"salt","q":4}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then tear it into rough bite-sized chunks — ragged edges crisp better than clean cubes.","Heat the olive oil in a wide skillet over medium-high and fry the tofu, turning every 2 to 3 minutes, until all sides are burnished and crackly, about 10 minutes; salt it while hot.","Meanwhile, shave the cabbage into thin ribbons and grate the carrots, tossing both with a pinch of salt to soften slightly.","Whisk the sesame oil, lime juice, grated ginger, minced garlic, and a pinch of salt into a sharp dressing, then pour it over the slaw with the thawed edamame, scallions, and most of the cilantro.","Pile the slaw into bowls, crown with the hot crispy tofu, and finish with toasted chopped cashews and the remaining cilantro."],"tip":"Tear the tofu, don''t cube it — those craggy surfaces are where the crunch lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_parmesan_frittata_2', '{"id":"zucchini_parmesan_frittata_2","name":"Zucchini Parmesan Frittata","emoji":"🍳","cuisine":"Italian","meal":["lunch"],"diets":["low-carb","high-protein","vegetarian","gluten-free"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"zucchini","q":1},{"f":"parmesan","q":40},{"f":"onion","q":0.3},{"f":"garlic","q":0.1},{"f":"basil","q":0.3},{"f":"cherry_tomatoes","q":100},{"f":"olive_oil","q":20},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 190C and slice the zucchini into thin coins, salting them lightly in a colander for 5 minutes to shed excess water.","Warm the olive oil in an ovenproof skillet over medium heat and cook the onion until soft, then add the blotted zucchini and garlic and saute until the coins turn golden at the edges, 5 to 6 minutes.","Whisk the eggs with most of the parmesan, salt, and pepper until uniformly yellow, then pour them over the vegetables and drop in the halved cherry tomatoes.","Cook undisturbed on the stove for 3 minutes, until the edges set and pull slightly from the pan while the center still wobbles.","Slide the skillet into the oven for 8 to 10 minutes, until the top is puffed and just set — a knife in the center should come out clean but glossy.","Shower with the remaining parmesan and torn basil, rest 5 minutes, and cut into wedges."],"tip":"Pull it while the center still trembles a little; a frittata keeps cooking in the pan and rubbery eggs have no appeal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_souvlaki_salad_plate', '{"id":"pork_souvlaki_salad_plate","name":"Pork Souvlaki-Style Plate with Cucumber Yogurt","emoji":"🍢","cuisine":"Mediterranean","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"lemon","q":1},{"f":"oregano","q":4},{"f":"garlic","q":0.3},{"f":"olive_oil","q":30},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":1},{"f":"romaine","q":0.5},{"f":"tomato","q":1},{"f":"onion","q":0.3},{"f":"olives","q":30},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Cut the pork loin into 3-centimeter cubes and toss with half the olive oil, the juice of half the lemon, two minced garlic cloves, oregano, salt, and pepper; let it marinate 15 minutes while you prep the rest.","Grate half the cucumber, squeeze it firmly dry, and stir it into the yogurt with the last garlic clove, a squeeze of lemon, and a pinch of salt.","Heat a skillet or grill pan over high until properly hot, then sear the pork in a single layer for 2 to 3 minutes per side, until charred at the corners and just barely blushing inside.","Rest the pork for 3 minutes so the juices settle instead of flooding the plate.","Slice the remaining cucumber, chop the romaine and tomato, and shave the onion thin, then arrange it all with the olives, pile the pork on top, and drop a thick spoonful of the yogurt sauce alongside with the rest of the oil drizzled over."],"tip":"Crowd the pan and you steam the pork — sear in two batches if your skillet is small, the char is non-negotiable."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_cottage_cheese_plate', '{"id":"mediterranean_cottage_cheese_plate","name":"Mediterranean Cottage Cheese Lunch Plate","emoji":"🧀","cuisine":"Mediterranean","meal":["lunch"],"diets":["low-carb","high-protein","vegetarian","gluten-free"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"cottage_cheese","q":400},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":200},{"f":"olives","q":50},{"f":"roasted_red_peppers","q":100},{"f":"avocado","q":1},{"f":"walnuts","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"black_pepper","q":2}],"steps":["Divide the cottage cheese between two shallow bowls and swoosh it into a wide bed with the back of a spoon, the way you would hummus.","Halve the cherry tomatoes, slice the cucumber into half-moons, and cut the roasted red peppers into ribbons, arranging everything in generous piles over the cheese.","Fan slices of avocado alongside and scatter the olives and roughly crushed walnuts across the top for briny crunch.","Whisk the olive oil with lemon juice, oregano, and black pepper into a quick dressing and spoon it over the whole plate so it pools into the cottage cheese.","Finish with torn basil and one more twist of pepper, and eat with a spoon that catches a bit of everything."],"tip":"Toast the walnuts in a dry pan for two minutes first — raw walnuts whisper, toasted ones sing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_chicken_cucumber_salad', '{"id":"tandoori_chicken_cucumber_salad","name":"Tandoori-Spiced Chicken with Cucumber Raita Salad","emoji":"🍗","cuisine":"Indian","meal":["lunch"],"diets":["low-carb","high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"greek_yogurt","q":150},{"f":"garam_masala","q":5},{"f":"turmeric","q":2},{"f":"cumin","q":3},{"f":"paprika","q":3},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"lime","q":1},{"f":"cucumber","q":1},{"f":"spinach","q":100},{"f":"onion","q":0.3},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Stir two-thirds of the yogurt with the garam masala, turmeric, cumin, paprika, grated ginger, minced garlic, half the lime juice, and salt, then coat the chicken thighs and let them marinate at least 20 minutes — the yogurt tenderizes as the spices soak in.","Heat the olive oil in a heavy skillet over medium-high and lay the chicken in, letting the marinade char into a burnished crust, 5 to 6 minutes per side, until the juices run clear.","Rest the chicken 5 minutes, then slice it thickly against the grain.","Meanwhile, grate half the cucumber, squeeze it dry, and mix it into the remaining yogurt with chopped cilantro and a pinch of salt for a quick raita.","Toss the spinach, sliced remaining cucumber, and shaved onion with the rest of the lime juice, plate the salad, top with the sliced chicken, and spoon the raita over the smoky edges."],"tip":"Let the marinade char in spots and resist the urge to scrape — those blackened yogurt edges are the closest a skillet gets to a tandoor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_edamame_crunch_salad', '{"id":"sesame_edamame_crunch_salad","name":"Sesame Edamame Crunch Salad","emoji":"🥢","cuisine":"Asian","meal":["lunch"],"diets":["low-carb","vegan","vegetarian","dairy-free","gluten-free"],"allergens":["soy","nuts","sesame"],"time":20,"servings":2,"ing":[{"f":"edamame_frozen","q":300},{"f":"cabbage","q":0.3},{"f":"cucumber","q":1},{"f":"bell_pepper","q":1},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.3},{"f":"avocado","q":1},{"f":"almonds","q":40},{"f":"sesame_oil","q":20},{"f":"olive_oil","q":10},{"f":"lime","q":1},{"f":"ginger","q":10},{"f":"salt","q":4}],"steps":["Simmer the edamame in well-salted water for 4 minutes, then drain and rinse under cold water until completely cool.","Shave the cabbage into fine ribbons, seed and slice the bell pepper into matchsticks, and halve the cucumber lengthwise before cutting it into thin half-moons.","Whisk the sesame oil, olive oil, lime juice, grated ginger, and a solid pinch of salt into a dressing that tastes bright and a touch too sharp on its own.","Toss the vegetables and edamame with the dressing and let the salad sit 5 minutes so the cabbage relaxes and drinks it in.","Fold in the sliced scallions and cilantro, top with diced avocado and toasted sliced almonds, and serve cold while everything still snaps."],"tip":"Dress it five minutes early and not fifty — cabbage that marinates through lunch prep is perfect, cabbage that marinates overnight is coleslaw''s sad cousin."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('loaded_cauliflower_bacon_soup', '{"id":"loaded_cauliflower_bacon_soup","name":"Loaded Cauliflower Soup with Bacon and Cheddar","emoji":"🥣","cuisine":"American","meal":["lunch"],"diets":["low-carb","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"cauliflower","q":1},{"f":"bacon","q":150},{"f":"broth","q":1000},{"f":"onion","q":1},{"f":"celery","q":60},{"f":"garlic","q":0.3},{"f":"butter","q":15},{"f":"milk","q":100},{"f":"cheddar","q":120},{"f":"sour_cream","q":100},{"f":"scallions","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":3}],"steps":["Chop the bacon and cook it in a soup pot over medium heat until the fat renders and the pieces turn shatteringly crisp, about 8 minutes, then lift them out and leave the drippings behind.","Add the butter, diced onion, and celery to the pot and sweat for 5 minutes until soft and fragrant, stirring in the garlic for the final minute.","Break the cauliflower into small florets, add them with the broth, salt, and pepper, and simmer for 15 minutes until a fork slides through the stems with no resistance.","Blend the soup until silky — an immersion blender right in the pot is easiest — then stir in the milk and most of the cheddar off the heat so the cheese melts smoothly instead of breaking.","Taste and season boldly with black pepper, then ladle into bowls and finish each with a swirl of sour cream, the crispy bacon, the reserved cheddar, and sliced scallions."],"tip":"Add the cheese off the boil or it will split — patience here is the difference between velvet and grit."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_sheet_pan_chicken_olives', '{"id":"greek_sheet_pan_chicken_olives","name":"Sheet-pan Greek chicken with artichokes & olives","emoji":"🍗","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"artichoke_hearts","q":240},{"f":"olives","q":60},{"f":"cherry_tomatoes","q":150},{"f":"lemon","q":1},{"f":"garlic","q":0.6},{"f":"oregano","q":4},{"f":"olive_oil","q":30},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 220C and pat the chicken thighs bone-dry so they brown instead of steam.","Toss the chicken with half the oil, the minced garlic, oregano, salt and pepper, then spread it skin-side up on a sheet pan with the drained artichoke hearts.","Roast 20 minutes, then scatter on the olives and cherry tomatoes, squeeze over half the lemon and drizzle with the remaining oil.","Roast 12-15 minutes more until the chicken edges are burnished and the tomatoes have slumped and split.","Rest 5 minutes on the pan, then finish with the last lemon squeeze and spoon the salty pan juices over everything."],"tip":"Crowd the pan and you get poached chicken — leave breathing room and the artichoke edges crisp like chips."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_oregano_skewers', '{"id":"shrimp_oregano_skewers","name":"Oregano shrimp skewers with cucumber-feta salad","emoji":"🍤","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"garlic","q":0.4},{"f":"oregano","q":4},{"f":"cucumber","q":1},{"f":"feta","q":80},{"f":"olives","q":40},{"f":"cherry_tomatoes","q":150},{"f":"salt","q":2}],"steps":["Toss the shrimp with half the oil, the grated garlic, oregano, salt and the zest of the lemon; let them sit 10 minutes while you make the salad.","Chop the cucumber into chunky half-moons, halve the cherry tomatoes and toss with the olives, crumbled feta and remaining oil.","Thread the shrimp onto skewers and get a grill pan smoking hot over high heat.","Sear the skewers 2 minutes per side until the shrimp curl into loose commas with charred edges — pull them the moment they turn opaque.","Squeeze the lemon over the hot skewers so it sizzles, and serve them right on top of the cold salad."],"tip":"A shrimp curled into a tight O is overcooked; you want a relaxed C that still snaps."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_roasted_pepper_feta', '{"id":"salmon_roasted_pepper_feta","name":"Roast salmon on roasted red peppers with feta crumble","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":30,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"roasted_red_peppers","q":200},{"f":"feta","q":60},{"f":"olives","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and slice the roasted red peppers into wide ribbons.","Toss the peppers with the sliced garlic, half the oil and the oregano, then spread them in a baking dish as a bed.","Set the salmon fillets on top, rub with the remaining oil and plenty of black pepper, and roast 12-14 minutes until the fish flakes at the thick end but still looks glossy inside.","Scatter the crumbled feta and halved olives over the hot fish so the cheese softens without melting.","Shower with chopped parsley and a hard squeeze of lemon, and serve straight from the dish with the sweet pepper juices."],"tip":"The peppers underneath catch every drop of salmon fat — do not leave them behind in the dish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_feta_zucchini_boats', '{"id":"turkey_feta_zucchini_boats","name":"Turkey & feta stuffed zucchini boats","emoji":"🥒","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"zucchini","q":2},{"f":"crushed_tomatoes","q":250},{"f":"feta","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"oregano","q":4},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise and scoop out the seedy cores with a spoon, leaving sturdy quarter-inch walls.","Brown the turkey in the oil over medium-high heat, breaking it into rubble, until it sizzles rather than steams, about 6 minutes.","Add the diced onion, garlic and oregano and cook 3 minutes, then stir in the crushed tomatoes and the chopped zucchini cores; simmer until thick enough to mound on a spoon.","Pile the filling into the zucchini shells, set them in a baking dish and top with crumbled feta.","Bake 20 minutes until the zucchini is tender when pierced and the feta has golden freckles, then rest 5 minutes before serving."],"tip":"Scoop like a surgeon, not a gravedigger — thin walls collapse under the filling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_keftedes_olive_tomato', '{"id":"beef_keftedes_olive_tomato","name":"Beef keftedes simmered in olive-tomato sauce","emoji":"🧆","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"parsley","q":0.4},{"f":"cumin","q":2},{"f":"oregano","q":3},{"f":"crushed_tomatoes","q":400},{"f":"olives","q":50},{"f":"olive_oil","q":20},{"f":"salt","q":3}],"steps":["Grate the onion half straight into the beef, then add the egg, most of the chopped parsley, half the garlic, the cumin, half the oregano and the salt.","Knead briefly and roll into 12 walnut-sized meatballs; wet hands keep the mix from clinging to you.","Brown the keftedes in the oil over medium-high heat until deeply crusted on two sides, about 5 minutes — they will not be cooked through yet.","Push them aside, bloom the remaining garlic and oregano in the pan fat for 30 seconds, then pour in the crushed tomatoes and olives.","Simmer uncovered 12-15 minutes, turning the meatballs once, until the sauce darkens and clings; finish with the reserved parsley."],"tip":"Grated onion is the secret keeper of juicy meatballs — diced onion just pokes holes in them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_medallions_peppers_artichokes', '{"id":"pork_medallions_peppers_artichokes","name":"Pork medallions with balsamic peppers & artichokes","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"roasted_red_peppers","q":150},{"f":"artichoke_hearts","q":200},{"f":"balsamic_vinegar","q":30},{"f":"broth","q":120},{"f":"olive_oil","q":25},{"f":"garlic","q":0.4},{"f":"oregano","q":3},{"f":"black_pepper","q":2},{"f":"salt","q":3}],"steps":["Slice the pork loin into medallions about an inch thick, season with salt, pepper and oregano, and let them lose their fridge chill for 10 minutes.","Sear in the oil over medium-high heat 3 minutes per side until mahogany-crusted, then move to a plate to rest.","In the same pan, sizzle the sliced garlic, drained artichokes and pepper strips until the artichoke edges catch some color, about 4 minutes.","Pour in the balsamic and broth, scraping up the browned bits, and let it bubble down to a glossy glaze that coats the vegetables.","Return the medallions and any resting juices for a final minute, turning them in the glaze until lacquered and just blushing at the center."],"tip":"Pork loin has zero forgiveness — pull it while faintly pink or eat it as a cautionary tale."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_spinach_feta_frittata', '{"id":"greek_spinach_feta_frittata","name":"Spinach, feta & roasted pepper frittata","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"spinach","q":150},{"f":"feta","q":90},{"f":"roasted_red_peppers","q":100},{"f":"scallions","q":0.5},{"f":"olive_oil","q":20},{"f":"oregano","q":2},{"f":"black_pepper","q":2}],"steps":["Heat the broiler and set an oven-safe skillet over medium heat with the oil.","Wilt the spinach with the sliced scallions until the pan is nearly dry — watery spinach means a weepy frittata.","Whisk the eggs with the oregano and black pepper, pour them over the greens, and scatter on the chopped roasted peppers and crumbled feta.","Cook undisturbed 4-5 minutes until the edges are set and puffing but the center still shimmies like custard.","Slide under the broiler 2-3 minutes until the top is golden-blistered and just set, then rest 3 minutes before cutting into fat wedges."],"tip":"The feta stays in proud salty pockets if you crumble it big — pea-sized bits vanish into the eggs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_artichoke_romaine_boats', '{"id":"tuna_artichoke_romaine_boats","name":"Tuna & artichoke romaine boats","emoji":"🥬","cuisine":"Mediterranean","meal":["lunch"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":284},{"f":"artichoke_hearts","q":150},{"f":"greek_yogurt","q":100},{"f":"olives","q":40},{"f":"roasted_red_peppers","q":80},{"f":"romaine","q":1},{"f":"lemon","q":0.5},{"f":"olive_oil","q":20},{"f":"parsley","q":0.3},{"f":"black_pepper","q":2}],"steps":["Drain the tuna hard and flake it into a bowl with the yogurt, olive oil, lemon juice and a generous grind of pepper.","Chop the artichoke hearts, olives and roasted peppers into confetti and fold them through until the salad is streaked red and green.","Taste and sharpen with more lemon — canned tuna drinks acid like it has been at sea for months.","Separate the romaine into whole crisp leaves, keeping the sturdy inner ones for boats.","Pile the salad into the leaves, shower with parsley and eat with your hands while the lettuce still cracks."],"tip":"Assemble at the table, not in the fridge — loaded romaine goes limp faster than a Monday handshake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_chicken_cauliflower_soup', '{"id":"lemon_chicken_cauliflower_soup","name":"Lemony chicken & cauliflower rice soup","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","low-carb","high-protein"],"allergens":["eggs"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"cauliflower","q":1},{"f":"broth","q":1500},{"f":"eggs","q":2},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"celery","q":100},{"f":"garlic","q":0.6},{"f":"lemon","q":1},{"f":"olive_oil","q":30},{"f":"oregano","q":3},{"f":"parsley","q":0.4},{"f":"salt","q":4}],"steps":["Sweat the diced onion, carrot and celery in the oil over medium heat until soft and sweet-smelling, about 6 minutes, then stir in the garlic and oregano.","Add the broth and whole chicken breasts, bring to a bare simmer, and poach gently 15 minutes — bubbles should whisper, not roll.","Pulse the cauliflower florets in a processor to rice-sized bits, lift out the chicken, and simmer the cauliflower rice in the pot 6-8 minutes until tender.","Shred the chicken with two forks and return it to the pot with the salt.","Whisk the eggs with the lemon juice, temper with a ladle of hot broth while whisking, then stir the mixture back in off the heat until the soup turns silky and pale gold; finish with parsley."],"tip":"Boil after adding the egg-lemon and you get chicken soup with scrambled regrets — keep it off the heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('savory_cottage_cheese_mezze_bowl', '{"id":"savory_cottage_cheese_mezze_bowl","name":"Savory cottage cheese mezze bowl","emoji":"🥣","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"cottage_cheese","q":450},{"f":"cucumber","q":1},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":50},{"f":"roasted_red_peppers","q":80},{"f":"walnuts","q":40},{"f":"olive_oil","q":20},{"f":"oregano","q":2},{"f":"black_pepper","q":2}],"steps":["Divide the cottage cheese between two shallow bowls and swirl it out to the edges like a savory canvas.","Dice the cucumber small, halve the cherry tomatoes and slice the olives and roasted peppers into slivers.","Arrange the vegetables in bright wedges over the cheese rather than stirring them in, so every spoonful is different.","Toast the walnuts in a dry pan 2-3 minutes until fragrant and scatter them over for crunch.","Finish with a ribbon of olive oil, a pinch of oregano crushed between your fingers and an aggressive grind of black pepper."],"tip":"Cold cottage cheese plus warm toasted walnuts is the temperature contrast breakfast has been missing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_baked_tofu_peppers', '{"id":"mediterranean_baked_tofu_peppers","name":"Baked oregano tofu with peppers, olives & artichokes","emoji":"🫒","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["soy"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"roasted_red_peppers","q":150},{"f":"artichoke_hearts","q":150},{"f":"olives","q":50},{"f":"cherry_tomatoes","q":150},{"f":"olive_oil","q":30},{"f":"balsamic_vinegar","q":15},{"f":"garlic","q":0.4},{"f":"oregano","q":4},{"f":"paprika","q":3},{"f":"basil","q":0.3},{"f":"salt","q":3}],"steps":["Heat the oven to 220C and press the tofu between towels under a heavy pan for 10 minutes so it can actually absorb flavor.","Tear the tofu into rough bite-sized chunks — ragged edges crisp better than clean cubes — and toss with half the oil, the paprika, oregano and salt.","Roast the tofu on one side of a sheet pan for 15 minutes until the edges turn golden and leathery.","Toss the pepper strips, artichokes, olives and cherry tomatoes with the remaining oil, add them to the pan and roast 12 minutes more until the tomatoes blister and burst.","Slide everything into a bowl, splash with the balsamic and the minced raw garlic while hot, and finish with torn basil."],"tip":"Torn tofu is craggy and crisp; cubed tofu is a bounce house — tear it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_feta_stacks', '{"id":"eggplant_feta_stacks","name":"Grilled eggplant & feta stacks with balsamic","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"tomato","q":2},{"f":"feta","q":120},{"f":"olive_oil","q":40},{"f":"balsamic_vinegar","q":20},{"f":"garlic","q":0.3},{"f":"basil","q":0.4},{"f":"oregano","q":2},{"f":"salt","q":3}],"steps":["Slice the eggplant into thick rounds, salt both sides and let them sweat 10 minutes, then blot dry — this is the difference between creamy and spongy.","Brush the rounds with most of the oil and grill in a screaming-hot pan 4 minutes per side until soft-centered with dark char stripes.","Slice the tomatoes thick and mash the feta with the remaining oil, minced garlic and oregano into a rough spread.","Build stacks on plates: eggplant, a smear of feta, tomato, and repeat, ending with a crown of feta.","Drizzle the balsamic over and around, scatter with torn basil, and serve while the eggplant is still steaming under its cheese."],"tip":"Undercooked eggplant is a punishment; cook it until it surrenders completely."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('horiatiki_village_salad', '{"id":"horiatiki_village_salad","name":"Village-style Greek salad with a feta slab","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":15,"servings":2,"ing":[{"f":"tomato","q":3},{"f":"cucumber","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olives","q":80},{"f":"feta","q":160},{"f":"olive_oil","q":45},{"f":"balsamic_vinegar","q":15},{"f":"oregano","q":3},{"f":"salt","q":2}],"steps":["Cut the tomatoes into fat irregular wedges over the serving bowl so none of the juice escapes.","Add the cucumber in thick half-moons, the pepper in rings and the onion in whisper-thin slices, then season with salt and toss gently.","Scatter the olives over and let the salad sit 5 minutes — the salt pulls out tomato juice that becomes half the dressing.","Lay the feta on top in two unapologetic slabs rather than crumbling it.","Flood with the olive oil, add a small splash of balsamic, and dust the feta heavily with oregano; serve with spoons for the pink juice at the bottom."],"tip":"The slab is non-negotiable — crumbled feta is a garnish, a slab is a commitment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('seared_chicken_broccoli_stir_fry', '{"id":"seared_chicken_broccoli_stir_fry","name":"Seared Chicken & Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"broccoli","q":400},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":10}],"steps":["Slice the chicken breast against the grain into thin strips and pat them bone-dry so they sear instead of steam.","Heat the olive oil in your largest skillet over high heat until it shimmers, then lay the chicken in a single layer and leave it alone for 2 minutes until deeply golden on one side.","Toss the chicken for another 2 minutes until just cooked through, then scrape it onto a plate.","Add the broccoli florets to the hot pan with a splash of water and cover for 3 minutes until they turn brilliant green and just barely tender.","Return the chicken with the minced garlic and soy sauce, tossing for 60 seconds until everything is glossy and the garlic smells toasty.","Kill the heat, drizzle with sesame oil, and serve while the broccoli still has some bite."],"tip":"A crowded pan boils, an uncrowded pan browns — sear the chicken in two batches if your skillet is small."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_cashew_lettuce_wraps', '{"id":"turkey_cashew_lettuce_wraps","name":"Crispy Turkey & Cashew Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame","nuts"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":500},{"f":"mushrooms","q":150},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cashews","q":30},{"f":"romaine","q":1},{"f":"olive_oil","q":10},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Finely chop the mushrooms and onion so they nearly disappear into the filling.","Heat the olive oil in a wide skillet over medium-high and brown the turkey for 5 to 6 minutes, breaking it into small crumbles and letting it crisp at the edges before you stir.","Add the onion, mushrooms, and minced garlic and cook 4 minutes more, until the mushroom liquid has evaporated and the pan sounds like it is sizzling again rather than simmering.","Stir in the soy sauce and sesame oil and toss for 1 minute until the filling is glossy and deeply savory.","Off the heat, fold in roughly chopped cashews for crunch.","Separate the romaine into whole leaves, pile the hot filling into the crisp cups, and eat immediately with plenty of napkins."],"tip":"Chill the romaine leaves in ice water for five minutes first — cold, snappy lettuce against hot filling is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_shrimp_zucchini_stir_fry', '{"id":"garlic_shrimp_zucchini_stir_fry","name":"Garlic Shrimp & Zucchini Stir-Fry","emoji":"🍤","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["shellfish","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"zucchini","q":2},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Pat the shrimp very dry and cut the zucchini into thick half-moons and the bell pepper into wide strips.","Heat half the olive oil in a large skillet over high heat and sear the shrimp for about 90 seconds per side, just until they curl into loose commas and turn pink, then remove them.","Add the remaining oil and stir-fry the zucchini and pepper for 3 to 4 minutes until blistered in spots but still firm at the center.","Push the vegetables aside, drop the minced garlic into the empty spot, and stir for 30 seconds until fragrant but not browned.","Return the shrimp with the soy sauce, toss everything for a final minute, then finish with sesame oil off the heat and serve hot."],"tip":"Shrimp go from succulent to rubber bands in about a minute — pull them the moment they curl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_pepper_onion_stir_fry', '{"id":"beef_pepper_onion_stir_fry","name":"Sizzling Beef, Pepper & Onion Stir-Fry","emoji":"🫑","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":500},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Set a large skillet over high heat until a drop of water skitters across it, then add the ground beef in one flat layer with no oil needed.","Let it sear untouched for 3 minutes to build a browned crust, then break it up and cook 3 minutes more, spooning off all but a tablespoon of the rendered fat.","Add the sliced onion and bell peppers and stir-fry 4 minutes, until the onion turns translucent at the edges and the peppers pick up charred spots.","Stir in the minced garlic and soy sauce and toss for 1 minute until the pan juices reduce to a glaze that clings to the beef.","Drizzle with sesame oil, give one last toss, and serve straight from the screaming-hot pan."],"tip":"That beef fat you spooned off is free flavor — save a spoonful for tomorrow''s eggs."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_edamame_stir_fry', '{"id":"crispy_tofu_edamame_stir_fry","name":"Crispy Tofu & Edamame Stir-Fry","emoji":"🌱","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","low-carb"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"broccoli","q":300},{"f":"mushrooms","q":200},{"f":"edamame_frozen","q":150},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then cut it into 2-centimeter cubes.","Heat the olive oil in a wide nonstick pan over medium-high and fry the tofu for 8 minutes, turning only when each face releases easily and is deep golden brown.","Remove the tofu and stir-fry the broccoli and mushrooms in the same pan for 4 to 5 minutes, until the mushrooms brown and the broccoli is crisp-tender.","Add the edamame and minced garlic and cook 2 minutes more, until the garlic is fragrant and the edamame is heated through.","Return the tofu with the soy sauce and toss until every cube is lacquered and glossy.","Finish with sesame oil off the heat and serve in warm bowls."],"tip":"Patience beats fiddling — tofu tells you it''s ready to flip by letting go of the pan on its own."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_mushroom_lettuce_cups', '{"id":"chicken_mushroom_lettuce_cups","name":"Chicken & Mushroom Lettuce Cups","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"mushrooms","q":200},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"romaine","q":1},{"f":"olive_oil","q":15},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10}],"steps":["Dice the chicken breast into small, even cubes about the size of a fingernail so they cook fast and tuck neatly into lettuce.","Heat the olive oil in a skillet over medium-high and cook the chicken 4 to 5 minutes, stirring occasionally, until the pieces are golden at the edges and opaque throughout.","Add the finely chopped mushrooms and onion and cook 5 minutes more, until their moisture cooks off and the mixture starts to sizzle and brown again.","Stir in the garlic and soy sauce and simmer 1 minute, scraping up the browned bits so the sauce turns savory and dark.","Drizzle with sesame oil, then spoon the filling into cold, crisp romaine leaves and serve stacked on a platter.","Fold each leaf around its filling like a small taco and eat while the lettuce is still icy-crisp against the hot chicken."],"tip":"Dice everything the same small size — a lettuce cup is not the place for a chunk of chicken staging an escape."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_glazed_salmon_broccoli', '{"id":"sesame_glazed_salmon_broccoli","name":"Sesame-Glazed Salmon with Charred Broccoli","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["fish","gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"broccoli","q":350},{"f":"garlic","q":0.2},{"f":"olive_oil","q":10},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Pat the salmon fillets dry and let them sit at room temperature while you cut the broccoli into flat-sided florets.","Heat the olive oil in a heavy skillet over medium-high and sear the broccoli cut-side down for 4 minutes without moving it, until deeply charred, then add a splash of water, cover for 2 minutes, and set aside.","Wipe the pan, return it to medium-high, and lay the salmon in skin-side up; sear 4 minutes until a golden crust forms and the sides turn opaque halfway up.","Flip gently, add the soy sauce, sesame oil, and minced garlic, and spoon the bubbling glaze over the fish for 2 to 3 minutes until it flakes at the thickest point.","Plate the salmon over the charred broccoli and pour every drop of pan glaze on top."],"tip":"If the salmon sticks when you try to flip it, it''s telling you to wait thirty more seconds — listen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_drop_tofu_soup', '{"id":"egg_drop_tofu_soup","name":"Silky Egg Drop Soup with Tofu","emoji":"🍲","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","low-carb"],"allergens":["eggs","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"broth","q":1000},{"f":"eggs","q":4},{"f":"tofu","q":300},{"f":"mushrooms","q":150},{"f":"spinach","q":100},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":15}],"steps":["Bring the broth to a gentle simmer in a soup pot with the sliced mushrooms and smashed garlic, and let it burble for 5 minutes so the mushrooms perfume the liquid.","Add the tofu in small cubes along with the soy sauce and simmer 3 minutes more, until the tofu is heated through and bobbing.","Beat the eggs thoroughly in a spouted cup, then reduce the soup to the barest simmer — bubbles just kissing the surface.","Pour the eggs in a thin, steady stream while stirring the soup slowly in one direction, and watch them bloom into soft golden ribbons.","Stir in the spinach until it wilts, about 30 seconds, then finish each bowl with a generous drizzle of sesame oil."],"tip":"The slower you pour and the gentler the simmer, the silkier the ribbons — a rolling boil turns them to confetti."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_style_beef_lettuce_wraps', '{"id":"korean_style_beef_lettuce_wraps","name":"Korean-Style Beef Lettuce Wraps","emoji":"🥩","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":450},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Slice the cucumber into paper-thin coins and toss with a teaspoon of the soy sauce; let it sit so it turns into a quick crunchy relish while you cook.","Brown the beef in a dry skillet over high heat for 5 to 6 minutes, pressing it flat first for a proper crust, then breaking it into crumbles.","Add the diced onion and minced garlic and cook 3 minutes, until the onion softens and the garlic smells sweet rather than sharp.","Pour in the remaining soy sauce and half the sesame oil and toss until the beef is glossy and the pan is nearly dry.","Spoon the beef into whole romaine leaves, top each with cucumber relish and a few drops of the remaining sesame oil, and serve while the contrast of hot and cold is at its best."],"tip":"Build wraps at the table, not in the kitchen — pre-filled lettuce goes limp faster than your dinner guests arrive."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garlic_egg_zucchini_stir_fry', '{"id":"garlic_egg_zucchini_stir_fry","name":"Golden Egg & Zucchini Stir-Fry","emoji":"🍳","cuisine":"Asian","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free","low-carb"],"allergens":["eggs","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"zucchini","q":2},{"f":"mushrooms","q":150},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":10}],"steps":["Beat the eggs until completely uniform and cut the zucchini into chunky batons that will hold their shape.","Heat half the olive oil in a wok or large skillet over high heat, pour in the eggs, and let them puff and set for 30 seconds before folding into large soft curds; scoop them out while still slightly glossy.","Add the remaining oil and stir-fry the zucchini and mushrooms for 4 minutes, until browned at the edges but still juicy inside.","Toss in the minced garlic for 30 seconds, then return the eggs with the soy sauce and fold gently so the curds stay pillowy.","Finish with sesame oil off the heat and serve immediately, while the eggs are still trembling."],"tip":"Undercook the eggs on their first pass — they take a second lap around the pan and nobody likes an egg that''s been to the gym twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tuna_edamame_salad', '{"id":"sesame_tuna_edamame_salad","name":"Sesame Tuna & Edamame Crunch Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["fish","soy","gluten","sesame"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"edamame_frozen","q":200},{"f":"avocado","q":1},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":20}],"steps":["Boil the edamame in well-salted water for 4 minutes, then drain and rinse under cold water until fully cooled.","Whisk the sesame oil and soy sauce in the bottom of a large bowl to make a glossy two-ingredient dressing.","Chop the romaine into wide ribbons, slice the cucumber into thin half-moons, and cube the avocado.","Drain the tuna thoroughly and flake it into big, satisfying chunks rather than shreds.","Add everything to the bowl and toss gently but completely, so each ribbon of lettuce carries dressing and every bite gets tuna, edamame, and a soft hit of avocado.","Serve within minutes, while the romaine still crackles."],"tip":"Drain the tuna like you mean it — a watery salad forgives nothing."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_chicken_mushroom_soup', '{"id":"gingery_chicken_mushroom_soup","name":"Restorative Chicken & Mushroom Soup","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"chicken_breast","q":700},{"f":"broth","q":1500},{"f":"mushrooms","q":300},{"f":"carrots","q":200},{"f":"spinach","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Bring the broth to a simmer in a large pot with the halved onion, smashed garlic cloves, and olive oil, and let it steep for 10 minutes to build a fragrant base.","Slide in the whole chicken breasts and poach at a bare, lazy simmer for 12 to 15 minutes, until just cooked through, then lift them out to rest.","Fish out the onion halves, then add the sliced mushrooms and carrot coins and simmer 8 minutes, until the carrots are tender but not mushy.","Shred the rested chicken with two forks and return it to the pot with the soy sauce.","Stir in the spinach until it collapses into silky ribbons, about 1 minute, then ladle into deep bowls and crown each with a swirl of sesame oil."],"tip":"Poach the chicken at a whisper, not a boil — furious bubbles are how tender breasts become packing material."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_egg_foo_young_omelets', '{"id":"shrimp_egg_foo_young_omelets","name":"Shrimp Egg Foo Young Omelets","emoji":"🦐","cuisine":"Asian","meal":["breakfast","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["eggs","shellfish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"shrimp","q":300},{"f":"mushrooms","q":150},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"broth","q":200},{"f":"olive_oil","q":20},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":10}],"steps":["Chop the shrimp into rough chunks and saute them with the sliced mushrooms and onion in half the olive oil over medium-high heat for 3 minutes, until the shrimp are barely pink; cool slightly.","Beat the eggs well, then fold in the shrimp mixture so every ladleful carries plenty of filling.","Simmer the broth with the soy sauce and minced garlic in a small pan for 3 to 4 minutes until slightly reduced, then whisk in the sesame oil to make a savory drizzling sauce.","Heat the remaining oil in a skillet over medium-high and ladle in half the egg mixture, cooking 2 minutes per side until the omelet is puffed, golden brown, and set at the center.","Repeat with the second omelet, keeping the first warm, then stack both on plates and pour the hot garlicky sauce over the top so it seeps into every craggy edge."],"tip":"A slightly-too-hot pan is your friend here — those lacy browned edges are the difference between egg foo young and a sad frittata."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_broccoli_cheddar_bake_3', '{"id":"chicken_broccoli_cheddar_bake_3","name":"Chicken Broccoli Cheddar Bake","emoji":"🥦","cuisine":"American","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"broccoli","q":400},{"f":"cheddar","q":80},{"f":"sour_cream","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 200C and cut the chicken into bite-size chunks, seasoning them generously with salt and pepper.","Sear the chicken in olive oil over medium-high heat for 4 minutes until the edges turn golden but the centers stay slightly underdone.","Blanch the broccoli florets in boiling salted water for 2 minutes, then drain them well so the casserole does not turn watery.","Stir the sour cream, minced garlic, and half the cheddar together, then fold in the chicken and broccoli until everything glistens.","Scrape the mixture into a baking dish, blanket it with the remaining cheddar, and bake for 20 minutes until the top bubbles and browns at the edges.","Rest the bake for 5 minutes so the sauce thickens from soupy to spoonable before serving."],"tip":"Drain that broccoli like it owes you money — a wet floret is the silent assassin of every casserole."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_beef_lasagna_bake', '{"id":"zucchini_beef_lasagna_bake","name":"Zucchini Beef Lasagna Bake","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":65,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"zucchini","q":2},{"f":"ricotta","q":150},{"f":"mozzarella","q":80},{"f":"parmesan","q":30},{"f":"tomato","q":3},{"f":"eggs","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Slice the zucchini lengthwise into thin planks, salt them, and let them weep on paper towels for 15 minutes while the oven heats to 190C.","Brown the beef with garlic in olive oil over high heat until deeply crusted, about 6 minutes, then add the chopped tomatoes and simmer until the sauce turns thick and jammy.","Whisk the ricotta with the egg and a pinch of salt until it loosens into a spreadable cream.","Layer the dish like lasagna: meat sauce, zucchini planks, ricotta, repeating until everything is used, finishing with mozzarella and parmesan on top.","Bake uncovered for 30 minutes until the cheese blisters bronze and the edges bubble like lava.","Rest for 10 full minutes so the layers set and slice cleanly instead of sliding apart."],"tip":"Salting the zucchini is non-negotiable unless you enjoy lasagna soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_spinach_feta_frittata', '{"id":"salmon_spinach_feta_frittata","name":"Salmon Spinach Feta Frittata","emoji":"🐟","cuisine":"Mediterranean","meal":["breakfast","lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"salmon","q":250},{"f":"eggs","q":6},{"f":"spinach","q":150},{"f":"feta","q":60},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 190C and warm the olive oil in an ovenproof skillet over medium heat.","Soften the sliced onion for 4 minutes until translucent, then wilt the spinach in handfuls until it collapses and its liquid cooks off.","Nestle in the salmon, broken into rough chunks, and let it turn opaque at the edges for 2 minutes.","Whisk the eggs with salt and pepper, pour them over everything, and scatter the feta so it studs the surface like white pebbles.","Cook undisturbed for 3 minutes until the edges set, then transfer to the oven for 12 minutes until the center is puffed and just barely wobbles.","Slide the frittata onto a board and cut into fat wedges while it is still steaming."],"tip":"Pull it when the middle still jiggles slightly — carryover heat finishes the job while overbaking finishes your reputation."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_cauliflower_melt_casserole', '{"id":"tuna_cauliflower_melt_casserole","name":"Tuna Cauliflower Melt Casserole","emoji":"🧀","cuisine":"American","meal":["lunch","dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":45,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"cauliflower","q":0.8},{"f":"cheddar","q":90},{"f":"sour_cream","q":120},{"f":"onion","q":0.5},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C and cut the cauliflower into small, even florets so they cook through by the time the top browns.","Steam the florets for 5 minutes until just fork-tender, then drain and pat them dry with real intent.","Saute the diced onion in olive oil until golden at the edges, about 5 minutes, then stir in the drained tuna and warm it through.","Fold the cauliflower, sour cream, and half the cheddar into the tuna mixture, seasoning boldly with salt and plenty of black pepper.","Spread everything into a baking dish, cap it with the remaining cheddar, and bake for 18 minutes until the cheese bubbles and spots of mahogany appear.","Let it stand 5 minutes so the sauce clings to the florets instead of the spoon."],"tip":"Squeeze the tuna dry first — the can juice is for cats, not casseroles."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_zucchini_parmesan_gratin', '{"id":"shrimp_zucchini_parmesan_gratin","name":"Shrimp Zucchini Parmesan Gratin","emoji":"🦐","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"zucchini","q":2},{"f":"parmesan","q":50},{"f":"butter","q":30},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 220C and slice the zucchini into thin coins, tossing them with olive oil, salt, and pepper.","Shingle the zucchini across a gratin dish and roast for 10 minutes to drive off moisture and concentrate their sweetness.","Melt the butter with minced garlic in a small pan until it foams and smells nutty, about 2 minutes, watching it does not brown past golden.","Toss the shrimp in the garlic butter, arrange them over the zucchini in a single layer, and shower everything with parmesan.","Bake for 10 to 12 minutes until the shrimp curl into loose commas and the cheese forms a lacy golden crust.","Serve straight from the dish while the butter still sizzles at the edges."],"tip":"A shrimp curled into a tight O is overcooked — you want commas, not full stops."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_stuffed_bell_peppers', '{"id":"turkey_stuffed_bell_peppers","name":"Cheesy Turkey Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"bell_pepper","q":3},{"f":"cauliflower","q":0.4},{"f":"tomato","q":2},{"f":"cheddar","q":70},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 190C, halve the peppers through the stem, and scoop out the seeds to make six sturdy boats.","Pulse or grate the cauliflower into rice-sized bits while the olive oil heats in a wide skillet.","Brown the turkey with the onion and garlic over medium-high heat for 6 minutes, breaking it into crumbles and seasoning with cumin, chili powder, and salt.","Stir in the chopped tomatoes and cauliflower rice and cook 4 more minutes until the mixture is juicy but not wet.","Pack the filling into the pepper halves, top each with cheddar, and bake for 25 minutes until the peppers slump slightly and the cheese bronzes.","Rest 5 minutes before serving so the filling firms enough to eat without an avalanche."],"tip":"Pick squat, flat-bottomed peppers — the tall elegant ones tip over and dump their dinner every time."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crustless_spinach_feta_quiche', '{"id":"crustless_spinach_feta_quiche","name":"Crustless Spinach Feta Quiche","emoji":"🥬","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":45,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"spinach","q":200},{"f":"feta","q":100},{"f":"milk","q":100},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 180C and oil a pie dish or small baking dish thoroughly, corners included.","Sweat the sliced onion in olive oil over medium heat for 5 minutes until soft and sweet, then wilt the spinach until every leaf collapses and the pan looks nearly dry.","Whisk the eggs with the milk, a pinch of salt, and a heavy grind of pepper until fully unified with no streaks of white.","Spread the spinach mixture over the dish, crumble the feta on top, and pour the custard over everything so it seeps into the gaps.","Bake for 28 to 32 minutes until the top is golden, the edges pull from the dish, and the center springs back to a gentle poke.","Cool for 10 minutes — this quiche slices like a dream warm and shatters like one straight from the oven."],"tip":"Cook the spinach until the pan is dry; feta brings enough brine that soggy quiche has no alibi."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_cheddar_gratin', '{"id":"cauliflower_cheddar_gratin","name":"Golden Cauliflower Cheddar Gratin","emoji":"🧈","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"cheddar","q":100},{"f":"parmesan","q":40},{"f":"milk","q":150},{"f":"butter","q":25},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 200C and boil the cauliflower florets in well-salted water for 4 minutes, until a knife meets slight resistance at the core.","Drain the florets and let them steam-dry in the colander for a full 5 minutes — moisture is the enemy of a proper gratin.","Melt the butter with the minced garlic in a saucepan, pour in the milk, and warm it to a bare simmer before stirring in the cheddar off the heat until glossy.","Tumble the cauliflower into a baking dish, pour the cheese sauce over every floret, and dust the top with parmesan.","Bake for 22 minutes until the surface freckles deep gold and the sauce bubbles up the sides like a cheese tide.","Rest briefly, then serve while the top still crackles."],"tip":"Undercook the cauliflower on the stove — it finishes in the oven, and nobody has ever praised a gratin for its mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_broccoli_bake', '{"id":"sesame_tofu_broccoli_bake","name":"Sesame Garlic Tofu Broccoli Bake","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["soy","sesame"],"time":45,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"broccoli","q":350},{"f":"bell_pepper","q":1},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3}],"steps":["Heat the oven to 220C and press the tofu between paper towels under a heavy pan for 10 minutes to squeeze out its water.","Tear the tofu into rough, craggy chunks — torn edges crisp far better than clean cubes ever will.","Toss the tofu, broccoli florets, and sliced bell pepper with olive oil, minced garlic, salt, and a good pinch of chili flakes on a sheet pan.","Roast for 25 minutes, flipping once halfway, until the tofu edges turn deep amber and the broccoli tips char and crisp.","Drizzle the sesame oil over the hot pan the moment it leaves the oven so its aroma blooms without burning.","Serve immediately while the contrast between crackly tofu and tender pepper is at its peak."],"tip":"Sesame oil is a finishing perfume, not a cooking fat — add it after the oven or mourn its flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ricotta_mushroom_florentine_bake', '{"id":"ricotta_mushroom_florentine_bake","name":"Ricotta Mushroom Florentine Bake","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":55,"servings":2,"ing":[{"f":"ricotta","q":250},{"f":"spinach","q":200},{"f":"mushrooms","q":200},{"f":"eggs","q":3},{"f":"parmesan","q":40},{"f":"mozzarella","q":60},{"f":"garlic","q":0.3},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 190C and sear the sliced mushrooms in olive oil over high heat until their water evaporates and they squeak then brown, about 8 minutes.","Add the garlic and spinach to the pan in handfuls, cooking until the leaves wilt to a dark tangle and the pan runs dry.","Beat the ricotta with the eggs, parmesan, salt, pepper, and a whisper of nutmeg until the mixture turns light and creamy.","Fold the vegetables through the ricotta base and spread it into an oiled baking dish, smoothing the top like frosting.","Scatter the mozzarella over the surface and bake for 30 minutes until puffed at the edges, golden in patches, and just set in the center.","Rest 8 minutes — the bake firms as it cools and rewards your patience with clean squares."],"tip":"Crowded mushrooms steam and sulk; give them room and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cottage_cheese_broccoli_egg_bake', '{"id":"cottage_cheese_broccoli_egg_bake","name":"Cottage Cheese Broccoli Egg Bake","emoji":"🍳","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":45,"servings":2,"ing":[{"f":"cottage_cheese","q":300},{"f":"eggs","q":4},{"f":"broccoli","q":300},{"f":"cheddar","q":60},{"f":"onion","q":0.5},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 180C and chop the broccoli into small, pea-to-marble-sized pieces so they soften fully in the custard.","Saute the diced onion in olive oil until golden, about 5 minutes, then add the broccoli and cook 3 minutes more until bright green.","Whisk the eggs with the cottage cheese, salt, pepper, and half the cheddar until the curds are evenly suspended.","Stir the vegetables into the custard, pour into an oiled baking dish, and top with the remaining cheddar.","Bake for 30 minutes until the top is burnished gold and a knife inserted at the center comes out clean and hot.","Cool 5 minutes; it slices into tidy squares that reheat beautifully all week."],"tip":"Cottage cheese skeptics never notice it here — the curds melt into custard and take all the credit as ''creaminess''."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_taco_zucchini_boats', '{"id":"beef_taco_zucchini_boats","name":"Beef Taco Zucchini Boats","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"zucchini","q":3},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"cheddar","q":60},{"f":"sour_cream","q":60},{"f":"olive_oil","q":10}],"steps":["Heat the oven to 200C, halve the zucchini lengthwise, and scoop out the centers with a spoon to leave sturdy quarter-inch walls.","Chop the scooped flesh and set it aside — it is filling, not trash.","Brown the beef with the onion and garlic in olive oil over high heat, seasoning with cumin, paprika, chili powder, and salt until deeply fragrant, about 7 minutes.","Stir in the chopped tomatoes and reserved zucchini flesh and simmer 5 minutes until the mixture thickens to a spoonable taco filling.","Load the boats, crown them with cheddar, and bake for 20 minutes until the zucchini is tender and the cheese bubbles with brown speckles.","Finish each boat with a cool dollop of sour cream against the spiced, molten filling."],"tip":"Leave those walls thick — a thin-hulled zucchini boat sinks under a full cargo of beef."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_chicken_cauliflower_traybake', '{"id":"tandoori_chicken_cauliflower_traybake","name":"Tandoori-Style Chicken Cauliflower Traybake","emoji":"🍗","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":60,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"cauliflower","q":0.7},{"f":"greek_yogurt","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20}],"steps":["Whisk the yogurt with minced garlic, garam masala, paprika, turmeric, cayenne, and salt into a brick-red marinade.","Cut the chicken into large chunks, coat them completely in two-thirds of the marinade, and let them sit at least 20 minutes while the oven heats to 220C.","Toss the cauliflower florets and thick onion wedges with olive oil, salt, and the remaining marinade on a large sheet pan.","Nestle the chicken among the vegetables in a single layer with breathing room so everything roasts instead of steams.","Roast for 25 to 28 minutes until the yogurt crust chars at the edges and the cauliflower tips blacken sweetly.","Rest 5 minutes and serve with the scorched pan juices spooned over the top."],"tip":"Those charred, almost-burnt yogurt edges are the whole point — resist the urge to rescue them early."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_artichoke_olive_chicken', '{"id":"sheet_pan_artichoke_olive_chicken","name":"Sheet-pan chicken with artichokes & olives","emoji":"🫒","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":450},{"f":"potatoes","q":450},{"f":"artichoke_hearts","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425°F and cut the potatoes into 2 cm chunks so they cook in step with the chicken.","Toss the potatoes, drained artichoke hearts, and olives on a rimmed sheet pan with half the oil, the oregano, minced garlic, salt, and pepper.","Rub the chicken thighs with the remaining oil, nestle them among the vegetables skin-side up, and tuck thin lemon slices around the edges.","Roast 35–40 minutes until the chicken skin is deeply bronzed and the potatoes yield easily to a fork.","Squeeze the remaining roasted lemon over the pan and let everything rest 5 minutes so the juices settle back into the meat."],"tip":"Roasted lemon slices are edible gold — eat them, rind and all, with the crispy chicken bits."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_turkey_meatballs_broccoli', '{"id":"sheet_pan_turkey_meatballs_broccoli","name":"Sheet-pan turkey meatballs with charred broccoli","emoji":"🍢","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"broccoli","q":400},{"f":"cherry_tomatoes","q":200},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 450°F and line a sheet pan so cleanup stays a rinse, not a scrub.","Mix the turkey with the egg, grated parmesan, minced garlic, oregano, salt, and pepper, then roll into twelve golf-ball meatballs with damp hands to keep them from sticking.","Toss the broccoli florets and cherry tomatoes with the olive oil and a pinch of salt, spread them on the pan, and space the meatballs among them.","Roast 18–20 minutes until the meatballs are firm and browned on the bottom and the broccoli tips are frizzled and dark at the edges.","Crush a few of the blistered tomatoes with the back of a spoon and drag the meatballs through that instant pan sauce before serving."],"tip":"Charred broccoli is a feature, not a mistake — those crispy black edges are the best part."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chili_beef_mini_meatloaf_sheet_pan', '{"id":"chili_beef_mini_meatloaf_sheet_pan","name":"Chili-rubbed mini meatloaves with sweet potato wedges","emoji":"🌶️","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"eggs","q":1},{"f":"onion","q":0.5},{"f":"sweet_potatoes","q":450},{"f":"chili_powder","q":6},{"f":"cumin","q":3},{"f":"olive_oil","q":15},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F and cut the sweet potatoes into thick wedges, tossing them with the oil, half the chili powder, and a good pinch of salt on one side of a sheet pan.","Mix the beef with the egg, finely grated onion, cumin, remaining chili powder, and salt until just combined — overworking makes tough loaves.","Shape the mixture into two oval mini meatloaves and set them on the open side of the pan.","Roast 25–28 minutes, flipping the wedges halfway, until the loaves are browned with an internal temp of 160°F and the wedges are caramelized at the tips.","Shower everything with chopped cilantro and a hard squeeze of lime to cut through the richness."],"tip":"Grate the onion instead of dicing it — it vanishes into the meat and keeps the loaves juicy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_ginger_salmon_green_beans_sheet_pan', '{"id":"soy_ginger_salmon_green_beans_sheet_pan","name":"Soy-ginger glazed salmon with blistered green beans","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":400},{"f":"green_beans","q":350},{"f":"soy_sauce","q":30},{"f":"honey","q":20},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"sesame_oil","q":10},{"f":"scallions","q":0.5},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425°F and whisk the soy sauce, honey, grated ginger, minced garlic, and sesame oil into a glossy glaze.","Toss the trimmed green beans with a spoonful of the glaze and spread them over most of a sheet pan, leaving room for the fish.","Lay the salmon fillets skin-side down in the gap, brush them generously with glaze, and roast 12–14 minutes until the fish flakes at a nudge but still looks rosy in the center.","Switch to broil for the final 2 minutes so the glaze bubbles and lacquers and the beans pick up dark blisters.","Scatter thin-sliced scallions over the pan and spoon any pooled glaze back over the salmon before serving."],"tip":"Pull salmon when it still looks slightly underdone — carryover heat finishes it while you find the plates."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_shrimp_fajitas', '{"id":"sheet_pan_shrimp_fajitas","name":"Sheet-pan shrimp fajitas","emoji":"🦐","cuisine":"Mexican","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","gluten"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"bell_pepper","q":3},{"f":"onion","q":1},{"f":"tortillas","q":4},{"f":"olive_oil","q":20},{"f":"cumin","q":4},{"f":"chili_powder","q":4},{"f":"lime","q":1},{"f":"avocado","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 450°F and slice the peppers and onion into thin strips so they soften and char quickly.","Toss the vegetables with the oil, cumin, chili powder, and salt, spread them in a single layer, and roast 15 minutes until the edges catch color.","Pat the shrimp very dry, toss them in the residual spiced oil in the bowl, and scatter them over the vegetables for a final 6–7 minutes — they are done the instant they curl into loose commas.","Warm the tortillas directly on the oven rack for the last 2 minutes.","Pile the pan''s contents into the tortillas with sliced avocado, torn cilantro, and a squeeze of lime, then serve with the pan drippings on the side."],"tip":"Shrimp go from succulent to rubber bands in about ninety seconds, so set a timer and trust it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_broccoli_sheet_pan', '{"id":"sesame_tofu_broccoli_sheet_pan","name":"Crispy sesame tofu and broccoli sheet pan","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":40,"servings":2,"ing":[{"f":"tofu","q":450},{"f":"broccoli","q":400},{"f":"rice","q":150},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":12},{"f":"maple_syrup","q":15},{"f":"ginger","q":8},{"f":"garlic","q":0.3},{"f":"scallions","q":0.5}],"steps":["Heat the oven to 450°F while you press the tofu between towels under a heavy skillet for 10 minutes — dry tofu is the only tofu that crisps.","Tear the tofu into rough bite-size chunks (craggy edges brown better than clean cubes), toss with half the sesame oil, and spread on one side of a sheet pan with the broccoli florets on the other.","Roast 25 minutes, turning once, until the tofu is golden and the broccoli tips are toasty; meanwhile simmer the rice in double its volume of water until tender, about 15 minutes.","Whisk the soy sauce, maple syrup, grated ginger, garlic, and remaining sesame oil, pour it over the hot pan, and toss so the sauce sizzles and clings.","Serve over the rice with a flurry of sliced scallions."],"tip":"Tearing tofu instead of cubing it is the cheapest texture upgrade in your kitchen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_baked_egg_veggie_nests', '{"id":"sheet_pan_baked_egg_veggie_nests","name":"Sheet-pan baked eggs in roasted vegetable nests","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["eggs","dairy"],"time":40,"servings":2,"ing":[{"f":"zucchini","q":1},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"cherry_tomatoes","q":250},{"f":"eggs","q":4},{"f":"feta","q":60},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 425°F and slice the zucchini, peppers, and onion into strips of roughly equal thickness so nothing lags behind.","Toss the vegetables and cherry tomatoes with the oil, oregano, salt, and pepper, and roast 22–25 minutes until slumped, sweet, and browned at the edges.","Pull the pan out, push the vegetables into four loose nests, and crack an egg into each hollow.","Crumble the feta over the top and return the pan for 7–9 minutes, until the whites are just set but the yolks still shiver when you shake the pan.","Serve straight from the pan while the yolks are still runny enough to sauce the vegetables."],"tip":"Crack each egg into a cup first — fishing shell shards out of a hot sheet pan builds character you don''t need."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('curried_chickpea_cauliflower_sheet_pan', '{"id":"curried_chickpea_cauliflower_sheet_pan","name":"Curried chickpea and cauliflower sheet pan","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"cauliflower","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":25},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"garam_masala","q":3},{"f":"lemon","q":1},{"f":"cilantro","q":0.4},{"f":"salt","q":4}],"steps":["Heat the oven to 450°F and cut the cauliflower into small florets, saving the sliced core — it roasts into sweet, nutty coins.","Pat the chickpeas thoroughly dry with a towel, then toss them, the cauliflower, and thick onion wedges with the oil, curry powder, turmeric, and salt.","Spread everything in a single layer across the pan; crowding steams, and steam is the enemy of crunch.","Roast 28–30 minutes, shaking the pan once, until the chickpeas rattle when you jostle them and the cauliflower is deeply browned in spots.","Dust with garam masala the moment the pan comes out, then finish with lemon juice and a big handful of chopped cilantro."],"tip":"Adding garam masala after roasting keeps its perfume bright instead of baking it into the background."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_pork_apple_carrot_sheet_pan', '{"id":"maple_pork_apple_carrot_sheet_pan","name":"Maple-roasted pork loin with apples and carrots","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"pork_loin","q":450},{"f":"apple","q":1},{"f":"carrots","q":300},{"f":"onion","q":0.5},{"f":"maple_syrup","q":25},{"f":"olive_oil","q":15},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 400°F and cut the carrots into thick batons, the apple into eighths, and the onion into wedges.","Toss the vegetables and apple with the oil, half the maple syrup, the cinnamon, and salt, and spread them around the edges of a sheet pan.","Season the pork loin aggressively with salt and pepper, set it in the center, and brush it with the remaining maple syrup.","Roast 30–35 minutes until the pork reads 140°F at its thickest point and the apples have collapsed into jammy, caramel-edged wedges.","Rest the pork 8 full minutes before slicing thick, then drag each slice through the syrupy pan juices."],"tip":"Pork loin punishes impatience — pull it at 140°F and let the rest do the last five degrees."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_white_bean_zucchini_sheet_pan', '{"id":"crispy_white_bean_zucchini_sheet_pan","name":"Crispy white beans with zucchini and parmesan","emoji":"🫘","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"white_beans","q":400},{"f":"zucchini","q":2},{"f":"cherry_tomatoes","q":250},{"f":"parmesan","q":40},{"f":"olive_oil","q":25},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"balsamic_vinegar","q":15},{"f":"basil","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 450°F and pat the white beans dry — moisture is the difference between crispy and mushy.","Cut the zucchini into thick half-moons and toss them, the beans, and the cherry tomatoes with the oil, sliced garlic, oregano, and salt.","Spread in a single layer and roast 22–25 minutes until the beans'' skins split and crackle and the tomatoes slump into jammy pockets.","Shower the hot pan with grated parmesan and return it to the oven for 3 minutes so the cheese melts into a lacy crust.","Drizzle with balsamic, tear the basil over the top, and serve straight from the pan with a spoon for the crispy cheese bits."],"tip":"The parmesan that fuses to the pan is the cook''s tax — scrape it off and eat it standing up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_black_bean_sheet_pan', '{"id":"sweet_potato_black_bean_sheet_pan","name":"Smoky sweet potato and black bean sheet pan","emoji":"🍠","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":400},{"f":"bell_pepper","q":2},{"f":"olive_oil","q":20},{"f":"cumin","q":4},{"f":"chili_powder","q":5},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.4},{"f":"salt","q":4}],"steps":["Heat the oven to 425°F and dice the sweet potatoes into 2 cm cubes so they turn creamy inside before the outsides burn.","Toss the sweet potatoes and sliced peppers with the oil, cumin, chili powder, and salt, and roast 20 minutes until the cubes take on dark caramel corners.","Pat the black beans dry, scatter them over the pan, and roast 8–10 minutes more until their skins tighten and a few begin to pop.","Mash the avocado with lime juice and a pinch of salt into a rough, chunky crema while the pan finishes.","Pile everything into bowls, dollop with the avocado mash, and finish with chopped cilantro and any lime left in the shell."],"tip":"Give the sweet potatoes a head start — beans only need minutes, but pale sweet potato is a broken promise."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_feta_pepper_sheet_pan', '{"id":"baked_feta_pepper_sheet_pan","name":"Sheet-pan baked feta with blistered peppers and pita","emoji":"🧀","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"feta","q":200},{"f":"bell_pepper","q":2},{"f":"cherry_tomatoes","q":300},{"f":"olives","q":50},{"f":"olive_oil","q":25},{"f":"oregano","q":3},{"f":"garlic","q":0.3},{"f":"pita","q":2},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 425°F and slice the peppers into wide strips, keeping the feta in one proud slab in the center of the pan.","Surround the cheese with the peppers, cherry tomatoes, olives, and sliced garlic, then douse everything with the olive oil, oregano, and plenty of black pepper.","Roast 25 minutes until the tomatoes burst, the peppers wilt and char at the tips, and the feta turns golden and soft enough to spread.","Slide the pitas onto the oven rack for the last 3 minutes to warm and puff.","Smash the feta gently into the burst tomatoes to make a creamy, briny sauce and scoop it all up with torn pita."],"tip":"Feta doesn''t melt like mozzarella — it softens into a spreadable cloud, which is honestly better."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sheet_pan_eggplant_mozzarella', '{"id":"sheet_pan_eggplant_mozzarella","name":"Sheet-pan eggplant parm-style bake","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"crushed_tomatoes","q":300},{"f":"mozzarella","q":150},{"f":"parmesan","q":20},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":5}],"steps":["Heat the oven to 450°F and slice the eggplant into rounds a generous centimeter thick, salting both sides and letting them sweat 10 minutes before blotting dry.","Brush the rounds with most of the olive oil, arrange them in a single layer, and roast 20 minutes, flipping once, until they are supple and mahogany on both faces.","Stir the minced garlic and oregano into the crushed tomatoes and spoon a thick layer onto each round.","Top with torn mozzarella and grated parmesan, then roast 8–10 minutes more until the cheese is molten with bronze freckles.","Rest 5 minutes — the eggplant firms as it cools — then finish with torn basil and the last thread of olive oil."],"tip":"Salting and sweating the eggplant first means roasted silk instead of oil-soaked sponge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_cheeseburger_penne', '{"id":"one_pot_cheeseburger_penne","name":"One-Pot Cheeseburger Penne","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"penne","q":160},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":300},{"f":"broth","q":450},{"f":"cheddar","q":50},{"f":"paprika","q":3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Brown the ground beef in a wide, deep skillet over medium-high heat for 6 to 7 minutes, breaking it into pebbly crumbles and letting it develop dark, crusty edges before you stir.","Add the diced onion and cook 4 minutes until translucent, then stir in the minced garlic and paprika for 30 seconds until the pan smells like a burger joint.","Pour in the crushed tomatoes and broth, season with salt and pepper, and scrape up every browned bit stuck to the bottom.","Stir in the dry penne, bring to a lively simmer, then cover and cook 12 to 14 minutes, stirring every few minutes so nothing sticks, until the pasta is al dente and the sauce clings like a chili.","Kill the heat, shower the shredded cheddar over the top, and cover for 2 minutes until it melts into glossy pockets before serving."],"tip":"Resist stirring the beef for the first few minutes — the crust you build there is doing the flavor work the drive-thru never could."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_turkey_ragu_spaghetti', '{"id":"one_pot_turkey_ragu_spaghetti","name":"One-Pot Turkey Ragu Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"broth","q":500},{"f":"oregano","q":2},{"f":"parmesan","q":30},{"f":"basil","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a deep saute pan over medium-high heat and brown the ground turkey for 5 to 6 minutes, pressing it flat like a patty first so it sears instead of steams.","Stir in the diced onion and cook 4 minutes until soft, then add the garlic and oregano and cook 30 seconds until fragrant.","Add the crushed tomatoes, broth, salt, and pepper, and bring the ragu to a rolling simmer.","Nestle the spaghetti in whole, submerging it as it softens over the first minute, then cook uncovered 11 to 13 minutes, tossing with tongs often, until the noodles are glossy and the sauce has thickened to coat them.","Turn off the heat, rain in the grated parmesan while tossing, and finish with torn basil leaves just before the bowls hit the table."],"tip":"Fan the spaghetti into the pan like a crosshatch so the strands don''t fuse into one heroic mega-noodle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_tuscan_chicken_penne', '{"id":"one_pot_tuscan_chicken_penne","name":"One-Pot Creamy Tuscan Chicken Penne","emoji":"🐔","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"penne","q":170},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"cherry_tomatoes","q":150},{"f":"broth","q":500},{"f":"milk","q":150},{"f":"parmesan","q":40},{"f":"spinach","q":100},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Cut the chicken into bite-size chunks, season with salt, pepper, and oregano, and sear in olive oil over medium-high heat for 4 to 5 minutes until golden at the edges but not yet cooked through.","Add the diced onion, garlic, and halved cherry tomatoes and cook 3 minutes until the tomatoes start to slump and release their juices.","Pour in the broth and milk, stir in the dry penne, and bring to a steady simmer.","Cover and cook 12 to 14 minutes, stirring every 3 minutes, until the pasta is tender and the liquid has turned into a light cream sauce.","Off the heat, stir in the parmesan and spinach by the handful, letting each addition wilt and the sauce turn silky before serving."],"tip":"The sauce will look too loose at minute 12 — give it two minutes off the heat and the parmesan will tighten it up like a good editor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_shrimp_scampi_spaghetti', '{"id":"one_pot_shrimp_scampi_spaghetti","name":"One-Pot Shrimp Scampi Spaghetti","emoji":"🍤","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy","shellfish"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"spaghetti","q":170},{"f":"butter","q":30},{"f":"olive_oil","q":15},{"f":"garlic","q":0.5},{"f":"broth","q":550},{"f":"lemon","q":1},{"f":"parsley","q":0.3},{"f":"chili_powder","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Melt half the butter with the olive oil in a wide skillet over medium heat, add the sliced garlic and chili powder, and cook 1 minute until the garlic turns pale gold and smells sweet, not sharp.","Pour in the broth, season with salt and pepper, and bring it to a brisk simmer.","Lay in the spaghetti, pressing it under the liquid as it relaxes, and cook uncovered 10 to 12 minutes, tossing frequently, until the noodles are just shy of al dente and the liquid has reduced to a loose glaze.","Scatter the shrimp over the pasta, cover, and cook 3 to 4 minutes until they curl into loose commas and turn opaque pink.","Finish off the heat with the remaining butter, the juice and zest of the lemon, and a flurry of chopped parsley, tossing until every strand shines."],"tip":"Shrimp go from succulent to eraser in about ninety seconds, so add them late and trust the residual heat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_lemon_salmon_spaghetti', '{"id":"one_pot_lemon_salmon_spaghetti","name":"One-Pot Creamy Lemon Salmon Spaghetti","emoji":"🐟","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy","fish"],"time":30,"servings":2,"ing":[{"f":"salmon","q":280},{"f":"spaghetti","q":160},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3},{"f":"broth","q":500},{"f":"milk","q":150},{"f":"peas_frozen","q":100},{"f":"parmesan","q":30},{"f":"lemon","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Season the salmon with salt and pepper and sear it skin-side down in olive oil over medium-high heat for 3 minutes until the skin crisps, then flip for 1 minute and lift it out — it should still be rare in the middle.","Lower the heat, add the minced garlic to the same pan, and cook 30 seconds in the salmon-scented oil.","Pour in the broth and milk, add the spaghetti, and simmer uncovered 10 to 12 minutes, tossing often, until the pasta is tender and the liquid has become a light cream.","Stir in the peas and parmesan, then flake the salmon into big blushing pieces and fold it back in gently so it finishes cooking in the sauce, about 2 minutes.","Brighten everything with the lemon''s zest and juice, grind over black pepper, and serve straight from the pan."],"tip":"Pull the salmon while it still looks underdone — it will finish in the sauce, and flaky beats chalky every night of the week."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_creamy_tuna_penne', '{"id":"one_pot_creamy_tuna_penne","name":"One-Pot Creamy Tuna Penne","emoji":"🥫","cuisine":"American","meal":["dinner","lunch"],"diets":["high-protein"],"allergens":["gluten","dairy","fish"],"time":30,"servings":2,"ing":[{"f":"tuna_canned","q":200},{"f":"penne","q":170},{"f":"butter","q":15},{"f":"onion","q":0.5},{"f":"celery","q":80},{"f":"broth","q":450},{"f":"milk","q":250},{"f":"peas_frozen","q":120},{"f":"cheddar","q":60},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Melt the butter in a deep skillet over medium heat and sweat the diced onion and celery for 5 minutes until soft and sweet, seasoning with salt and pepper as they go.","Add the broth, milk, and dry penne, bring to a gentle simmer, and cook 12 to 14 minutes, stirring every few minutes so the milk doesn''t catch, until the pasta is tender and the liquid is creamy.","Stir in the peas and drained tuna in big flakes and let them heat through for 2 minutes without aggressive stirring, so the tuna stays in real pieces.","Off the heat, fold in the cheddar until it melts into a glossy sauce that coats the back of a spoon.","Rest the pot 3 minutes with the lid on — the sauce settles from soupy to spoon-clinging — then serve with more black pepper."],"tip":"This is the casserole of your childhood minus the oven and the mystery — keep the simmer gentle or the milk will remind you who''s boss."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_amatriciana_style_spaghetti', '{"id":"one_pot_amatriciana_style_spaghetti","name":"One-Pot Bacon Amatriciana-Style Spaghetti","emoji":"🥓","cuisine":"Italian","meal":["dinner"],"diets":[],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"bacon","q":100},{"f":"spaghetti","q":170},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"broth","q":450},{"f":"chili_powder","q":1},{"f":"parmesan","q":40},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Cut the bacon into thin strips and render it in a cold, wide pan brought slowly up to medium heat, about 6 minutes, until the pieces are bronzed and the fat has pooled.","Spoon off all but a couple tablespoons of fat, then cook the sliced onion in what remains for 4 minutes until golden at the edges, adding the garlic and chili powder for the last 30 seconds.","Pour in the crushed tomatoes and broth, season lightly with salt (the bacon and parmesan carry plenty), and bring to a simmer.","Add the spaghetti, pushing it under as it bends, and cook uncovered 11 to 13 minutes, tossing often, until the sauce is brick-red, glossy, and hugging every strand.","Toss in most of the parmesan off the heat until creamy, then top each bowl with the rest and a bold grind of black pepper."],"tip":"Starting bacon in a cold pan is the difference between rendered and cremated — patience pays in fat, and fat pays in flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_white_bean_basil_penne', '{"id":"one_pot_white_bean_basil_penne","name":"One-Pot White Bean & Basil Penne","emoji":"🌿","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"white_beans","q":350},{"f":"penne","q":170},{"f":"olive_oil","q":25},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"zucchini","q":1},{"f":"crushed_tomatoes","q":400},{"f":"basil","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a wide pot over medium heat and cook the diced onion for 5 minutes until soft and translucent, then add the garlic and oregano for a fragrant 30 seconds.","Add the diced zucchini and cook 3 minutes until it starts to brown at the corners.","Stir in the crushed tomatoes, 500 ml of water, the salt, and the dry penne, and bring everything to a steady simmer.","Cook uncovered 12 to 14 minutes, stirring regularly and mashing a spoonful of the white beans against the pot''s side to thicken the sauce, adding the rest whole halfway through.","When the penne is tender and the sauce is velvety, tear in the basil, grind over black pepper, and drizzle each bowl with any olive oil left in your conscience."],"tip":"That smashed spoonful of beans is your secret thickener — creamy sauce, zero cream, and nobody needs to know."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_pasta_e_ceci', '{"id":"one_pot_pasta_e_ceci","name":"One-Pot Pasta e Ceci","emoji":"🫘","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"spaghetti","q":150},{"f":"olive_oil","q":25},{"f":"onion","q":0.5},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":250},{"f":"spinach","q":80},{"f":"oregano","q":2},{"f":"chili_powder","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a heavy pot over medium heat and cook the diced onion 4 minutes until soft, then add the garlic, oregano, and chili powder and stir for 30 seconds until the kitchen smells like a Roman trattoria.","Add the chickpeas and crushed tomatoes and simmer 5 minutes, crushing about a third of the chickpeas with the back of your spoon to give the broth body.","Pour in 600 ml of water, season with salt, and bring to a boil.","Snap the spaghetti into rough 3 cm pieces, stir them in, and cook uncovered 10 to 12 minutes, stirring often, until the pasta is tender and the pot has turned into something between a stew and a sauce.","Wilt in the spinach for the final minute, then rest 3 minutes off the heat — it thickens beautifully — and serve with black pepper and a defiant drizzle of olive oil."],"tip":"Snapping spaghetti is a crime in Naples and a technique in pasta e ceci — this is the one dish where you break noodles with pride."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_creamy_paprika_pork_penne', '{"id":"one_pot_creamy_paprika_pork_penne","name":"One-Pot Creamy Paprika Pork Penne","emoji":"🐷","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"penne","q":170},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"mushrooms","q":150},{"f":"paprika","q":5},{"f":"broth","q":550},{"f":"sour_cream","q":100},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Slice the pork loin into thin strips, season with salt and pepper, and sear in olive oil over high heat for 2 to 3 minutes until browned but still juicy, then set aside on a plate.","Drop the heat to medium and cook the sliced onion and mushrooms in the same pan for 6 minutes until the mushrooms release their liquid and it evaporates, leaving them golden.","Stir in the garlic and paprika for 30 seconds — just until the paprika blooms brick-red and fragrant, no longer or it turns bitter.","Add the broth and dry penne, bring to a simmer, cover, and cook 12 to 14 minutes with occasional stirring until the pasta is tender and only a slick of liquid remains.","Off the heat, stir in the sour cream and the pork with its resting juices, warm through for 2 minutes without boiling, and finish with chopped parsley."],"tip":"Sour cream added at a boil will split into sad little curds — kill the flame first and it stays silky as a jazz standard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_mushroom_garlic_spaghetti', '{"id":"one_pot_mushroom_garlic_spaghetti","name":"One-Pot Garlicky Mushroom Spaghetti","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":30,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"spaghetti","q":160},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"balsamic_vinegar","q":15},{"f":"spinach","q":100},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in your widest pan over medium-high and cook the sliced mushrooms in a single layer, undisturbed, for 4 minutes until deeply browned on one side, then stir and cook 3 minutes more.","Add the sliced onion and cook 4 minutes until golden, then stir in the garlic and oregano for 30 seconds.","Deglaze with the balsamic vinegar, scraping up the sticky brown film on the pan floor, then add 650 ml of water and the salt and bring to a boil.","Lay in the spaghetti and cook uncovered 10 to 12 minutes, tossing constantly toward the end, until the starchy water reduces to a glossy pan sauce that grips the noodles.","Fold in the spinach until it collapses, hit everything with a heavy grind of black pepper, and serve while the mushrooms are still swaggering."],"tip":"Crowded mushrooms steam and sulk; give them room and silence and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_lemon_ricotta_zucchini_penne', '{"id":"one_pot_lemon_ricotta_zucchini_penne","name":"One-Pot Lemon Ricotta Zucchini Penne","emoji":"🍋","cuisine":"Italian","meal":["dinner","lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"ricotta","q":200},{"f":"penne","q":170},{"f":"zucchini","q":2},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"parmesan","q":30},{"f":"basil","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the olive oil in a deep skillet over medium-high and saute the half-moon zucchini slices for 5 to 6 minutes until browned and tender, seasoning with salt as they cook.","Add the sliced garlic for 30 seconds, then pour in 650 ml of water with the remaining salt and bring to a boil.","Stir in the dry penne and cook uncovered 12 to 14 minutes, stirring often, until the pasta is al dente and the water has reduced to a few starchy spoonfuls.","Off the heat, stir in the ricotta, parmesan, and the zest and juice of the lemon, tossing until the starchy liquid and cheese emulsify into a pale, creamy sauce.","Tear in the basil, grind over black pepper, and serve immediately, while the sauce is at peak cling."],"tip":"That murky pasta water you almost boiled away is the glue of this sauce — guard the last half-cup with your life."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('one_pot_lentil_ragu_spaghetti', '{"id":"one_pot_lentil_ragu_spaghetti","name":"One-Pot Lentil Ragu Spaghetti","emoji":"🥕","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":45,"servings":2,"ing":[{"f":"lentils_dry","q":120},{"f":"spaghetti","q":150},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"celery","q":60},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the finely diced onion, carrot, and celery for 7 to 8 minutes until soft and sweet — this soffritto is the ragu''s whole personality.","Add the garlic and oregano for 30 seconds, then stir in the rinsed lentils, crushed tomatoes, and 700 ml of water.","Simmer partially covered for 20 minutes, stirring occasionally, until the lentils are just tender with a slight bite, then season with the salt.","Snap the spaghetti in half, stir it into the pot, and cook uncovered 11 to 13 minutes, stirring often and adding a splash of water if it thickens faster than the pasta cooks.","When the noodles are tender and the ragu is thick enough to mound on a spoon, rest it 3 minutes off the heat and serve with black pepper and a thread of olive oil."],"tip":"Salt lentils after they soften, not before — early salt keeps them stubborn, and nobody wants a ragu with attitude."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_garlic_chicken_skillet', '{"id":"lemon_garlic_chicken_skillet","name":"Lemon-Garlic Chicken Skillet with Wilted Spinach","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"spinach","q":150},{"f":"broth","q":200},{"f":"butter","q":15}],"steps":["Halve the chicken breasts horizontally into thin cutlets, pat them bone-dry, and season generously with salt and pepper.","Heat the olive oil in a large skillet over medium-high until it shimmers, then sear the cutlets 3 to 4 minutes per side until deeply golden and just cooked through; transfer to a plate.","Drop the heat to medium, add the sliced garlic, and stir for 30 seconds until fragrant but not browned.","Pour in the broth and the juice of the lemon, scraping up the browned bits, and simmer 2 to 3 minutes until the liquid reduces by half.","Swirl in the butter until the sauce turns glossy, then pile in the spinach and let it wilt for 1 minute.","Return the chicken and any juices to the pan, spoon the sauce over the top, and serve straight from the skillet."],"tip":"Thin cutlets are the whole secret to weeknight speed — a thick breast will still be sulking raw in the middle when the sauce is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_soy_chicken_broccoli_stir_fry', '{"id":"honey_soy_chicken_broccoli_stir_fry","name":"Honey-Soy Chicken and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"broccoli","q":400},{"f":"soy_sauce","q":45},{"f":"honey","q":20},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.3},{"f":"rice","q":150}],"steps":["Get the rice simmering first: rinse it, cover with water by a knuckle, and cook covered on low for 15 minutes while you stir-fry.","Slice the chicken into thin strips against the grain and whisk the soy sauce and honey together in a small bowl.","Heat half the sesame oil in a wok over high heat until it just smokes, then sear the chicken in a single layer for 2 minutes without touching it, toss, and cook 2 minutes more until browned at the edges; scoop it out.","Add the remaining oil, the broccoli florets, and a splash of water, and stir-fry 3 to 4 minutes until the broccoli is bright green with charred spots but still snappy.","Return the chicken with the minced garlic, pour in the sauce, and toss for 1 minute until everything is lacquered and sticky.","Serve immediately over the hot rice while the glaze still clings."],"tip":"A screaming-hot wok and an untouched first sear buy you restaurant char — fiddling with the chicken buys you gray steamed sadness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('quick_chicken_tortilla_soup', '{"id":"quick_chicken_tortilla_soup","name":"Quick Chicken Tortilla Soup","emoji":"🍲","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten"],"time":30,"servings":4,"ing":[{"f":"chicken_breast","q":450},{"f":"broth","q":1000},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"black_beans","q":240},{"f":"corn_frozen","q":200},{"f":"tortillas","q":4},{"f":"lime","q":1},{"f":"avocado","q":1},{"f":"olive_oil","q":15}],"steps":["Cut two tortillas into thin strips, toss with a little of the oil, and toast in a dry skillet over medium heat for 4 to 5 minutes until crisp and golden; set aside.","Heat the remaining oil in a soup pot over medium, then soften the diced onion for 3 minutes and stir in the garlic, cumin, and chili powder until fragrant.","Add the chopped tomatoes, broth, and whole chicken breasts, bring to a lively simmer, and cook 12 minutes until the chicken registers 165°F.","Pull the chicken onto a board, shred it with two forks, and return it to the pot with the beans, corn, and the remaining two tortillas torn into pieces to thicken the broth.","Simmer 5 minutes more, squeeze in the lime, and taste for salt — the broth should be tangy and faintly smoky.","Ladle into bowls and crown with diced avocado and the crispy tortilla strips."],"tip":"The torn tortillas melting into the broth are doing quiet thickening work — skip them and you have chicken soup wearing a sombrero."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('charred_lime_chicken_tacos', '{"id":"charred_lime_chicken_tacos","name":"Charred Lime Chicken Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":300},{"f":"tortillas","q":4},{"f":"lime","q":2},{"f":"onion","q":0.5},{"f":"avocado","q":1},{"f":"sour_cream","q":60},{"f":"olive_oil","q":15}],"steps":["Toss the chicken thighs with the oil, the juice of one lime, and a bold shower of chili powder, cumin, and salt; let them sit 5 minutes while a heavy skillet gets ripping hot.","Lay the thighs in the dry, hot pan and cook 4 to 5 minutes per side until the edges char and the thickest part hits 170°F — thighs forgive you, so lean into the color.","While the chicken rests, char the tortillas directly over the flame or in the skillet for 20 seconds per side until blistered and pliable.","Chop the rested chicken into bite-size pieces, catching every drop of juice on the board.","Pile the chicken into the warm tortillas and top with thin-sliced onion, avocado, a swipe of sour cream, and wedges of the second lime.","Serve immediately, ideally standing over the counter."],"tip":"Resting the thighs before chopping keeps the juice in the taco instead of on your cutting board, where it helps no one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_tomato_chicken_penne', '{"id":"creamy_tomato_chicken_penne","name":"Creamy Tomato Chicken Penne with Spinach","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"penne","q":180},{"f":"tomato","q":2},{"f":"spinach","q":100},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"milk","q":120},{"f":"parmesan","q":40}],"steps":["Drop the penne into well-salted boiling water and cook until just shy of al dente, about 10 minutes; reserve a cup of the starchy water before draining.","Meanwhile, cube the chicken, season with salt and dried oregano, and brown it in the olive oil over medium-high heat for 5 to 6 minutes until golden and cooked through.","Add the garlic and chopped tomatoes to the pan and cook 3 to 4 minutes, mashing gently, until the tomatoes slump into a rough sauce.","Pour in the milk and a splash of pasta water, simmer 2 minutes until slightly thickened, then stir in the spinach to wilt.","Tumble in the drained penne with most of the parmesan and toss vigorously for a minute until the sauce turns silky and coats every tube.","Plate with the last of the parmesan grated over the top."],"tip":"That reserved pasta water is free sauce insurance — the starch marries milk and cheese into something that tastes suspiciously like heavy cream."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('greek_chicken_chopped_salad', '{"id":"greek_chicken_chopped_salad","name":"Greek Chicken Chopped Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein","low-carb","gluten-free"],"allergens":["dairy"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"romaine","q":1},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"onion","q":0.5},{"f":"feta","q":80},{"f":"olive_oil","q":25},{"f":"lemon","q":1}],"steps":["Butterfly the chicken breasts thin, rub with a spoonful of the olive oil, dried oregano, salt, and pepper, and sear in a hot skillet 3 to 4 minutes per side until golden with crisp edges.","Let the chicken rest on a board while you build the salad — cutting too soon floods your bowl with juice.","Chop the romaine into ribbons and toss it in a wide bowl with the diced cucumber, chopped tomatoes, and paper-thin slices of onion.","Whisk the remaining olive oil with the juice of the lemon, a pinch of salt, and a crack of pepper until it looks cloudy and emulsified.","Slice the rested chicken against the grain, lay it over the salad, and crumble the feta on top in craggy chunks.","Pour the dressing over everything and toss once, gently, at the table."],"tip":"Soak the sliced onion in cold water for five minutes if you enjoy conversation with other humans later tonight."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('weeknight_coconut_chicken_curry', '{"id":"weeknight_coconut_chicken_curry","name":"Weeknight Coconut Chicken Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"coconut_milk","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":2},{"f":"rice","q":120},{"f":"olive_oil","q":10}],"steps":["Start the rice: rinse, cover with water, and simmer lidded on low for 15 minutes, then rest off the heat.","Heat the oil in a deep skillet over medium and cook the sliced onion 4 to 5 minutes until soft and golden at the edges.","Stir in the minced garlic with a heaped spoonful of curry powder and a pinch of salt, toasting for 30 seconds until the kitchen smells unmistakably like dinner.","Add the chopped tomatoes and cook 3 minutes until they break down, then pour in the coconut milk and bring to a gentle bubble.","Slide in the cubed chicken and simmer 8 to 10 minutes, stirring occasionally, until the chicken is cooked through and the sauce coats a spoon.","Taste, adjust the salt, and ladle the curry over the fluffy rice."],"tip":"Toasting the curry powder in the onions for thirty seconds does more for flavor than doubling the amount ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sticky_honey_soy_chicken_bowl', '{"id":"sticky_honey_soy_chicken_bowl","name":"Sticky Glazed Chicken Rice Bowl","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"rice","q":150},{"f":"soy_sauce","q":40},{"f":"honey","q":25},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.2},{"f":"carrots","q":150},{"f":"cucumber","q":0.8}],"steps":["Set the rinsed rice to simmer, covered, over low heat for 15 minutes while everything else comes together.","Shave the carrots into ribbons with a peeler, slice the cucumber thin, and toss both with a splash of the soy sauce to lightly pickle.","Cut the chicken thighs into large chunks and brown them in the sesame oil over medium-high heat, 6 to 7 minutes, until the fat renders and the edges crisp.","Stir the honey, remaining soy sauce, and grated garlic together, pour it over the chicken, and let it bubble 2 minutes until it reduces to a dark, sticky glaze that clings to every piece.","Fluff the rice into two bowls, arrange the glazed chicken on one side and the cool vegetable ribbons on the other.","Drizzle any pan glaze over the top — that is the good stuff."],"tip":"Take the glaze off the heat the moment it turns syrupy; honey goes from lacquer to lollipop in about forty-five seconds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_black_bean_quesadillas', '{"id":"chicken_black_bean_quesadillas","name":"Crispy Chicken and Black Bean Quesadillas","emoji":"🧀","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":250},{"f":"tortillas","q":4},{"f":"cheddar","q":100},{"f":"black_beans","q":150},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":10},{"f":"sour_cream","q":60}],"steps":["Dice the chicken small and sauté it in half the oil over medium-high heat with cumin, paprika, and salt for 4 to 5 minutes until cooked through and lightly browned.","Stir in the diced bell pepper and drained black beans, cooking 2 minutes more and mashing a few beans so the filling holds together.","Scatter cheddar over half of each tortilla, top with the chicken mixture and more cheese, and fold into half-moons — cheese on both sides of the filling is the glue.","Wipe out the skillet, film it with the remaining oil, and cook the quesadillas over medium heat 2 to 3 minutes per side until the tortillas are deeply golden and audibly crisp.","Rest them one minute so the molten cheese sets from lava to lush, then slice into wedges.","Serve with cool sour cream for dragging."],"tip":"Medium heat is non-negotiable — high heat gives you a burnt tortilla hugging cold cheese, and nobody deserves that."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_gyro_style_pitas_2', '{"id":"chicken_gyro_style_pitas_2","name":"Gyro-Style Chicken Pitas with Yogurt Sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"pita","q":2},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.8},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":15}],"steps":["Slice the chicken into thin strips and toss with the olive oil, half the lemon''s juice, oregano, paprika, salt, and pepper.","Make the sauce: coarsely grate a third of the cucumber, squeeze it dry in your fist, and stir it into the yogurt with the grated garlic, the remaining lemon juice, and a pinch of salt.","Sear the chicken in a very hot skillet for 5 to 6 minutes, tossing once, until the strips are browned at the edges and cooked through.","Warm the pitas in the same pan for 30 seconds per side so they turn soft and floppy.","Slice the tomato and remaining cucumber, shave the onion thin, and pile everything into the warm pitas with the sizzling chicken.","Spoon the garlicky yogurt sauce generously over the top and wrap tightly in foil or paper for structural integrity."],"tip":"Squeezing the grated cucumber dry is the difference between tzatziki and a sad yogurt puddle escaping down your wrist."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_stovetop_chicken_chili', '{"id":"smoky_stovetop_chicken_chili","name":"Smoky 30-Minute Chicken Chili","emoji":"🌶️","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":30,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"black_beans","q":400},{"f":"broth","q":750},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":15},{"f":"sour_cream","q":80},{"f":"cheddar","q":60}],"steps":["Heat the oil in a Dutch oven over medium-high and sauté the diced onion and bell pepper for 4 minutes until softened and starting to color.","Add the garlic with a hefty spoonful each of chili powder, cumin, and paprika, stirring 30 seconds until the spices darken and bloom.","Stir in the diced chicken and cook 3 minutes until the outside turns opaque, then add the chopped tomatoes, beans, and broth.","Bring to a boil, then simmer briskly, uncovered, for 15 minutes until the chicken is tender and the chili has thickened enough to mound on a spoon.","Mash a ladleful of beans against the pot wall and stir it back in for body, then season with salt to taste.","Serve in deep bowls topped with grated cheddar and a cool spoonful of sour cream."],"tip":"Simmering uncovered is the whole trick — a lid traps steam and turns your chili into soup with commitment issues."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('better_than_takeout_chicken_fried_rice', '{"id":"better_than_takeout_chicken_fried_rice","name":"Better-Than-Takeout Chicken Fried Rice","emoji":"🍳","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","eggs","sesame"],"time":20,"servings":2,"ing":[{"f":"chicken_breast","q":250},{"f":"rice","q":150},{"f":"eggs","q":2},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15},{"f":"carrots","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Cook the rice first and spread it on a plate for 10 minutes to steam off surface moisture — slightly dried rice is what fries instead of steams.","Dice the chicken small, then stir-fry it in half the sesame oil over high heat for 3 to 4 minutes until golden and cooked through; push it to one side.","Add the diced carrot and onion and stir-fry 2 minutes until the onion turns translucent and the carrot loses its rawness.","Pour the beaten eggs into the empty side of the pan, scramble them into soft curds, then break up everything together.","Add the remaining oil and the rice, pressing it flat against the hot pan for 30-second stretches so it crackles and picks up toasty spots.","Drizzle the soy sauce down the hot pan wall so it sizzles and caramelizes, toss with the garlic for a final minute, and serve steaming."],"tip":"Pouring soy sauce onto the hot pan instead of the rice caramelizes it on contact — that whiff of wok smoke is the takeout flavor you thought required a restaurant."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('broiled_chicken_souvlaki_skewers', '{"id":"broiled_chicken_souvlaki_skewers","name":"Broiled Chicken Souvlaki Skewers with Yogurt Dip","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free"],"allergens":["dairy"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"zucchini","q":1.5},{"f":"bell_pepper","q":1},{"f":"olive_oil","q":20},{"f":"lemon","q":1},{"f":"garlic","q":0.3},{"f":"greek_yogurt","q":100}],"steps":["Set the broiler to high with a rack about 6 inches from the element, and line a sheet pan with foil.","Cut the chicken, zucchini, and bell pepper into even 3-centimeter chunks and toss with the olive oil, half the lemon''s juice, two minced garlic cloves, oregano, salt, and pepper.","Thread the pieces onto skewers, alternating chicken and vegetables snugly but not crushed together, and arrange them on the pan.","Broil 6 to 7 minutes, flip, and broil 6 minutes more, until the edges char and the chicken registers 165°F at its thickest chunk.","While they cook, stir the yogurt with the last garlic clove, the remaining lemon juice, and a pinch of salt for the dip.","Rest the skewers 2 minutes, then serve hot with the cool garlicky yogurt alongside."],"tip":"Cut everything the same size or accept that your zucchini will be jam by the time the chicken is safe — the broiler shows no mercy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheeseburger_penne_skillet', '{"id":"cheeseburger_penne_skillet","name":"Cheeseburger Penne Skillet","emoji":"🧀","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"penne","q":140},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":200},{"f":"broth","q":250},{"f":"cheddar","q":60},{"f":"olive_oil","q":10},{"f":"paprika","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in a deep 12-inch skillet over medium-high and brown the beef with the diced onion for 6 to 7 minutes, breaking it into rubble until deeply crusted at the edges.","Stir in the minced garlic, paprika, salt, and pepper and cook 30 seconds, just until the pan smells like a burger joint.","Pour in the crushed tomatoes and broth, scrape up the browned bits, and stir in the dry penne so every piece is submerged.","Cover and simmer over medium-low for 12 to 14 minutes, stirring twice, until the pasta is al dente and the sauce clings like a good chili.","Kill the heat, scatter the cheddar over the top, and lid it for 2 minutes until glossy and molten before serving straight from the pan."],"tip":"The pasta drinks the sauce as it sits, so if you dawdle, loosen it with a splash of broth rather than an apology."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_potato_cottage_pie', '{"id":"beef_potato_cottage_pie","name":"Weeknight Beef Cottage Pie","emoji":"🥧","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":55,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"potatoes","q":500},{"f":"milk","q":60},{"f":"butter","q":25},{"f":"onion","q":1},{"f":"carrots","q":100},{"f":"peas_frozen","q":80},{"f":"broth","q":150},{"f":"flour","q":10},{"f":"salt","q":5},{"f":"black_pepper","q":2},{"f":"oregano","q":1}],"steps":["Boil the peeled, chunked potatoes in well-salted water for 15 minutes until a knife slides in without resistance, then mash with the butter and warm milk until fluffy.","Meanwhile, brown the beef in a skillet over medium-high for 6 minutes, then add the diced onion and carrots and cook 5 more until the onion turns translucent and sweet.","Sprinkle the flour over the meat, stir for 1 minute to cook off the raw taste, then add the broth, oregano, salt, and pepper and simmer until it thickens to a gravy that coats a spoon.","Fold in the frozen peas, transfer the filling to a small baking dish, and rake the mash over the top with a fork so it ridges like a plowed field.","Bake at 400 F for 20 minutes until the peaks are bronzed and the gravy bubbles up the sides like lava at the edges."],"tip":"Those fork ridges on the mash are not decoration — more edges means more crispy brown bits, which is the whole point."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tex_mex_bean_stuffed_peppers', '{"id":"tex_mex_bean_stuffed_peppers","name":"Tex-Mex Black Bean Stuffed Peppers","emoji":"🫑","cuisine":"Mexican","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":2},{"f":"black_beans","q":250},{"f":"rice","q":70},{"f":"corn_frozen","q":80},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"salsa","q":120},{"f":"cheddar","q":60},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":4}],"steps":["Simmer the rice in salted water for 15 minutes until just tender, and halve the peppers through the stem, pulling out the seeds and ribs to make four boats.","Soften the diced onion in the olive oil over medium heat for 4 minutes, then stir in the garlic, cumin, chili powder, and salt for 30 seconds until the pan smells toasty.","Add the black beans and corn, mashing a few beans against the pan so the filling binds, then fold in the cooked rice and salsa so everything turns brick-red and juicy.","Pack the filling into the pepper halves, nestle them in a baking dish with a splash of water on the bottom, and cover with foil.","Bake at 400 F for 25 minutes, then uncover, cap each with cheddar, and bake 5 more until the cheese blisters; shower with cilantro before serving."],"tip":"The splash of water in the dish steams the peppers tender — skip it and you will be sawing through raw pepper with a butter knife."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_rice_cabbage_rolls', '{"id":"beef_rice_cabbage_rolls","name":"Lemony Beef and Rice Cabbage Rolls","emoji":"🥬","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"cabbage","q":0.5},{"f":"ground_beef","q":250},{"f":"rice","q":60},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2},{"f":"sugar","q":5}],"steps":["Blanch 8 large cabbage leaves in boiling salted water for 3 minutes until they drape like wet silk, then drain and shave down the thick center rib of each so it rolls without cracking.","Mix the raw beef with the uncooked rice, grated onion, minced garlic, half the parsley, oregano, salt, and pepper until just combined — overworking makes them tough.","Roll a few spoonfuls of filling snugly in each leaf, tucking the sides in like a burrito, and shingle the rolls seam-side down in a wide pot.","Whisk the crushed tomatoes with the olive oil, sugar, lemon juice, and a cup of water, pour it over, and weigh the rolls down with a small plate so they stay submerged.","Cover and simmer gently for 45 minutes until the rice is swollen and tender and the sauce has thickened; finish with the remaining parsley and a fresh squeeze of lemon."],"tip":"The plate on top is non-negotiable — unweighted rolls float, unravel, and become very expensive cabbage soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_beef_bean_chili_2', '{"id":"smoky_beef_bean_chili_2","name":"Smoky Beef and Black Bean Chili","emoji":"🌶️","cuisine":"American","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":450},{"f":"black_beans","q":250},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"broth","q":250},{"f":"corn_frozen","q":100},{"f":"chili_powder","q":8},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"oregano","q":2},{"f":"olive_oil","q":15},{"f":"salt","q":6}],"steps":["Heat the oil in a Dutch oven over medium-high and brown the beef hard for 8 minutes, leaving it alone in patches so it sears instead of steams.","Add the diced onion and bell pepper and cook 5 minutes until softened, then stir in the garlic, chili powder, cumin, paprika, and oregano and toast for 1 minute until the spices smell dusky and rich.","Pour in the crushed tomatoes and broth, scraping the fond off the bottom, and bring to a lazy bubble.","Simmer uncovered for 25 minutes, stirring occasionally, until the chili darkens a shade and thickens enough to mound on a spoon.","Stir in the beans and corn, simmer 5 more minutes to heat through, and season with salt until the flavors snap into focus."],"tip":"Chili judges its cook by patience — it tastes noticeably better tomorrow, so make it tonight and take credit twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_meatball_spaghetti', '{"id":"beef_meatball_spaghetti","name":"Sunday Beef Meatballs and Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":225},{"f":"eggs","q":1},{"f":"parmesan","q":25},{"f":"flour","q":20},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"crushed_tomatoes","q":400},{"f":"spaghetti","q":130},{"f":"olive_oil","q":15},{"f":"basil","q":0.3},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Mix the beef gently with the egg, grated parmesan, flour, one minced garlic clove, oregano, salt, and pepper, then roll into 8 golf-ball meatballs with damp hands so nothing sticks.","Brown the meatballs in olive oil over medium heat for 6 minutes, turning until crusted on all sides but still pink inside — they finish in the sauce.","In the same pan, soften the diced onion and remaining garlic in the drippings for 3 minutes, then add the crushed tomatoes and a splash of water.","Slide the meatballs back in, cover, and simmer gently for 15 minutes until they are tender all the way through and the sauce has gone glossy and brick-red.","Boil the spaghetti in aggressively salted water until al dente, toss it through the sauce with torn basil, and serve with the meatballs perched on top."],"tip":"Roll the meatballs like you are handling a soap bubble — a tight squeeze today is a bouncy meatball tonight."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_style_beef_rice_bowls', '{"id":"korean_style_beef_rice_bowls","name":"Korean-Style Ground Beef Rice Bowls","emoji":"🍚","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["soy","gluten","sesame","eggs"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"rice","q":150},{"f":"soy_sauce","q":45},{"f":"sugar","q":15},{"f":"sesame_oil","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":0.5},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"eggs","q":2}],"steps":["Rinse the rice until the water runs nearly clear, then simmer it covered with a scant double volume of water for 15 minutes and let it rest off the heat.","Sear the beef in a hot skillet for 5 to 6 minutes, breaking it up, until the edges frizzle and brown; pour off all but a slick of fat.","Stir in the garlic, grated ginger, soy sauce, and sugar and let it bubble for 2 minutes until the meat glazes and turns lacquered and sticky.","Fry the eggs in the sesame oil until the whites are crisp-edged and the yolks still tremble.","Pile the beef over the rice, add shredded carrot and thin cucumber half-moons alongside, crown each bowl with an egg, and shower with sliced scallions."],"tip":"Break the yolk and stir it through everything immediately — it is the sauce you did not have to make."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_keema_matar', '{"id":"beef_keema_matar","name":"Beef Keema with Peas","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"cumin","q":3},{"f":"crushed_tomatoes","q":200},{"f":"peas_frozen","q":120},{"f":"coconut_milk","q":100},{"f":"olive_oil","q":15},{"f":"cilantro","q":0.3},{"f":"salt","q":5}],"steps":["Cook the finely diced onion in the oil over medium heat for 8 to 10 minutes, stirring often, until it turns deep golden — this slow start is where keema gets its backbone.","Add the minced garlic and grated ginger and fry 1 minute, then stir in the cumin, turmeric, and half the garam masala until the kitchen smells like a spice shop.","Crumble in the beef and cook over medium-high for 6 minutes, breaking it fine, until no pink remains and the fat runs golden and fragrant.","Add the crushed tomatoes and salt and simmer 10 minutes until the sauce thickens and the oil beads at the edges of the pan.","Stir in the peas and coconut milk, simmer 3 minutes more, then finish with the remaining garam masala and a fistful of chopped cilantro."],"tip":"When the oil separates and pools at the edges, that is not greasy — that is the curry telling you it is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_beef_zucchini_boats_2', '{"id":"italian_beef_zucchini_boats_2","name":"Italian Beef Zucchini Boats","emoji":"🥒","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"zucchini","q":2},{"f":"ground_beef","q":250},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":200},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"olive_oil","q":15},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Halve the zucchini lengthwise and scoop out the seedy cores with a spoon, leaving quarter-inch walls; chop the scooped flesh and save it.","Brown the beef with the onion in olive oil over medium-high for 6 minutes until crusty, then add the garlic, chopped zucchini flesh, oregano, salt, and pepper and cook 3 more minutes.","Stir in the crushed tomatoes and simmer 5 minutes until the filling is thick enough to hold its shape on a spoon.","Arrange the boats in a baking dish, salt their insides lightly, mound in the filling, and top with mozzarella and parmesan.","Bake at 400 F for 20 to 25 minutes until the zucchini yields to a fork and the cheese is bubbling with brown freckles; scatter torn basil over the top."],"tip":"Quarter-inch walls are the sweet spot — thinner collapses into a puddle, thicker eats like raw squash with a meat hat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cuban_style_beef_picadillo', '{"id":"cuban_style_beef_picadillo","name":"Cuban-Style Beef Picadillo","emoji":"🥘","cuisine":"Mexican","meal":["dinner"],"diets":["gluten-free","dairy-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"ground_beef","q":450},{"f":"potatoes","q":300},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":400},{"f":"olives","q":60},{"f":"broth","q":200},{"f":"cumin","q":5},{"f":"oregano","q":2},{"f":"cinnamon","q":1},{"f":"olive_oil","q":15},{"f":"salt","q":6}],"steps":["Dice the potatoes into half-inch cubes and brown them in the olive oil over medium-high heat for 5 minutes until their edges turn golden; scoop them out and set aside.","In the same pot, brown the beef for 6 to 7 minutes, then add the diced onion and bell pepper and cook until soft and sweet, about 5 minutes more.","Stir in the garlic, cumin, oregano, and cinnamon and toast 30 seconds — the cinnamon should whisper, not shout.","Return the potatoes with the crushed tomatoes, broth, and salt, and simmer partially covered for 15 minutes until the potatoes are tender and the stew is thick and savory.","Stir in the sliced olives, simmer 2 final minutes so their brine ripples through the sauce, and serve in shallow bowls."],"tip":"The olives go in last on purpose — simmered too long they surrender their salty punch, and the punch is why they were invited."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_eggplant_moussaka_bake', '{"id":"beef_eggplant_moussaka_bake","name":"Weeknight Beef and Eggplant Moussaka Bake","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy","eggs"],"time":70,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"ground_beef","q":250},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":250},{"f":"cinnamon","q":1},{"f":"oregano","q":2},{"f":"olive_oil","q":25},{"f":"greek_yogurt","q":150},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Slice the eggplant into half-inch rounds, brush both sides with most of the olive oil, and roast on a sheet pan at 425 F for 20 minutes until browned and collapsing.","Meanwhile, brown the beef with the onion in the remaining oil for 7 minutes, then add the garlic, cinnamon, oregano, salt, and pepper and cook until fragrant.","Pour in the crushed tomatoes and simmer 10 minutes until the sauce is thick, jammy, and barely wet.","Whisk the greek yogurt with the egg, half the parmesan, and a pinch of salt to make a quick tangy topping.","Layer half the eggplant in a small baking dish, spread on the meat sauce, shingle the rest of the eggplant over, spoon on the yogurt layer, and bake at 400 F for 20 minutes until puffed and gilded; rest 10 minutes before cutting."],"tip":"The 10-minute rest is the difference between clean, proud layers and an eggplant landslide on your plate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_beef_lettuce_wraps', '{"id":"ginger_beef_lettuce_wraps","name":"Ginger Beef Lettuce Wraps","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["soy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"romaine","q":1},{"f":"mushrooms","q":100},{"f":"carrots","q":80},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"scallions","q":0.5},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"sugar","q":10},{"f":"lime","q":0.5}],"steps":["Separate the romaine into whole leaves, rinse, and chill them so they stay snappy while you cook.","Sear the beef in a screaming-hot skillet for 5 minutes without crowding until it browns and crackles, then add the finely chopped mushrooms and cook 3 minutes until their moisture cooks off.","Add the garlic and grated ginger for 30 seconds, then splash in the soy sauce and sugar and toss until the meat glazes dark and glossy.","Off the heat, stir in the sesame oil, grated carrot, most of the scallions, and a hard squeeze of lime.","Spoon the hot filling into the cold leaves, top with the remaining scallions, and eat immediately with both hands and zero dignity."],"tip":"Cold crisp lettuce against hot glazed beef is the entire dish — lukewarm leaves turn it into a sad, floppy salad."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salisbury_beef_patties_mash', '{"id":"salisbury_beef_patties_mash","name":"Salisbury Beef Patties with Mushroom Gravy","emoji":"🍄","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"eggs","q":1},{"f":"flour","q":15},{"f":"onion","q":1},{"f":"mushrooms","q":200},{"f":"broth","q":300},{"f":"butter","q":30},{"f":"potatoes","q":400},{"f":"milk","q":50},{"f":"balsamic_vinegar","q":10},{"f":"salt","q":6},{"f":"black_pepper","q":3}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 minutes until tender, then mash with half the butter and the warm milk until smooth and cloud-soft.","Mix the beef with the egg, a third of the onion grated fine, salt, and pepper, shape into two thick oval patties, and dust them lightly with some of the flour.","Sear the patties in a hot skillet for 3 minutes per side until mahogany-crusted, then move them to a plate — they will finish in the gravy.","Melt the remaining butter in the drippings, cook the sliced mushrooms and remaining onion for 6 minutes until browned and squeaky-soft, then stir in the rest of the flour for 1 minute.","Whisk in the broth and balsamic and simmer until the gravy coats a spoon, then return the patties and simmer 8 minutes, spooning gravy over, until cooked through and glistening.","Serve the patties over the mash with every last drop of gravy from the pan."],"tip":"Do not scrub that skillet between patties and gravy — the brown crust on the bottom is flavor you already paid for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_parm_meatballs_spaghetti', '{"id":"turkey_parm_meatballs_spaghetti","name":"Turkey Parmesan Meatballs with Spaghetti","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"eggs","q":1},{"f":"parmesan","q":30},{"f":"flour","q":15},{"f":"garlic","q":0.3},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"crushed_tomatoes","q":400},{"f":"oregano","q":2},{"f":"sugar","q":3},{"f":"spaghetti","q":120},{"f":"basil","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Mix the turkey with the egg, grated parmesan, flour, one minced garlic clove, half the salt, and a good grind of pepper, then roll into 12 balls with damp hands so nothing sticks.","Sear the meatballs in olive oil over medium-high heat for 6 to 8 minutes, turning until deeply browned on at least two sides — that crust is where the flavor lives.","Push the meatballs aside, soften the diced onion and remaining garlic for 3 minutes, then pour in the crushed tomatoes with the oregano and sugar.","Simmer gently, partially covered, for 15 minutes until the sauce darkens to brick red and the meatballs register cooked through at 74C.","Meanwhile boil the spaghetti in well-salted water until just shy of tender, then finish it in the sauce for a minute with a splash of pasta water.","Shower with torn basil and serve while the sauce still clings glossily to every strand."],"tip":"Wet hands and a light touch make tender meatballs; squeeze them like stress balls and they will eat like them too."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_street_tacos', '{"id":"turkey_street_tacos","name":"Smoky Turkey Street Tacos","emoji":"🌮","cuisine":"Mexican","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"chili_powder","q":6},{"f":"cumin","q":4},{"f":"paprika","q":2},{"f":"salsa","q":120},{"f":"tortillas","q":4},{"f":"avocado","q":1},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"salt","q":3}],"steps":["Heat the oil in a wide skillet until shimmering, then press the turkey into an even layer and leave it alone for 3 full minutes so the underside browns and crisps at the edges.","Break the meat into rubble, stir in the diced onion and minced garlic, and cook 3 minutes more until the onion turns translucent.","Season with chili powder, cumin, paprika, and salt, toast the spices for 30 seconds until fragrant, then stir in the salsa and simmer 2 minutes so the filling turns saucy but not wet.","Char the tortillas directly over a burner flame or in a dry pan for 20 seconds a side until blistered and pliable.","Pile the filling into the tortillas and top with sliced avocado, a hard squeeze of lime, and a flurry of chopped cilantro."],"tip":"The three minutes of not touching the turkey is the whole recipe — stir early and you get gray steam-meat instead of crispy taco gold."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_larb_lettuce_cups', '{"id":"turkey_larb_lettuce_cups","name":"Thai-Style Turkey Larb Lettuce Cups","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy"],"time":30,"servings":2,"ing":[{"f":"rice","q":30},{"f":"ground_turkey","q":450},{"f":"olive_oil","q":10},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"soy_sauce","q":30},{"f":"lime","q":2},{"f":"honey","q":10},{"f":"chili_powder","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":1},{"f":"romaine","q":1},{"f":"cucumber","q":0.5}],"steps":["Toast the raw rice in a dry skillet over medium heat for 5 to 7 minutes, shaking often, until it turns deep golden and smells like popcorn, then grind it to a coarse powder.","Cook the turkey in the oil over high heat for 5 to 6 minutes, breaking it up finely and letting the pan juices evaporate until the meat sizzles rather than simmers.","Stir in the garlic and ginger for 30 seconds, then pull the pan off the heat and dress the warm meat with soy sauce, the juice of both limes, honey, and chili powder.","Fold in the sliced scallions, most of the cilantro, and the toasted rice powder, which gives the larb its signature nutty crunch.","Spoon into crisp romaine leaves, top with thin cucumber half-moons and the last of the cilantro, and eat immediately with extra lime on the side."],"tip":"Do not skip the toasted rice powder — it takes seven minutes and is the difference between larb and sad taco meat in a leaf."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_kofta_pita_plates', '{"id":"turkey_kofta_pita_plates","name":"Turkey Kofta Plates with Yogurt Sauce","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"parsley","q":0.8},{"f":"cumin","q":5},{"f":"paprika","q":4},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2},{"f":"olive_oil","q":15},{"f":"pita","q":2},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"tomato","q":1}],"steps":["Grate the onion on the coarse holes and squeeze out the excess juice, then knead it into the turkey with two minced garlic cloves, most of the parsley, cumin, paprika, cinnamon, salt, and pepper until tacky.","Shape the mixture into 8 torpedo-shaped kofta and chill them for 10 minutes so they hold their shape on the heat.","Sear the kofta in olive oil over medium-high heat for 8 to 10 minutes, rolling them every few minutes, until mahogany-crusted on all sides and firm to the touch.","While they cook, stir the grated cucumber, remaining garlic, half the lemon juice, and a pinch of salt into the yogurt to make a quick cooling sauce.","Warm the pitas in the empty corner of the pan until soft and lightly toasted, then plate the kofta over them with tomato wedges, the yogurt sauce, and the rest of the parsley and lemon."],"tip":"Grated onion vanishes into the meat and keeps it juicy; chopped onion just gives you kofta that crack open like fault lines."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_keema_matar', '{"id":"turkey_keema_matar","name":"Turkey Keema Matar with Basmati-Style Rice","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"rice","q":120},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"ground_turkey","q":400},{"f":"garam_masala","q":6},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"chili_powder","q":2},{"f":"crushed_tomatoes","q":200},{"f":"peas_frozen","q":150},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Start the rice in a small pot with double its volume of salted water, cover, and let it steam on low for 15 minutes while you build the keema.","Fry the finely diced onion in the oil over medium heat for 8 to 10 minutes until it turns deep golden at the edges — this slow browning is the backbone of the dish, so do not rush it.","Stir in the minced garlic and ginger for a minute, then add the turkey and cook 5 minutes, mashing it into fine crumbles.","Bloom the garam masala, turmeric, cumin, chili powder, and salt in the fat for 30 seconds until the kitchen smells unmistakably like dinner, then pour in the crushed tomatoes.","Simmer 10 minutes until the sauce thickens and pools of oil break at the surface, then fold in the peas for the final 3 minutes so they stay sweet and bright green.","Serve the keema over the fluffed rice with a generous handful of chopped cilantro."],"tip":"When the oil separates and beads on top of the sauce, the keema is done — that shimmer is Indian home cooking''s built-in doneness thermometer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_white_bean_chili', '{"id":"turkey_white_bean_chili","name":"White Bean Turkey Chili","emoji":"🍲","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":600},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"cumin","q":8},{"f":"oregano","q":4},{"f":"chili_powder","q":4},{"f":"broth","q":750},{"f":"white_beans","q":400},{"f":"corn_frozen","q":150},{"f":"lime","q":1},{"f":"cilantro","q":1},{"f":"sour_cream","q":100},{"f":"salt","q":5}],"steps":["Brown the turkey in the oil in a Dutch oven over medium-high heat for 5 to 6 minutes, breaking it into bite-size crumbles and letting it pick up golden spots.","Add the diced onion, bell pepper, and garlic and cook 5 minutes until softened, then toast the cumin, oregano, chili powder, and salt in the mixture for 30 seconds.","Pour in the broth, scrape up every browned bit from the bottom, and add the white beans; mash about a third of them against the pot wall to give the chili body.","Simmer uncovered for 20 minutes, stirring occasionally, until the liquid reduces to a loose, spoon-coating stew and the flavors taste rounded rather than sharp.","Stir in the corn and lime juice for the last 3 minutes, then ladle into bowls topped with a swirl of sour cream and plenty of cilantro."],"tip":"Mashing a few beans thickens the chili better than any starch, and nobody at the table will ever know your secret was violence."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_smash_burgers', '{"id":"turkey_smash_burgers","name":"Crispy-Edge Turkey Smash Burgers","emoji":"🍔","cuisine":"American","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":450},{"f":"salt","q":4},{"f":"black_pepper","q":2},{"f":"paprika","q":2},{"f":"olive_oil","q":10},{"f":"cheddar","q":60},{"f":"bread","q":4},{"f":"butter","q":15},{"f":"greek_yogurt","q":60},{"f":"onion","q":0.5},{"f":"romaine","q":0.2},{"f":"tomato","q":1}],"steps":["Divide the turkey into 4 loose balls, season the outsides with salt, pepper, and paprika, and get a cast-iron skillet screaming hot with a slick of oil.","Drop in two balls at a time and smash them flat with a sturdy spatula, pressing hard for 10 seconds so maximum meat kisses the metal.","Cook undisturbed for 2 to 3 minutes until the edges turn lacy and deep brown, then flip, lay cheddar on each patty, and give them 2 minutes more to melt and finish cooking through.","Butter the bread slices and toast them in the same skillet until golden, soaking up all the savory drippings.","Stir the paprika into the yogurt for a two-second sauce, then stack each burger with shaved onion, romaine, and thick tomato slices between the toasted bread."],"tip":"Turkey has no fat to spare, so the ripping-hot pan is non-negotiable — a timid skillet gives you a beige frisbee, not a burger."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('italian_turkey_stuffed_peppers_2', '{"id":"italian_turkey_stuffed_peppers_2","name":"Italian Turkey and Rice Stuffed Peppers","emoji":"🫑","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":55,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"rice","q":80},{"f":"ground_turkey","q":350},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":300},{"f":"oregano","q":3},{"f":"basil","q":0.5},{"f":"mozzarella","q":60},{"f":"parmesan","q":20},{"f":"salt","q":4}],"steps":["Heat the oven to 200C, halve the peppers through the stem, scoop out the seeds, and roast the empty shells cut-side up for 10 minutes so they get a head start on softening.","Meanwhile simmer the rice in salted water until just tender, and brown the turkey in olive oil with the onion and garlic for 6 minutes, seasoning with oregano and salt.","Stir two-thirds of the crushed tomatoes and the cooked rice into the meat and let it bubble 3 minutes until the filling is juicy but holds together on a spoon.","Mound the filling into the pepper halves, spoon the remaining tomatoes over the top, and cap each with torn mozzarella and a snowfall of parmesan.","Bake 20 to 25 minutes until the cheese is bronzed and bubbling and a knife slides through the pepper walls with no resistance, then rest 5 minutes and finish with basil."],"tip":"Pre-roasting the empty peppers is the cure for that classic stuffed-pepper tragedy: molten filling trapped inside a raw, crunchy shell."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_turkey_rice_soup', '{"id":"ginger_turkey_rice_soup","name":"Ginger Turkey and Rice Soup","emoji":"🥣","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"sesame_oil","q":10},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"mushrooms","q":150},{"f":"broth","q":1500},{"f":"rice","q":120},{"f":"soy_sauce","q":20},{"f":"spinach","q":100},{"f":"scallions","q":1},{"f":"black_pepper","q":2}],"steps":["Sizzle the julienned ginger and sliced garlic in the sesame oil over medium heat for a minute until fragrant, then add the turkey and cook 5 minutes, breaking it into small nubs.","Add the sliced carrots and mushrooms and stir for 2 minutes until the mushrooms start to release their juices and slump.","Pour in the broth and rice, bring to a boil, then lower to a gentle simmer for 20 minutes until the rice grains swell and start to fray at the edges, thickening the soup slightly.","Season with soy sauce and black pepper, tasting as you go — the broth should be savory enough to make you take a second sip immediately.","Wilt in the spinach off the heat and serve steaming, showered with sliced scallions."],"tip":"Let the rice overcook a little on purpose; those blown-out grains turn the broth silky, like a congee that still respects your schedule."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_picadillo_rice', '{"id":"turkey_picadillo_rice","name":"Turkey Picadillo over Rice","emoji":"🫒","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"rice","q":120},{"f":"ground_turkey","q":400},{"f":"olive_oil","q":15},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"cumin","q":5},{"f":"oregano","q":3},{"f":"cinnamon","q":1},{"f":"chili_powder","q":3},{"f":"crushed_tomatoes","q":250},{"f":"olives","q":50},{"f":"honey","q":5},{"f":"salt","q":4}],"steps":["Get the rice simmering in salted water, covered, on your back burner — it will land at the same time as the picadillo if you start it first.","Soften the diced onion and bell pepper in olive oil over medium heat for 5 minutes until sweet and slack, then stir in the garlic for 30 seconds.","Add the turkey and cook 5 to 6 minutes, crumbling it fine, until no pink remains and the pan bottom is glazed brown.","Season with cumin, oregano, cinnamon, chili powder, and salt, then stir in the crushed tomatoes, sliced olives, and honey.","Simmer uncovered for 10 minutes until the mixture is thick enough to mound on a spoon, tasting for the salty-sweet-briny balance that makes picadillo addictive, then serve over the fluffy rice."],"tip":"The pinch of cinnamon and drizzle of honey are doing the job raisins usually do — sweet whispers, not a dessert takeover."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_broccoli_stirfry', '{"id":"turkey_broccoli_stirfry","name":"Honey-Garlic Turkey and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"rice","q":120},{"f":"ground_turkey","q":400},{"f":"olive_oil","q":10},{"f":"broccoli","q":400},{"f":"garlic","q":0.3},{"f":"ginger","q":15},{"f":"soy_sauce","q":40},{"f":"honey","q":15},{"f":"sesame_oil","q":10},{"f":"scallions","q":1}],"steps":["Set the rice to steam, then stir the soy sauce, honey, and sesame oil together in a cup so the sauce is ready before anything hits the pan.","Heat a wok or your widest skillet over high heat with the olive oil until it just smokes, then add the broccoli florets with a splash of water and stir-fry 3 to 4 minutes until they turn vivid green with charred tips; scoop them out.","Add the turkey to the empty pan and press it flat, letting it sear untouched for 2 minutes before breaking it up and cooking 3 minutes more.","Stir in the minced garlic and ginger for 30 seconds, return the broccoli, and pour the sauce over everything, tossing for a minute until it bubbles and glazes each crumble and floret.","Serve over the rice, topped with sliced scallions while the glaze is still glossy."],"tip":"Cook the broccoli and the meat separately — a crowded pan steams instead of sears, and stir-fry is a game of elbow room."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
